		fmt = '7.会长连续5天不上线，将会按照副会长>会员的优先级，传位给期间满足上线条件、贡献度最高的玩家，与其职位互换'
	},
	[11007] = {
		id = 11007,
		fmt = '8.会长需将会长职位传给其他玩家才能离开公会'
	},
	[12001] = {
		id = 12001,
		fmt = '1.挑战每层的不同玩家，追求更高层数，争取更多奖励。'
	},
	[12002] = {
		id = 12002,
		fmt = '2.试炼的部分楼层中包含宝箱，除了获得固定奖励外，更能通过消费钻石开启更加丰厚的奖励。'
	},
	[12003] = {
		id = 12003,
		fmt = '3.宝箱中有概率获得宠物'
	},
	[12004] = {
		id = 12004,
		fmt = '4.部分楼层可消耗试炼得星购买增益buff，对后续的挑战有巨大帮助哦。'
	},
	[12005] = {
		id = 12005,
		fmt = '5.宠物试炼玩法每日凌晨5点重置。'
	},
	[12006] = {
		id = 12006,
		fmt = '6.重置时，为上榜玩家发送邮件奖励。'
	},
	[12007] = {
		id = 12007,
		fmt = '7.当历史积分达到某一值时，还能够获得额外的积分奖励。'
	},
	[13001] = {
		id = 13001,
		fmt = '1.玩家可在活动开启8天内完成前5天开启的活动列表，超过8天后，活动将自动关闭；'
	},
	[13002] = {
		id = 13002,
		fmt = '2.完成全部目标即可领取全部的全目标奖励，或者在第8天时也可以根据当前进度所在的档位领取最终奖励；'
	},
	[13003] = {
		id = 13003,
		fmt = '3.全目标奖励只可领取一次，领取后不可再领，请谨慎领取。'
	},
	[14001] = {
		id = 14001,
		fmt = '长有闪耀光芒的六张翼，神圣到以纯白之衣覆盖身体的天使宠物。是完全的善之存在，被称作带来幸福的宠物，对邪恶非常冷酷，不完全消灭对方，是不会停止攻击的。'
	},
	[14002] = {
		id = 14002,
		fmt = '天堂之拳：用金黄光芒的巨型拳头对敌方全体造成海量伤害，对每个目标有30%概率降低其300怒气，15%的概率控制目标'
	},
	[14003] = {
		id = 14003,
		fmt = '神圣之杖：利用天使兽手中的神圣之杖，对单体目标造成巨额伤害，有20%几率的封印敌人，对防属性的敌人造成60%的额外伤害'
	},
	[14004] = {
		id = 14004,
		fmt = '神级攻击强化：提升自身攻击力'
	},
	[14005] = {
		id = 14005,
		fmt = '天使兽守护：战斗中，增加己方技类型宠物的控制率'
	},
	[14006] = {
		id = 14006,
		fmt = '伤害加深：宠物通用被动技能，对目标造成更高的伤害，伤害率增加'
	},
	[14007] = {
		id = 14007,
		fmt = '伤害减免：宠物通用被动技能，敌人对自身造成的伤害减少，免伤率增加'
	},
	[15001] = {
		id = 15001,
		fmt = '活动开启时间为服务器开启第3日5：00-第8日5：00，奖励发放依据为第7日21：30战力排行榜排名（通过邮件发放）！'
	},
	[15002] = {
		id = 15002,
		fmt = '第7日21：30根据战力，可以获得战力达标奖励（达标奖励按照最高战力发放，不累计）'
	},
	[15003] = {
		id = 15003,
		fmt = '战力相同，按照排名时间先后排序'
	},
	[15004] = {
		id = 15004,
		fmt = '1-10名排名奖励需要达到45000战力值'
	},
	[16001] = {
		id = 16001,
		fmt = '1.玩法次数在每天凌晨5点重置'
	},
	[16002] = {
		id = 16002,
		fmt = '2.长按箭头上下移动或拉伸，可调整炮管的力度与角度'
	},
	[16003] = {
		id = 16003,
		fmt = '3.本玩法可获得金币、钻石、冰熊兽碎片'
	},
	[16004] = {
		id = 16004,
		fmt = '4.射中一个靶子积分数+1，每达到一定积分数可获得相应奖励'
	},
	[16005] = {
		id = 16005,
		fmt = '5.奖励设置每日上限'
	},
	[17001] = {
		id = 17001,
		fmt = '嘿！驯兽师，看这里，点击我查看buff相关规则'
