	[18001] = {
		id = 18001,
		fmt = '#C0xFFFFF5D6#1.报名时间：#C0xFF4FF701#10:00-19:50'
	},
	[18002] = {
		id = 18002,
		fmt = '#C0xFFFFF5D6#2.比赛时间：#C0xFF4FF701#20:00-20:55'
	},
	[19001] = {
		id = 19001,
		fmt = '#C0xFFF5D6#1.玩家可在公会红包里进行发红包和抢红包，红包有个数限定，可要抓紧咯'
	},
	[19002] = {
		id = 19002,
		fmt = '#C0xFFF5D6#2.公会红包每天19点自动刷新'
	},
	[19003] = {
		id = 19003,
		fmt = '#C0xFFF5D6#3.提升研究院红包科技的等级可提升公会红包的额度和个数'
	},
	[19004] = {
		id = 19004,
		fmt = '#C0xFFF5D6#4.发红包和抢红包由玩家自己手动选择'
	},
	[19005] = {
		id = 19005,
		fmt = '#C0xFFF5D6#5.发红包玩家可抢自己所发的红包哟'
	},
	[19006] = {
		id = 19006,
		fmt = '#C0xFFF5D6#6.红包内的额度为随机获得，多扶老奶奶过马路吧'
	},
	[19007] = {
		id = 19007,
		fmt = '#C0xFFF5D6#7.提高贵族等级可增加发红包和抢红包的次数'
	},
	[19008] = {
		id = 19008,
		fmt = '#C0xFFF5D6#8.玩家发出的红包保留24小时，到期自动消失，剩余额度不会退回'
	},
	[20001] = {
		id = 20001,
		fmt = '欢迎来到公会战，公会战一周为一个赛季，每个赛季都有丰厚奖励哟。快叫上你的战友，一起战斗吧！'
	},
	[20002] = {
		id = 20002,
		fmt = '1.公会战分为预选赛、决赛两个阶段：预选赛4天（周二至周五），决赛1天（周六）；'
	},
	[20003] = {
		id = 20003,
		fmt = '2.每天比赛的报名时间：#C0xF76B45#9：30-20：50'
	},
	[20004] = {
		id = 20004,
		fmt = '3.每天比赛正式开始时间：   #C0xF76B45#21:00'
	},
	[20005] = {
		id = 20005,
		fmt = '4.报名条件：训练家等级到达40级以上、且所在公会等级到达4级及以上的玩家方可报名，只有报名了才能参加当日比赛；'
	},
	[20006] = {
		id = 20006,
		fmt = '5.贵族等级到达3及以上的玩家每天战斗开始前半小时，系统会自动报名。'
	},
	[21001] = {
		id = 21001,
		fmt = '1.预选赛期间，周二到周四会限定出战精灵属性类型，具体限制可查看当天报名界面或布阵界面，周五对于精灵属性类型无限制；'
	},
	[21002] = {
		id = 21002,
		fmt = '2.对于有限制属性的轮次，只要精灵有一种属性符合，即可参与当天的战斗，同进化系列精灵一天只允许使用一次；'
	},
	[21003] = {
		id = 21003,
		fmt = '3.预选赛可以派出2队精灵出战，每队可使用3只；'
	},
	[21004] = {
		id = 21004,
		fmt = '4.第一队被击败后，第二队可在下一轮中继续战斗；'
	},
	[21005] = {
		id = 21005,
		fmt = '5.比赛形式为混战模式，您将会遇到其他各个公会的玩家（当剩余人数过少时，您可能会与自己公会的成员进行交战决出个人排名）；'
	},
	[21006] = {
		id = 21006,
		fmt = '6.胜利的玩家，可继续进行下一轮战斗，与保留下来的对手继续鏖战；'
	},
	[21007] = {
		id = 21007,
		fmt = '7.每次战斗完保留生命值和怒气值；'
	},
	[21008] = {
		id = 21008,
		fmt = '8.公会战存在积分机制，个人积分规则为：每打败1名对手获得2积分，失败获得1积分；'
	},
	[21009] = {
		id = 21009,
		fmt = '9.最终胜利玩家可以为公会增加公会积分和战斗之星，战斗之星可用于决战时控制决战属性加成；'
	},
	[21010] = {
		id = 21010,
		fmt = '10.公会当日排行由当日公会总积分决定；'
	},
	[21011] = {
		id = 21011,
		fmt = '11.双方最多战斗10回合，到时间若未分出胜负，剩余血量百分比多的一方获胜。'
	},
	[22001] = {
		id = 22001,
		fmt = '1.前4天战斗中，公会积分前8强的公会可进入决赛，符合参赛条件的所有玩家在决赛预备期间自动报名；'
	},
	[22002] = {
		id = 22002,
		fmt = '2.决赛中，所有属性均可出场；'
	},
	[22003] = {
		id = 22003,
		fmt = '3.决赛为公会对战公会，淘汰晋级模式，直至决出冠军；'
	},
	[22004] = {
		id = 22004,
		fmt = '4.决赛战斗模式为公会间的车轮战，玩家可使用3队精灵进行比赛，每个队伍最多上阵4只精灵；'
	},
	[22005] = {
		id = 22005,
		fmt = '5.两公会对战中，根据对战序列进行比赛，胜利的队伍会继续参与下一场比赛，失败一方队伍从对战序列中去除，直到一方公会的所有队伍全灭，另一方胜出；'
	},
	[22006] = {
		id = 22006,
		fmt = '6.胜出的公会可以继续参与之后与其他胜出公会的对战，直到决出冠军；'
	},
	[22007] = {
		id = 22007,
		fmt = '7.整个决赛系列赛宠物状态均会保留，即便胜利，与下一个胜利公会的对战，精灵的生命值也不会回复，且阵亡精灵也不会复活。'
	},
	[22008] = {
		id = 22008,
		fmt = '8.公会战最终战斗结束后，会根据排名，给公会增加大量额外的积分。'
	},
	[22101] = {
		id = 22101,
		fmt = '1.预选赛期间，每天获得最终胜利的公会可以拿到一颗战斗之星；'
	},
	[22102] = {
		id = 22102,
		fmt = '2.决战开始前，拥有战斗之星公会的管理（会长/副会长）可以使用战斗之星对决赛进行属性和能力值的加成设置；'
	},
	[22103] = {
		id = 22103,
		fmt = '3.设置成功时会消耗一颗战斗之星，且设置后无法更改；'
	},
	[22104] = {
		id = 22104,
		fmt = '4.设置完成后，该能力变更对所有参与决赛的精灵都会产生效果。'
	},
	[22201] = {
		id = 22201,
		fmt = '1.整个公会战对战期间，每轮的对战中，首次进入战斗队伍中的所有精灵可以获得一定的攻击、防御、速度等属性加成；'
	},
	[22202] = {
		id = 22202,
		fmt = '2.随着对战持续，该属性加成会得到衰减，且精灵会变得疲惫，战斗能力会越来越弱；'
	},
	[22203] = {
		id = 22203,
		fmt = '3.之后每次参与对战，队伍中的精灵攻击、防御、速度、受治疗量等属性会持续降低。'
	},
	[22301] = {
		id = 22301,
		fmt = '1.在决赛报名阶段（周六9:30-20:50）可以对决赛结果进行押注竞猜；'
	},
	[22302] = {
		id = 22302,
		fmt = '2.冠军下注，赔率越高，回报越大，最高不超过1000000金币；'
	},
	[22303] = {
		id = 22303,
		fmt = '3.比赛结束后，奖励统一以邮件形式发放，竞猜对冠军可获得押注倍率的金额，竞猜目标为第二名时返还一半押注金额。'
	},
	[23001] = {
		id = 23001,
		fmt = '1.比赛结束后，所有奖励均通过邮件发送；'
	},
	[23002] = {
		id = 23002,
		fmt = '2.每天的比赛包括报名奖励、个人胜场奖励、公会排行奖励，其中公会排行奖励为该公会参赛人员可获得；'
	},
	[23003] = {
		id = 23003,
		fmt = '3.预选赛和决赛报名均可获得一份参与奖励；'
	},
	[23004] = {
		id = 23004,
		fmt = '4.个人胜利奖励为公会战胜利宝箱，每胜利一次，获得一个，该项奖励每天最多可获得6个，只有预选赛战胜对手可以获得，决战期间没有个人胜利奖励；'
	},
	[23005] = {
		id = 23005,
		fmt = '5.公会排名奖励详见以下奖励展示'
	},
	[24001] = {
		id = 24001,
		fmt = '#C0xFFF5D6#1、每周进行2期比赛，每期比赛持续2天，开始时间为每周1、5'
	},
	[24002] = {
		id = 24002,
		fmt = '#C0xFFF5D6#2、每期比赛会根据每个服实力和玩家数，匹配相近的若干服'
	},
	[24003] = {
		id = 24003,
		fmt = '#C0xFFF5D6#3、报名时间：每期比赛第1天05:00-18:50'
	},
	[24004] = {
		id = 24004,
		fmt = '#C0xFFF5D6#4、开始时间：19:00'
	},
	[24005] = {
		id = 24005,
		fmt = '#C0xFFF5D6#5、报名时需选定12个宠物，每天比赛正式开始前均可自由更替'
	},
	[24006] = {
		id = 24006,
		fmt = '#C0xFFF5D6#6、每期比赛共包括预选赛，八强赛，冠军赛3个阶段。'
	},
	[24007] = {
		id = 24007,
		fmt = '#C0xFFF5D6#7、预选赛每场比赛持续4分钟，八强赛和冠军赛每场比赛持续5分钟，比赛开始前1分钟内不能进行布阵。'
	},
	[24008] = {
		id = 24008,
		fmt = '#C0xFFF5D6#8、贵族3及以上可自动报名。'
	},
	[25001] = {
		id = 25001,
		fmt = '#C0xFFF5D6#1、每胜利一场获得1个金宝箱，失败一场获得1个银宝箱。'
	},
	[25002] = {
		id = 25002,
		fmt = '#C0xFFF5D6#2、每期比赛结束后，会根据您的排名发放排名奖励。'
	},
	[25003] = {
		id = 25003,
		fmt = '#C0xFFF5D6#3、宝箱可以开出各种稀有奖励'
	},
	[25004] = {
		id = 25004,
		fmt = '#C0xFFF5D6#4、排名奖励将在每期比赛结束后通过邮件发放'
	},
	[26001] = {
		id = 26001,
		fmt = '#C0xFFF5D6#1、预选赛为积分淘汰制'
	},
	[26002] = {
		id = 26002,
		fmt = '#C0xFFF5D6#2、预选赛分为3轮，第1天进行2轮，第二天进行1轮。每轮进行4场比赛，共12场比赛，每场比赛4分钟'
	},
	[26003] = {
		id = 26003,
		fmt = '#C0xFFF5D6#3、每进行一场比赛，玩家可获得相应积分。'
	},
	[26004] = {
		id = 26004,
		fmt = '#C0xFFF5D6#4、每轮预选赛继承积分和胜负场次，累计5败即淘汰出局。'
	},
	[26005] = {
		id = 26005,
		fmt = '#C0xFFF5D6#5、单轮比赛宠物不能重复使用，不同轮次间宠物可重复使用。'
	},
	[27001] = {
		id = 27001,
		fmt = '#C0xFFF5D6#1、预选赛结束后根据排名选出前64强进行8强赛，8强赛将分8个赛场进行选拨'
	},
	[27002] = {
		id = 27002,
		fmt = '#C0xFFF5D6#2、8强选拔赛为淘汰制，包括32强赛，16强赛，8强赛三场比赛'
	},
	[27003] = {
		id = 27003,
