	[29001] = {
		id = 29001,
		fmt = '#C0xFFF5D6#1、预选赛，八强赛，冠军赛均为3对3车轮战。'
	},
	[29002] = {
		id = 29002,
		fmt = '#C0xFFF5D6#2、上阵宠物，总先手值高的先出手；先手值相同则总战力高的先出手。'
	},
	[29003] = {
		id = 29003,
		fmt = '#C0xFFF5D6#3、两个宠物对战，最高战斗回合为10回合。'
	},
	[29004] = {
		id = 29004,
		fmt = '#C0xFFF5D6#4、10回合结束后如均末死亡，则剩余血量百分比高的一方获胜。'
	},
	[29005] = {
		id = 29005,
