	},
	[30001] = {
		id = 30001,
		fmt = '#C0xFFF5D6#1、玩家第一天可下注自已在预选赛中胜利场次的单双数。'
	},
	[30002] = {
		id = 30002,
		fmt = '#C0xFFF5D6#2、第二天可下注该区总战力前64强玩家的冠军归属。'
	},
	[30003] = {
		id = 30003,
		fmt = '#C0xFFF5D6#3、冠军下注，赔率越高，回报越大。每期最高可获得1500000金币'
	},
	[30004] = {
		id = 30004,
		fmt = '#C0xFFF5D6#4、如下注对象进入四强则返还1.5倍金额，未进入四强则返还一半金额'
	},
	[30005] = {
		id = 30005,
		fmt = '#C0xFFF5D6#5、以下为排名奖励：'
	},
	[31001] = {
		id = 31001,
		fmt = '#C0x08ED1F#宠物们发现了一片盛产矿石的大陆，传闻在该大陆的商店中能用矿石兑换丰厚的奖励，因此驯兽师们纷纷加入了矿石的争夺中。'
	},
	[31002] = {
		id = 31002,
		fmt = '#C0xFFF5D6#1.跨服矿战进行时间：#C0x08ED1F#周六10点-下周一22点'
	},
	[31003] = {
		id = 31003,
		fmt = '#C0xFFF5D6#2.每日可抢夺时间段为：#C0x08ED1F#10点-22点'
	},
	[31004] = {
		id = 31004,
		fmt = '#C0xFFF5D6#3.每天免费抢夺#C0x08ED1F#3次'
	},
	[31005] = {
		id = 31005,
		fmt = '#C0xFFF5D6#4.每期比赛会根据服务器的实力和人数，匹配实力相近的若干服务器，各服务器间互相比拼，比赛结束时，根据各服一定排名内玩家的积分总和排序，积分总和越高的服务器获得越高的排名'
	},
	[31006] = {
		id = 31006,
		fmt = '#C0xFFF5D6#5.跨服矿战存在最终个人奖励，最终个人奖励由服务器排名及积分总和决定，最终个人奖励=服务器排名对应基础奖励+积分比重奖励，因此，服务器排名越高、积分越多，最终个人奖励越丰厚'
	},
	[31007] = {
		id = 31007,
		fmt = '#C0xFFF5D6#6.每个矿点对应一个排名，排名越高，积分越高，驯兽师可以通过附近矿区挑战更高排名的玩家提高排名，也可直接通过高级矿区直接挑战前10名的矿点'
	},
	[32001] = {
		id = 32001,
		fmt = '#C0xFFF5D6#1.矿石资源可用于鼓舞矿石兽和在矿战商店中兑换道具'
	},
	[32002] = {
		id = 32002,
		fmt = '#C0xFFF5D6#2.鼓舞矿石兽可为全服玩家或个人提供buff加成'
	},
	[32003] = {
		id = 32003,
		fmt = '#C0xFFF5D6#3.矿点可以生产矿石，每10分钟结算一次，排名越高，生产速度越快'
	},
	[32004] = {
		id = 32004,
		fmt = '#C0xFFF5D6#4.驯兽师们可向其他玩家的矿点发起抢夺'
	},
	[32005] = {
		id = 32005,
		fmt = '#C0xFFF5D6#5.抢夺本服玩家、战力比自己低太多的玩家时无法获得矿石'
	},
	[32006] = {
		id = 32006,
		fmt = '#C0xFFF5D6#6.矿点存在被抢夺上限，每次抢夺的数量无法超过被抢夺上限'
	},
	[32007] = {
		id = 32007,
		fmt = '#C0xFFF5D6#7.跨服矿战竞争激烈，在抢夺过程中目标玩家可能存在矿石变更，最终抢到的资源可能少于抢夺界面看到的资源数，先下手为强哟'
	},
	[33001] = {
		id = 33001,
		fmt = '#C0xFFF5D6#1.驯兽师们可以派出3队宠物进行战斗，每队最多4个'
	},
	[33002] = {
		id = 33002,
		fmt = '#C0xFFF5D6#2.战斗为三局两胜'
	},
	[33003] = {
		id = 33003,
		fmt = '#C0xFFF5D6#3.双方最多战斗20回合，若20回合未分胜负，则算防守方胜'
	},
	[34001] = {
		id = 34001,
		fmt = '#C0xFFF5D6#1.在战报中可对抢夺过自己的玩家发起复仇，只有被抢夺成功了才能发起复仇，且若被抢夺的玩家因受保护未被抢夺矿石时不触发复仇'
	},
	[34002] = {
		id = 34002,
		fmt = '#C0xFFF5D6#2.复仇行为类似抢夺，可抢夺对方矿石，但不更换排名'
	},
	[34003] = {
		id = 34003,
		fmt = '#C0xFFF5D6#3.驯兽师每天有5次复仇机会，该次数与抢夺独立计数'
	},
	[35001] = {
		id = 35001,
		fmt = '#C0xFFF5D6#1.比赛期间每日22点通过邮件发放个人排行奖励'
	},
	[35002] = {
		id = 35002,
		fmt = '#C0xFFF5D6#2.排名越高，奖励越丰厚，奖励为海量矿石资源和金币'
	},
	[36001] = {
		id = 36001,
		fmt = '#C0xFFF5D6#恶魔兽妄图破坏并重塑宠物世界，发出大量黑暗齿轮，控制了大批宠物，每天都会放出部分宠物出来作乱。为了拯救宠物世界，让我们团结起来，净化被黑色齿轮控制的宠物吧。'
	},
	[36002] = {
		id = 36002,
		fmt = '#C0xFFF5D6#1.每天12点会刷新新的黑暗宠物阵容。'
	},
	[36003] = {
		id = 36003,
		fmt = '#C0xFFF5D6#2.每天12点世界各地的召唤师门可以创建或加入其他召唤师的队伍，一起对抗被黑色齿轮控制的宠物。'
	},
	[36004] = {
		id = 36004,
		fmt = '#C0xFFF5D6#3.组队净化宠物可以获得相应的宠物碎片。'
	},
	[36005] = {
		id = 36005,
		fmt = '#C0xFFF5D6#4.想要净化某个宠物，需要先拥有该宠物。'
	},
	[36006] = {
		id = 36006,
		fmt = '#C0xFFF5D6#5.每次战斗胜利可以获得两个宝箱，第一个免费开启，第二个需要花费钻石，两个宝箱都有几率获得宠物碎片。'
	},
	[36007] = {
		id = 36007,
		fmt = '#C0xFFF5D6#6.每次净化任务中，完成所有战斗的玩家越多，获得的额外奖励越多，额外奖励将通过邮件发送，获得额外奖励的前提是自己完成所有战斗。'
	},
	[36008] = {
		id = 36008,
		fmt = '#C0xFFF5D6#7.队伍中3人、4人、5人完成战斗时可获得不同程度的额外奖励。'
	},
	[36009] = {
		id = 36009,
		fmt = '#C0xFFF5D6#8.选择净化目标后，只要战斗胜利过一次，就无法退出当前队伍，将战斗进行到底！'
	},
	[36010] = {
		id = 36010,
		fmt = '#C0xFFF5D6#9.每天12点老队伍会自动解散，需要重新组队。'
	},
	[36011] = {
		id = 36011,
		fmt = '#C0xFFF5D6#10.玩家可以点击队伍中自己的头像更换上阵的宠物。'
	},
	[37001] = {
