		fmt = '5、最终有存活精灵的一方胜利。'
	},
	[38001] = {
		id = 38001,
		fmt = '1、玩家第一天可下注自已在预选赛中胜利场次的单双数。'
	},
	[38002] = {
		id = 38002,
