	},
	[39001] = {
		id = 39001,
		fmt = '1.报名时间：#C0xF76B45#10:00-19:50'
	},
	[39002] = {
		id = 39002,
		fmt = '2.比赛时间：#C0xF76B45#20:00-20:55'
	},
	[39003] = {
		id = 39003,
		fmt = '3.报名时最多选择10名精灵上场，报名成功后可更换阵容'
	},
	[39004] = {
		id = 39004,
		fmt = '4.比赛分为预选赛和八强赛两部分，预选赛的8强可进入八强赛'
	},
	[39005] = {
		id = 39005,
		fmt = '5.比赛开始前1分钟，玩家无法调整上阵阵容'
	},
	[39006] = {
		id = 39006,
		fmt = '6.贵族3及以上的玩家在每天报名截止前50分钟将自动进行报名'
	},
	[39007] = {
		id = 39007,
		fmt = '7.战斗阶段双方最多战斗10回合，回合结束双方未分胜负，若双方血量都高于85%，则按照造成伤害较高的一方胜出，若其中只要有一方血量百分比低于85%，则按照最终血量百分比较高的一方胜出'
	},
	[39008] = {
		id = 39008,
		fmt = '8.比赛存在积分排行，积分由精灵造成的伤害决定，伤害越高，积分越高'
	},
	[39009] = {
		id = 39009,
		fmt = '9.每天10点可以开始下注，赔率越高，回报越丰厚，每天最高可获得100w金币'
	},
	[39010] = {
		id = 39010,
		fmt = '10.若下注对象进入八强，未获冠军，会返还部分下注金额；若未进入八强，则不返还金额'
	},
	[40001] = {
		id = 40001,
		fmt = '1.预选赛为淘汰制，一共10场比赛，每场比赛4分钟，根据胜利场次进行排名，胜利场次一样按照积分排名'
	},
	[40002] = {
		id = 40002,
		fmt = '2.每场比赛派出一名精灵进行对战'
	},
	[40003] = {
		id = 40003,
		fmt = '3.预选赛累计#C0xF76B45#3负直接淘汰出局'
	},
	[40004] = {
		id = 40004,
		fmt = '4.每场比赛玩家可获得积分，预选赛结束后根据胜利场次、积分排名得出8强,进入八强赛'
	},
	[40005] = {
		id = 40005,
		fmt = '5.精灵不能重复使用'
	},
	[41001] = {
		id = 41001,
		fmt = '1.八强赛阶段同样为淘汰制，包含四强赛、半决赛、冠军赛和季军赛四场比赛，每场比赛5分钟'
	},
	[41002] = {
		id = 41002,
		fmt = '2.每场比赛，玩家需派出3名精灵，采用车轮战，依顺序出场'
	},
	[41003] = {
		id = 41003,
		fmt = '3.3名精灵全部被击败则判负'
	},
	[41004] = {
		id = 41004,
		fmt = '4.精灵不能重复使用'
	},
	[42001] = {
		id = 42001,
		fmt = '1.每进行一场比赛，玩家可获得一个宝箱奖励'
	},
	[42002] = {
		id = 42002,
		fmt = '2.胜利获得黄金宝箱，失败获得白银宝箱'
	},
	[42003] = {
		id = 42003,
		fmt = '3.两种宝箱均有概率开出石英纪念品等物品'
	},
	[42004] = {
		id = 42004,
		fmt = '4.根据当天石英大会排名可获得排名奖励。'
	},
	[43001] = {
		id = 43001,
		fmt = '#C0xFFF5D6#1.初始每天可玩5次，在研究院中提升\'摇取火神兽\'科技等级，可增加玩法次数'
	},
	[43002] = {
		id = 43002,
		fmt = '#C0xFFF5D6#2.初始本玩法可免费改摇5次，同样，在研究院中提升相关科技，可增加免费改摇次数'
	},
	[43003] = {
		id = 43003,
		fmt = '#C0xFFF5D6#3.已经摇出的火神兽不会消失4.火神兽数量越多，奖励越丰厚，可获得火神兽碎片和大量公会币'
	},
	[43004] = {
		id = 43004,
		fmt = '#C0xFFF5D6#4.火神兽数量越多，奖励越丰厚，可获得火神兽碎片和大量公会币'
	},
	[44001] = {
		id = 44001,
		fmt = '1.公会副本开放时间：周一至周六9：30-23：30，周日休息；'
	},
	[44002] = {
		id = 44002,
		fmt = '2.周一、三、五凌晨5点系统自动重置副本，仅重置当前进度中难度最高的副本；周二、四、六晚23:30，公会副本关闭后统一结算并发放伤害排名奖励'
	},
	[44003] = {
		id = 44003,
		fmt = '3.每天有3次挑战次数，所有副本共用该次数，每天凌晨5点重置，挑战过程中有几率获得公会首领宝箱；'
	},
	[44004] = {
		id = 44004,
		fmt = '4.通关当前副本后，将会开启下一副本，已通关的副本在月度重置前无法重复打；'
	},
	[44005] = {
		id = 44005,
		fmt = '5.每个公会副本挑战完成后，将根据副本贡献，发放额外的伤害排名奖励；'
	},
	[44006] = {
		id = 44006,
		fmt = '6.每个副本有首次通关奖励，每个玩家只能领取一次；'
	},
	[44007] = {
		id = 44007,
		fmt = '7.单个副本随着通关公会个数和停留时长，公会内玩家将获得额外的攻、防、血量加成，该加成只对当前副本生效；'
	},
	[44008] = {
		id = 44008,
		fmt = '8.每月月初重置所有副本，重置后每通关一个副本，全公会可领取击杀奖励（非首次通关奖励）；'
	},
	[44009] = {
		id = 44009,
		fmt = '9.击杀奖励（非首次通关奖励）每个玩家每个副本每次重置均只能领取1次；'
	},
	[44010] = {
		id = 44010,
		fmt = '10.更换公会后，当天无法进行公会副本挑战，需要等到次日凌晨5点后才能进行；'
	},
	[44011] = {
		id = 44011,
		fmt = '11.为每只公会首领补刀的训练家可额外获得金币钻石奖励，同一只首领的击杀奖励在一个月重置周期内只能拿一次；'
	},
	[44012] = {
		id = 44012,
		fmt = '12.所有击杀奖励需要手动在奖励盒子里领取；参与奖励和补刀奖励挑战结算时发放；伤害排名奖励以邮件形式发放。'
	},
	[45001] = {
		id = 45001,
		fmt = '1.每位会员每天可以许愿一次，将希望获取碎片的精灵作为愿望发布到公会中'
	},
	[45002] = {
		id = 45002,
		fmt = '2.许愿时只能以自己当前拥有的精灵作为许愿目标'
	},
	[45003] = {
		id = 45003,
		fmt = '3.不同品质的精灵，每次许愿可以获得的最大数量有所不同，品质越高的精灵，可获取的数量越少'
	},
	[45004] = {
		id = 45004,
		fmt = '4.可以给其他会员赠送自己拥有的碎片，来帮助他完成心愿，最多可以给同一个会员赠送1个碎片'
	},
	[45005] = {
		id = 45005,
		fmt = '5.精灵碎片赠送后会以邮件形式发送到受赠会员的邮箱中'
	},
	[45006] = {
		id = 45006,
		fmt = '6.赠送不同品质的精灵碎片可以得到不同数量的精灵魂石和热心人点数奖励'
	},
	[45007] = {
		id = 45007,
		fmt = '7.每天5点清空所有的许愿列表'
	},
	[46001] = {
		id = 46001,
		fmt = '#C0xFFF5D6#1.每进行一场比赛，玩家可获得一个宝箱奖励'
	},
	[46002] = {
		id = 46002,
		fmt = '#C0xFFF5D6#2.胜利获得黄金宝箱，失败获得白银宝箱'
	},
	[46003] = {
		id = 46003,
		fmt = '#C0xFFF5D6#3.两种宝箱均有概率开出指环、徽章等物品'
	},
	[46004] = {
		id = 46004,
		fmt = '#C0xFFF5D6#4.根据当天王者之战排名可获得排名奖励，包括天使兽碎片等稀有物品'
	},
	[47001] = {
		id = 47001,
		fmt = '1.将合金镶嵌在宠物的矩阵槽上，宠物可获得合金的数值加成，矩阵槽位随战队等级解锁；'
	},
	[47002] = {
		id = 47002,
		fmt = '2.将合金以指定的类型放置在矩阵槽中时，可激活矩阵属性加成，宠物实力将得到进一步提升；'
	},
	[47003] = {
		id = 47003,
		fmt = '3.矩阵效果本身存在品质强弱，当激活矩阵效果的合金全部达到某一品质时，该矩阵效果也可提升至该品质，也即：矩阵效果的强弱取决于矩阵中品质最低的合金；'
	},
	[47004] = {
		id = 47004,
		fmt = '4.当宠物激活某个矩阵效果，且当前矩阵槽中还有空位时，可自行选择在空槽中使用喜欢的合金，不会影响矩阵效果的激活；'
	},
	[47005] = {
		id = 47005,
		fmt = '5.多余的合金可通过合金熔炼转化为合金精华，合金精华可用作提升其他合金的等级。'
	},
	[48001] = {
		id = 48001,
		fmt = '完成列表中的每日任务，即可获得对应的累计活跃度。'
	},
	[48002] = {
		id = 48002,
		fmt = '当每日活跃度累积达到20、40、60、80、100时，可以领取活跃度累计宝箱中的奖励。'
	},
	[48003] = {
		id = 48003,
		fmt = '部分如累计在线、消耗体力等的活跃度任务，可以分阶段完成，每个阶段都能获得该阶段的活跃度。'
	},
	[49001] = {
		id = 49001,
		fmt = '1.在限时宝箱里每抽取一次宝箱，可获得10积分，积分高低决定排行榜排名先后，积分相同时，先达到该积分的玩家排名靠前'
	},
	[49002] = {
		id = 49002,
		fmt = '2.在本活动中，每抽取十次装备宝箱必得觉醒合金和万能碎片宝箱(不产出觉醒碎片)'
	},
	[49003] = {
		id = 49003,
		fmt = '3.活动结束时间为最后一天的21:30，活动结束后，无法再进行抽奖，前30名奖励将通过邮件发放'
	},
	[49004] = {
		id = 49004,
		fmt = '4.第1名的排行奖励需要达到7000积分'
	},
	[49005] = {
		id = 49005,
		fmt = '5.2-3名的排名奖励需要达到5000积分'
	},
	[49006] = {
		id = 49006,
		fmt = '6.4-6名的排名奖励需要达到3500积分'
	},
	[49007] = {
		id = 49007,
		fmt = '7.7-10名的排名奖励需要达到2000积分'
	},
	[49008] = {
		id = 49008,
		fmt = '8.11-20名的排名奖励需要达到1000积分'
	},
	[49009] = {
		id = 49009,
		fmt = '9.若未达到活动对应积分需求，只能领取自身积分对应奖励'
	},
	[50001] = {
		id = 50001,
		fmt = '1.活动期间，每累计充值6元，可获得一个砸金蛋的锤子。每天最多能获得10个锤子。'
	},
	[50002] = {
		id = 50002,
		fmt = '2.砸金蛋的正确步骤为：拥有锤子的情况下，点击您喜欢的金蛋，即可获取奖励。'
	},
	[50003] = {
		id = 50003,
		fmt = '3.每砸一次金蛋，消耗1个锤子和XXXX货币（数量和货币读取配置）。每次砸蛋有几率获取3倍、6倍、10倍的翻倍奖励。'
	},
	[50004] = {
		id = 50004,
		fmt = '4.当砸中10倍大奖时，会立即重置为3个金蛋，若未砸中，可继续砸剩余的金蛋直至砸中。'
	},
	[50005] = {
		id = 50005,
		fmt = '5.如果运气好，第一次就能砸出10倍大奖；如果运气欠佳，3次砸完也必定会出10倍奖励。'
	},
	[51001] = {
		id = 51001,
		fmt = '1.限时首领活动为限时活动，活动期间每天有3次挑战首领的机会，次数用完后，可花费钻石购买次数，挑战次数每天凌晨5点重置；'
	},
	[51002] = {
		id = 51002,
		fmt = '2.排行榜会记录玩家的单次最高伤害，而非总伤害；'
	},
	[51003] = {
		id = 51003,
		fmt = '3.每次挑战会获得一定的金币和道具奖励；'
	},
	[51004] = {
		id = 51004,
		fmt = '4.活动开放期间，每天凌晨5点会重置排行榜，并根据伤害排行发放排行奖励；'
	},
	[51005] = {
		id = 51005,
		fmt = '5.限时首领有各种各样的属性特点，挑战前还请仔细阅读首领介绍。'
	},
	[51006] = {
		id = 51006,
		fmt = '6.挑战限时首领-奥米加兽时建议开启系统设置中的镜头拉伸功能'
	},
	[52001] = {
		id = 52001,
		fmt = '点击（按住）屏幕的相对左右位置操作亚'
	},
	[52002] = {
		id = 52002,
		fmt = '古兽向左右移动，在生命值耗尽之前，下的层'
	},
	[52003] = {
		id = 52003,
		fmt = '数越多，越有机会获得更高的奖励。'
	},
	[52004] = {
		id = 52004,
		fmt = '点击（按住）屏幕的相对左右位置操作宠物向左右移动，在生命值耗尽之前，下的层数越多，越有机会获得更高的奖励。'
