	[57006] = {
		id = 57006,
		fmt = '6.等级达到90级且通过300关可解锁#C0xF76B45##L10#冒险之路深渊模式#C0x5b545b#'
	},
	[58001] = {
		id = 58001,
		fmt = '1.精灵训练师可以通过重生系统，将自己背包内的精灵还原至初始状态'
	},
	[58002] = {
		id = 58002,
		fmt = '2.精灵重生的内容，包括：精灵等级、突破品质、技能、饰品'
	},
	[58003] = {
