	},
	[83004] = {
		id = 83004,
		fmt = '4.符石重生需要消耗钻石，重生的符石培养程度越高需要的钻石会更多；单个符石重生钻石消耗上限为10#Icommon/icon/icon_diamond.png-56-56#'
