		fmt = '5.未培养过的符石无法进行重生，也不会出现在重生可选符石的界面内'
	},
	[84001] = {
		id = 84001,
		fmt = '1.精灵训练师们可以将多余的符石在符石分解内无消耗分解'
	},
	[84002] = {
		id = 84002,
		fmt = '2.对于已培养过的符石，分解后将100%返还消耗的强化材料和金币'
	},
	[84003] = {
		id = 84003,
		fmt = '3.镶嵌中的符石不能分解，也无法在符石分解内查看'
	},
	[84004] = {
		id = 84004,
		fmt = '4.每次分解可按照品质分类一键多选；或者长按多选进行分解'
	},
	[84005] = {
		id = 84005,
		fmt = '5.符石分解后可获得符石强化材料，用来强化其他的符石'
	},
	[85001] = {
		id = 85001,
		fmt = '1.活动时间内，玩家可以率领精灵挑战世界首领'
	},
	[85002] = {
		id = 85002,
		fmt = '2每局挑战世界首领会记录玩家的伤害量，达成相应目标伤害可在本次挑战结束后立即获得对应宝箱里的奖励'
	},
	[85003] = {
		id = 85003,
		fmt = '3.世界首领记录全服玩家最高伤害总值，达成目标后，当日参与活动的玩家可获得宝箱奖励，奖励在次日5点邮件发放，且此时会重置累计伤害数据'
	},
	[85004] = {
		id = 85004,
		fmt = '4.世界首领有免费挑战次数，也可额外购买，次数达到上限后当日不可再进战斗，次数在次日5点重置'
	},
	[85005] = {
		id = 85005,
		fmt = '5.当日挑战世界首领单次造成的个人最高伤害将被记录进个人排行与公会排行榜，排行榜与伤害记录在次日5点重置'
	},
	[85006] = {
		id = 85006,
		fmt = '6.登上排行榜的玩家与公会都将获得排行奖励，奖励预览请点击排名奖励按钮，奖励将在次日5点通过邮件的形式发放'
	},
	[85007] = {
		id = 85007,
		fmt = '7.没有加入公会的玩家不进入公会排行，若数据重置前加入公会，则只记录在新公会之后的世界首领挑战信息'
	},
	[85008] = {
		id = 85008,
		fmt = '8.玩家在已有公会的情况下进入世界首领战斗后退出公会，数据重置前再次加入公会将不在新公会产生自己的伤害数据'
	},
	[86001] = {
		id = 86001,
		fmt = '1.跨服竞技场需要等待服务器间匹配，当匹配成功后，会在界面展示#C0xF76B45#匹配成功等待开赛状态#C0x5B545B#'
	},
	[86002] = {
		id = 86002,
		fmt = '2.赛季流程：#C0xF76B45#赛季开赛（两周14日）——赛季结束，玩家展示（持续5日）——准备开赛（预告2日）'
	},
	[86003] = {
		id = 86003,
		fmt = '3.赛季过程中设置2次排名结算，分别为#C0xF76B45#赛季第7日22:00时阶段性结算，以及第14日22:00赛季季终结算'
	},
	[86004] = {
		id = 86004,
		fmt = '4.赛季中，每日有免费的挑战次数，也可额外花费钻石购买挑战次数，次数每天5点重置'
	},
	[86005] = {
		id = 86005,
		fmt = '5.玩家可以手动刷新可挑战对手，手动刷新有免费次数，当免费次数使用完之后，需要花费金币刷新对手，手动刷新免费次数每天5点进行重置'
	},
	[86006] = {
		id = 86006,
		fmt = '6.赛季段位有大段位与小段位的展示区别，大段位按照#C0xF76B45#青铜—白银—黄金—铂金—钻石—无畏大师—巅峰王者#C0x5B545B#低到高排序，小段位则按照数字大小排序，数字越小，排序越高，无畏大师、巅峰王者不设小段位'
	},
	[86007] = {
		id = 86007,
		fmt = '7.每个小段位内设定有排名，排名有限定的名次，每个训练家都将按照段位>段位内排名进行总的排序（无小段位的则以大段位来进行排序）'
	},
	[86008] = {
		id = 86008,
		fmt = '8.在对战情报内，可提供查看最近一段时间内高段位玩家之间的对战视频'
	},
	[87001] = {
		id = 87001,
		fmt = '1.对战前，玩家可以布阵2组队伍，可上阵不少于2个不多于12只精灵'
	},
	[87002] = {
		id = 87002,
		fmt = '2.战斗实行6对6车轮战，最多3轮战斗，第一轮胜利的队伍会保持当前状态继续挑战对方的下一支队伍'
	},
	[87003] = {
		id = 87003,
		fmt = '3.一方2队的精灵全战败则判失败，若回合结束未分胜负的，则血量多的一方判胜利'
	},
	[87004] = {
		id = 87004,
		fmt = '4.跨服竞技场的战斗方式为#C0xF76B45#锁定自动战斗#C0x5B545B#'
	},
	[87005] = {
		id = 87005,
		fmt = '5.玩家主动挑战对手，若战斗胜利，则与对方互换排名；若战斗失败，则排名不进行变化'
	},
	[87006] = {
		id = 87006,
		fmt = '6.对方主动挑战玩家时，将派出玩家的防守阵容迎战，排名更迭与战斗结束关系与上条一致'
	},
	[88001] = {
		id = 88001,
		fmt = '1.每日挑战达成任务次数之后，可以手动在竞技奖励-每日奖励页签中领取奖励，每天5点重置任务'
	},
	[88002] = {
		id = 88002,
		fmt = '2.当最高段位记录更新时，可以手动在竞技奖励-段位奖励页签中领取奖励，该奖励每个赛季结束后进行重置'
	},
	[88003] = {
		id = 88003,
		fmt = '3.赛季过程中2次排名结算，会根据段位以邮件发放奖励，奖励详情可前往竞技奖励-赛季七日、赛季最终页签进行查看'
	},
	[89001] = {
		id = 89001,
		fmt = '1.好感度交换需要一定的限定条件\n     条件①：双方精灵的初始形态拥有相同的稀有度\n     条件②：双方培养好感度所消耗的材料是一致的'
	},
	[89002] = {
		id = 89002,
		fmt = '2.好感度交换时，只需满足条件的精灵图鉴激活即可，即使背包内没有对应精灵时也可以进行好感度交换'
	},
	[90001] = {
		id = 90001,
		fmt = '1.每期活动的限定提升符石种类会有所变化'
	},
	[90002] = {
		id = 90002,
		fmt = '2.每日有一次免费抽取限定的机会，次日5点重置免费次数'
	},
	[90003] = {
		id = 90003,
		fmt = '3.每日的抽取次数有一定限制，免费抽取次数不包括在内'
	},
	[91001] = {
		id = 91001,
		fmt = '1.每期限定符石活动的符石置换次数会有一定限制，超出限制次数后本期活动时间内无法继续置换'
	},
	[91002] = {
		id = 91002,
		fmt = '2.符石置换仅限紫色及紫色以上、且相同品质的符石'
	},
	[91003] = {
		id = 91003,
		fmt = '3.符石置换至少需要2个或3个同品质符石；#C0xF76B45##L10#消耗2个同品质符石只能置换获得1个新的同品质符石，消耗3个同品质符石可以置换2个新的同品质符石'
	},
	[91004] = {
		id = 91004,
		fmt = '4.符石置换的方式有3种：'
	},
	[91005] = {
		id = 91005,
		fmt = '①[限定类型]和[限定编号]默认都不勾选时，同品质之间等权值随机置换'
	},
	[91006] = {
		id = 91006,
		fmt = '②[限定类型]勾选时，仅限相同品质和相同种类之间等权值随机置换'
	},
	[91007] = {
		id = 91007,
		fmt = '③[限定编号]勾选时，仅限相同品质和相同编号之间等权值随机置换'
	},
	[91008] = {
		id = 91008,
		fmt = '5.[限定类型]和[限定编号]二者只能二选其一'
	},
	[91009] = {
		id = 91009,
		fmt = '6.符石置换会消耗钻石。置换次数越多，消耗的钻石也会越多；选择置换的符石品质越高，消耗的钻石也会越高'
	},
	[91010] = {
		id = 91010,
		fmt = '7.选择已强化过的符石置换后，对应强化等级的强化材料会免费返还'
	},
	[91011] = {
		id = 91011,
		fmt = '8.符石置换界面内，只会显示原符石背包内品质不低于紫色、且未镶嵌的符石；已镶嵌在精灵身上的符石不会看到'
	},
	[92001] = {
		id = 92001,
		fmt = '1.活动时间内，玩家可在粽叶飘香活动中使用收集来的食材包粽子'
	},
	[92002] = {
		id = 92002,
		fmt = '2.食材分为主料、配料两类，使用#C0xF76B45#粽子食材礼盒道具#C0x5B545B#可随机获得，限时活动中#C0xF76B45#连续登陆、完成任务得粽子食材#C0x5B545B#活动中可获得该道具'
	},
	[92003] = {
		id = 92003,
		fmt = '3.制作时需要#C0xF76B45#同时放置主料与配料，缺少一类将无法制作粽子'
	},
	[92004] = {
		id = 92004,
		fmt = '4.主料、配料可以#C0xF76B45#随意进行搭配，#C0x5B545B#都可制作出不同口味的粽子'
	},
	[92005] = {
		id = 92005,
		fmt = '5.获得粽子后可在活动界面或背包内进行使用，食材与粽子均设有使用期限，#C0xF76B45#请在期限内进行制作与食用，#C0x5B545B#过期后道具将被清理'
	},
	[93001] = {
		id = 93001,
		fmt = '1.钓鱼玩法有每日次数限制，次数限制每日5:00刷新，次数消耗完后当日不能再进行钓鱼'
	},
	[93002] = {
		id = 93002,
		fmt = '2.每次钓鱼需要消耗一个鱼饵'
	},
	[93003] = {
		id = 93003,
		fmt = '3.鱼上钩以后需要控制鱼钩和鱼重合，点击/按住收线则鱼钩向上，放开则向下'
	},
	[93004] = {
		id = 93004,
		fmt = '4.当鱼钩和鱼重合时进度钓鱼进度提升，反之进度下降'
	},
	[93005] = {
		id = 93005,
		fmt = '5.当进度条到达顶部时钓鱼成功，进度条到达底部则钓鱼失败，无论成功失败都会消耗次数和鱼饵'
	},
	[93006] = {
		id = 93006,
		fmt = '6.选择更高品质的鱼竿和鱼饵可以降低钓鱼的操作难度或提升自动钓鱼的成功率'
	},
	[93007] = {
		id = 93007,
		fmt = '7.钓鱼等级的提升可以获得一定的全精灵属性加成和钓鱼操作难度的降低'
	},
	[93008] = {
		id = 93008,
		fmt = '8.钓鱼等级的提升需要达成对应等级的鱼的条目计数，计数全满后自动升级，升级后新一级计数重新开始计算'
	},
	[93009] = {
		id = 93009,
		fmt = '9.可能会有一些其他神秘精灵出现，精灵不计入升级计数内。'
	},
	[93010] = {
		id = 93010,
		fmt = '10.训练家等级到达68级时可使用自动钓鱼功能，点击界面上的陪伴精灵进入自动钓鱼，自动钓鱼有可能失败.'
	},
	[93011] = {
		id = 93011,
		fmt = '11.钓鱼涉及到的部分属性解释：'
	},
	[93012] = {
		id = 93012,
		fmt = '①自动钓鱼成功率——自动钓鱼过程中鱼的成功率由自身品质决定，受到渔具的影响'
	},
	[93013] = {
		id = 93013,
		fmt = '②进度提升速度——钓鱼操作界面，鱼钩和鱼位置重合时右侧的进度提升速度'
	},
	[93014] = {
		id = 93014,
		fmt = '③进度下降速度——钓鱼操作界面，鱼钩和鱼位置不重合时右侧的进度下降速度'
	},
	[93015] = {
		id = 93015,
		fmt = '④鱼钩判定范围——鱼钩所在的判定框的大小，受到鱼饵的影响'
	},
	[93016] = {
		id = 93016,
		fmt = '⑤钓鱼等待时间——从抛竿到鱼上钩锁需要的等待时间'
	},
	[93017] = {
		id = 93017,
		fmt = '⑥鱼行动范围——钓鱼操作界面中鱼每次上下浮动的距离'
	},
	[94001] = {
		id = 94001,
		fmt = '1.钓鱼大赛每两周举行一次，参赛时间为周日5:00-23:00'
	},
	[94002] = {
		id = 94002,
		fmt = '2.每次大赛将会随机匹配若干服务器进行比赛，根据钓上的积分进行排名'
	},
	[94003] = {
		id = 94003,
		fmt = '3.比赛结束时根据最终积分排名发放排名奖励'
	},
	[94004] = {
		id = 94004,
		fmt = '4.同积分的训练家排名根据到达时间'
	},
	[94005] = {
		id = 94005,
		fmt = '5.大赛中会出现稀有的盖欧卡，盖欧卡拥有更高的积分'
	},
	[94006] = {
		id = 94006,
		fmt = '6.使用大赛专用高级鱼饵可以增加盖欧卡的出现概率'
	},
	[94007] = {
		id = 94007,
		fmt = '7.预祝取得好成绩'
	},
	[95001] = {
		id = 95001,
		fmt = '1.图鉴内特定的精灵可以在超进化屋内进行超进化。'
	},
	[95002] = {
		id = 95002,
		fmt = '2.超进化之后精灵的基础属性会获得提升，所有已培养属性将完全继承；属性系和稀有度#C0xF76B45##L10#也可能有所变化#C0x5B545B#。'
	},
	[95003] = {
		id = 95003,
		fmt = '3.精灵需要培养至一定阶段后才可以进行超进化；且主要消耗两类特殊的道具：钥石和专属的超级进化石。'
	},
	[95004] = {
		id = 95004,
		fmt = '4.钥石和专属的超级进化石，每天都可以在超进化屋内通过转化获得，升星过的精灵不能作为转化钥石和专属的超级进化石的材料。'
	},
	[95005] = {
		id = 95005,
		fmt = '5.超进化屋会不定时开放新的超进化精灵，敬请期待。'
	},
	[95101] = {
		id = 95101,
		fmt = '#C0xF76B45##L10#请玩家认真谨慎阅读以下特殊超进化规则！！！#C0x5B545B#'
	},
	[95102] = {
		id = 95102,
		fmt = '#C0xF76B45##L10#请玩家认真谨慎阅读以下特殊超进化规则！！！#C0x5B545B#'
	},
	[95103] = {
		id = 95103,
		fmt = '#C0xF76B45##L10#请玩家认真谨慎阅读以下特殊超进化规则！！！#C0x5B545B#'
	},
	[95104] = {
		id = 95104,
		fmt = '1.超梦超进化的两个形态需要经历以下操作：#C0xF76B45##L30#初始超进化#C0x5B545B# → #C0xF76B45##L30#线路解锁#C0x5B545B# → #C0xF76B45##L30#形态转换#C0x5B545B#'
	},
	[95105] = {
		id = 95105,
		fmt = '2.#C0xF76B45##L30#初始超进化#C0x5B545B#：超梦初始超进化可以选择超级超梦x或超级超梦y，但只能超进化到其中#C0xF76B45##L30#一个形态#C0x5B545B#'
	},
	[95106] = {
		id = 95106,
		fmt = '3.#C0xF76B45##L30#线路解锁#C0x5B545B#：初始超进化后，仍在当前界面消耗一定资源解锁另外一个形态，线路解锁#C0xF76B45##L30#不消耗精灵#C0x5B545B#'
	},
	[95107] = {
		id = 95107,
		fmt = '4.#C0xF76B45##L30#形态转换#C0x5B545B#：解锁形态后，可在分支切换界面操作形态转换，#C0xF76B45##L30#每次形态转换都有消耗且转换后进入冷却时间#C0x5B545B#'
	},
	[95108] = {
		id = 95108,
		fmt = '5.超级超梦x&超级超梦y本质上为同一个精灵的两个分支形态，玩家可根据自身阵容搭配选择需要转换的形态'
	},
	[95109] = {
		id = 95109,
		fmt = '6.#C0xF76B45##L30#特殊情况答疑#C0x5B545B#：'
	},
	[95110] = {
		id = 95110,
		fmt = '		问：若真的同时拥有超级超梦x和超级超梦y可以一起上阵吗'
	},
	[95111] = {
		id = 95111,
		fmt = '		答：不可同时上阵'
	},
	[95201] = {
		id = 95201,
		fmt = '#C0xF76B45##L10#请玩家认真谨慎阅读以下特殊超进化规则！！！#C0x5B545B#'
	},
	[95202] = {
		id = 95202,
		fmt = '#C0xF76B45##L10#请玩家认真谨慎阅读以下特殊超进化规则！！！#C0x5B545B#'
	},
	[95203] = {
		id = 95203,
		fmt = '#C0xF76B45##L10#请玩家认真谨慎阅读以下特殊超进化规则！！！#C0x5B545B#'
	},
	[95204] = {
		id = 95204,
		fmt = '焰白酋雷姆由酋雷姆和莱希拉姆合体进化得到'
	},
	[95205] = {
		id = 95205,
		fmt = '#C0xF76B45##L10#合体相关#C0x5B545B#'
	},
	[95206] = {
		id = 95206,
		fmt = '1.合体条件：需要合体前的精灵达到一定的养成条件'
	},
	[95207] = {
		id = 95207,
		fmt = '2.合体后焰白酋雷姆的卡牌养成中有且仅有个体值，好感度，性格这三项继承#C0xF76B45##L10#【首次合体】#C0x5B545B#选择的酋雷姆（后续该酋雷姆改变后再次合体，不同步继承），焰白酋雷姆的性格、个体值可以用酋雷姆进行交换，好感度、努力值的交换方式与其他超进化神话精灵一致'
	},
	[95208] = {
		id = 95208,
		fmt = '3.合体状态下：被合体使用的酋雷姆和莱希拉姆不可在用于各类系统和玩法的布阵'
	},
	[95209] = {
		id = 95209,
		fmt = '4.合体状态下：焰白酋雷姆与酋雷姆，莱希拉姆不可一起上阵'
	},
	[95210] = {
		id = 95210,
		fmt = '5.焰白酋雷姆不可用于星级转移'
	},
	[95211] = {
		id = 95211,
		fmt = '#C0xF76B45##L10#解体相关#C0x5B545B#'
	},
	[95212] = {
		id = 95212,
		fmt = '1.请玩家谨慎选择解体功能，重新合体需要消耗额外资源'
	},
	[95213] = {
		id = 95213,
		fmt = '2.解体后，合体前的酋雷姆和莱希拉姆可恢复使用于养成或玩法布阵'
	},
	[95214] = {
		id = 95214,
		fmt = '3.解体后，焰白酋雷姆处于上锁状态，各类系统和玩法布阵中不可用'
	},
	[95215] = {
		id = 95215,
		fmt = '4.解体后，可继续培养焰白酋雷姆，重新激活后养成阶段保留'
	},
	[95216] = {
		id = 95216,
		fmt = '#C0xF76B45##L10#合体分支#C0x5B545B#'
	},
	[95217] = {
		id = 95217,
		fmt = '暗黑酋雷姆相关'
	},
	[95218] = {
		id = 95218,
		fmt = '1.若当前处于焰白合体状态，需要解体后，重新合体得到暗黑酋雷姆'
	},
	[95219] = {
		id = 95219,
		fmt = '2.首次合成暗黑酋雷姆的消耗资源与解体后重新合体焰白酋雷姆的消耗资源不同'
	},
	[95220] = {
		id = 95220,
		fmt = '3.其他合体规则类比于焰白酋雷姆'
	},
	[96001] = {
		id = 96001,
		fmt = '1.钥石可以通过消耗#C0xF76B45##L10#同稀有度精灵#C0x5B545B#或者#C0xF76B45##L10#同稀有度精灵的碎片#C0x5B545B#转化获得，且每日有一定的转化数量限制:'
	},
	[96002] = {
		id = 96002,
		fmt = '①每个稀有品质精灵或紫色百变怪可转化10个紫色进化钥石,每3个稀有品质碎片可转化1个紫色进化钥石'
	},
	[96003] = {
		id = 96003,
		fmt = '②每个精英品质精灵或橙色百变怪可转化10个橙色进化钥石,每5个精英品质碎片可转化1个橙色进化钥石'
	},
	[96004] = {
		id = 96004,
		fmt = '③每个史诗品质精灵或红色百变怪可转化10个红色进化钥石,每8个史诗品质碎片可转化1个红色进化钥石'
	},
	[96005] = {
		id = 96005,
		fmt = '2.每日05:00系统固定增加和钻石购买的钥石可转化数量，可永久累积但不能超出上限'
	},
	[97001] = {
		id = 97001,
		fmt = '1.专属的超级石可以通过消耗#C0xF76B45##L10#同属性且同稀有度的精灵#C0x5B545B#或者#C0xF76B45##L10#同属性且同稀有度的精灵碎片#C0x5B545B#转化获得，且每日有一定的转化数量限制:'
	},
	[97002] = {
		id = 97002,
		fmt = '①每个稀有品质同属性精灵或紫色百变怪可转化10个紫色品质的超级石,每3个稀有品质碎片可转化1个紫色品质的超级石'
	},
	[97003] = {
		id = 97003,
		fmt = '②每个精英品质同属性精灵或橙色百变怪可转化10个橙色品质的超级石,每5个精英品质碎片可转化1个橙色品质的超级石'
	},
	[97004] = {
		id = 97004,
		fmt = '③每个史诗品质同属性精灵或红色百变怪可转化10个红色品质的超级石,每8个史诗品质碎片可转化1个红色品质的超级石'
	},
	[97005] = {
		id = 97005,
		fmt = '3.对于不同的超级石，系统会单独纪录转化数量'
	},
	[97006] = {
		id = 97006,
		fmt = '4.每日05:00系统固定增加和钻石购买的超级石可转化数量，可永久累积但不能超出上限'
	},
	[98001] = {
		id = 98001,
		fmt = '1.对战竞技场是#C0xF76B45#跨服匹配战斗#C0x5B545B#，因此，需要等待匹配服务器，匹配成功过后，会在界面展示#C0xF76B45#匹配成功等待开赛状态'
	},
	[98002] = {
		id = 98002,
		fmt = '2.对战竞技场按赛季进行，赛季流程：#C0xF76B45#本赛季预告开赛→赛季进行中→赛季结束、排名展示。赛季时间一般会持续几周时间，在你的形象上方可以查看'
	},
	[98003] = {
		id = 98003,
		fmt = '3.赛季中以每周为循环，匹配开放期间，可以无限次匹配战斗；未开启匹配时，则不可进行战斗。#C0xF76B45#匹配时间参见开始匹配按钮下方'
	},
	[98004] = {
		id = 98004,
		fmt = '4.对战竞技场为#C0xF76B45#实时匹配对战#C0x5B545B#， 所有模式需要手动点击开始匹配后，等待系统匹配一个旗鼓相当的对手，与对手战斗中也需要全程在线战斗'
	},
	[98005] = {
		id = 98005,
		fmt = '5.采用#C0xF76B45#积分制#C0x5B545B#；胜率越高，积分将越高，排行榜按照所有参与玩家的积分值进行先后排名，#C0xF76B45#场内2个模式独立计算积分，并且进行排名'
	},
	[98006] = {
		id = 98006,
		fmt = '6.每次赛季开始时，会清空前赛季中玩家历史最高分记录、2个模式积分的内容'
	},
	[99001] = {
		id = 99001,
		fmt = '1.对战竞技场内开放2个模式玩法，#C0xF76B45#无限制赛模式与公平赛模式#C0x5B545B#'
	},
	[99002] = {
		id = 99002,
		fmt = '2.无限制赛模式需要在#C0xF76B45#开始匹配前设定好编队阵容#C0x5B545B#，进入后手动操作战斗'
	},
	[99003] = {
		id = 99003,
		fmt = '3.公平赛模式则设有主题玩法，#C0xF76B45#主题玩法以周为单位，每周或每几周进行主题更换（只更换主题，积分仍累计计算）'
	},
	[99004] = {
		id = 99004,
		fmt = '4.公平赛根据正式战斗前选取精灵的流程分为#C0xF76B45#选位制与禁选制，积分达到一定分数后自动进阶为禁选制（主题不变更），具体分数可在公平赛模式下，点击切换按钮下方的 i 进行查阅'
	},
	[99005] = {
		id = 99005,
		fmt = '5.公平赛需要提前预设好备选阵容，#C0xF76B45#精灵数量不足最低匹配限制时将无法进行匹配，备选阵容决定了禁选阶段可上阵的精灵'
	},
	[99006] = {
		id = 99006,
		fmt = '6.无限制赛模式与公平赛模式都采用1场#C0xF76B45#6对6#C0x5B545B#的模式，公平赛战斗中会对精灵的#C0xF76B45#各项属性#C0x5B545B#进行公平修正，不同稀有度的精灵也会相应修正到一个维度，精灵的速度属性决定战斗的先后手'
	},
	[99007] = {
		id = 99007,
		fmt = '7.公平赛战斗中#C0xF76B45#携带道具、符文、性格等#C0x5B545B#系统的属性及效果都不会带入，公会技能、天赋技能、探险器属性等双方都会修正到统一水平线'
	},
	[99008] = {
		id = 99008,
		fmt = '8.无限制赛模式与公平赛模式战斗均采用#C0xF76B45#手动模式#C0x5B545B#，在规定倒计时结束内对精灵进行技能操作，倒计时结束执行自动战斗'
	},
	[99009] = {
		id = 99009,
		fmt = '9.无限制赛模式与公平赛模式战斗最多进行20回合，战斗过程中一方精灵全战败则判失败，若回合结束未分出胜负，则血量多的一方判胜利'
	},
	[100001] = {
		id = 100001,
		fmt = '1.开启匹配期间，#C0xF76B45#每日前6场战斗结束后#C0x5B545B#设定有结算奖励，无论输赢都可获得奖励'
	},
	[100002] = {
		id = 100002,
		fmt = '2.赛季中每周设立#C0xF76B45#小目标奖励，在界面右下角礼包处进行领取#C0x5B545B#，完成简单的匹配任务即可领取'
	},
	[100003] = {
		id = 100003,
		fmt = '3.赛季中#C0xF76B45#每周发放结算奖励，在周日结束匹配的30分钟之后#C0x5B545B#，取玩家2个模式中积分较高的对应区间奖励进行发放，#C0xF76B45#注意：每周至少参与3场匹配（无论模式）的玩家才可领取结算奖励'
	},
	[100004] = {
		id = 100004,
		fmt = '4.赛季末#C0xF76B45#发放一次结算奖励，在最后一日结束匹配的30分钟之后进行#C0x5B545B#，取玩家2个模式中当前排行最高的对应名次奖励进行发放，#C0xF76B45#注意：赛季中至少参与1场匹配（无论模式）的玩家才可领取结算奖励'
	},
	[100005] = {
		id = 100005,
		fmt = '5.系统货币可以在对应的对战竞技场商店内进行使用，商店内有设定条件解锁的商店，当#C0xF76B45#满足积分条件时商品将立即永久解锁哦！'
	},
	[101001] = {
		id = 101001,
		fmt = '1.活动期间，回归训练家可找#C0xF76B45#1个资深训练家#C0x5B545B#与Ta进行绑定参与活动，#C0xF76B45#不设解绑'
	},
	[101002] = {
		id = 101002,
		fmt = '2.资深训练家必须达到等级55级、战力15万之后才可被回归训练家进行绑定'
	},
	[101003] = {
		id = 101003,
		fmt = '3.双方训练家绑定后，将开启绑定任务内容，任务分为协同任务与单人任务，#C0xF76B45#针对回归训练家开放所有任务，只有部分协同任务需要资深训练家的参与，因此在资深训练家的活动界面上，仅展示协同任务内容'
	},
	[101004] = {
		id = 101004,
		fmt = '4.每完成一个任务后，#C0xF76B45#双方训练家都会获得任务点数奖励#C0x5B545B#，点数达到一定数值后，可以开启重聚宝箱，#C0xF76B45#即双方宝箱进度是一致的，需要共同努力开启喔！'
	},
	[101005] = {
		id = 101005,
		fmt = '5.双方#C0xF76B45#只可绑定1次参与该活动内容，#C0x5B545B#在重聚活动结束后，资深训练家将进入冷却期，即在一段时间内不可再次参与重聚活动'
	},
	[101006] = {
		id = 101006,
		fmt = '6.本次重聚活动若因回归训练家长期未上线导致活动未完成的，与其绑定的资深训练家，在本次重聚活动结束后，将迎来较短的冷却期'
	},
	[101007] = {
		id = 101007,
		fmt = '7.活动结束后，#C0xF76B45#所有本活动内未领取的奖励，将不设邮件补发，#C0x5B545B#有奖励时记得快快领取喔！'
	},
	[102001] = {
		id = 102001,
		fmt = '#C0xF76B45#【道馆基础规则】'
	},
	[102002] = {
		id = 102002,
		fmt = '1.道馆开放时间：#C0xF76B45#每周一10:00#C0x5B545B#到#C0xF76B45#每周日21:45#C0x5B545B#;其他时间为道馆关闭时间，期间无法进行道馆副本挑战和争夺荣誉馆主。每周一05:00重置所有道馆。'
	},
	[102003] = {
		id = 102003,
		fmt = '2.道馆副本每日有一定成功挑战次数，成功挑战后扣除次数，失败则不扣除次数；每日05:00重置'
	},
	[102004] = {
		id = 102004,
		fmt = '3.每期固定为8个不同的道馆，每个道馆对应5个道馆副本'
	},
	[102005] = {
		id = 102005,
		fmt = '4.道馆副本为一次性副本，不可重复挑战；且道馆怪物的属性和玩家的战力相关，每周重置后自动刷新怪物及其属性'
	},
	[102006] = {
		id = 102006,
		fmt = '5.每个道馆所有难度通关后，可挑战成为对应道馆的荣誉馆主'
	},
	[102007] = {
		id = 102007,
		fmt = '6.每个道馆只有1个荣誉馆主；且每个玩家只能成为一个道馆的荣誉馆主，在成为新的道馆馆主后自动清除在其他道馆的阵容'
	},
	[102008] = {
		id = 102008,
		fmt = '7.荣誉馆主挑战有一定的冷却时限制，成功挑战后需要休息一段时间后才能重新挑战；但没有挑战次数的限制'
	},
	[102009] = {
		id = 102009,
		fmt = '8.馆主挑战需要拥有指定属性的精灵（第一、第二属性只要有任一满足即可），如果没有对应限定属性的精灵，则无法进行挑战'
	},
	[102010] = {
		id = 102010,
		fmt = '#C0xF76B45#【道馆日志说明】'
	},
	[102011] = {
		id = 102011,
		fmt = '1.道馆日志内，只记录#C0xF76B45#和自己相关的所有竞技玩法挑战记录#C0x5B545B#和#C0xF76B45#道馆副本通关记录'
	},
	[102012] = {
		id = 102012,
		fmt = '2.道馆日志的内容只有上一周和本周的记录'
	},
	[102013] = {
		id = 102013,
		fmt = '#C0xF76B45#【挑战加成说明】'
	},
	[102014] = {
		id = 102014,
		fmt = '1.挑战加成内激活的属性仅在道馆副本时生效'
	},
	[102015] = {
		id = 102015,
		fmt = '2.挑战天赋加成通过消耗加成点数激活'
	},
	[102016] = {
		id = 102016,
		fmt = '3.加成点数每日05:00系统会固定增加少量，也可以通过花费钻石来购买，每日购买的次数有限;通关道馆也可以获得加成点数'
	},
	[102017] = {
		id = 102017,
		fmt = '4.每周重置后，加成点数和对应的加成等级会自动清空'
	},
	[102018] = {
		id = 102018,
		fmt = '#C0xF76B45#【馆主奖励预览】'
	},
	[103001] = {
		id = 103001,
		fmt = '1.跨服道馆同样为8个不同的道馆，且每个跨服道馆内可驻守1个跨服馆主和7个跨服馆员'
	},
	[103002] = {
		id = 103002,
		fmt = '2.对应的本服道馆副本所有难度通关后，可挑战成为跨服的荣誉馆主或馆员'
	},
	[103003] = {
		id = 103003,
		fmt = '3.每个玩家只能成为一个跨服道馆的荣誉馆主或者馆员，在成为新的道馆馆主或者馆员后自动清除旧的阵容'
	},
	[103004] = {
		id = 103004,
		fmt = '4.跨服馆主挑战同样有一定的冷却时间，成功挑战后需要休息一段时间后才能重新挑战；但没有挑战次数的限制'
	},
	[103005] = {
		id = 103005,
		fmt = '5.跨服馆主挑战需要拥有指定属性的精灵（第一、第二属性只要有任一满足即可），如果没有对应限定属性的精灵，则无法进行挑战'
	},
	[103006] = {
		id = 103006,
		fmt = '#C0xF76B45#【跨服道馆奖励预览】'
	},
	[104001] = {
		id = 104001,
		fmt = '1.活动时间内，可以进行翻牌玩法获得翻出的道具'
	},
	[104002] = {
		id = 104002,
		fmt = '2.活动设置多轮翻牌，每轮翻牌有一个超级头奖，头奖可能在任何一张牌面之下，翻到之后可以立即获得奖励并且进行下一轮的翻牌游戏'
	},
	[104003] = {
		id = 104003,
		fmt = '3.翻牌会消耗次数，优先消耗免费次数，免费次数每日5点重置；再消耗任务次数，任务次数不重置，可通过完成任务获得'
	},
	[104004] = {
		id = 104004,
		fmt = '4.翻牌的每轮超级头奖内容会在活动页面依次显示，祝你好运！'
	},
	[105001] = {
		id = 105001,
		fmt = '1.在满足条件的情况下，房主可将其他玩家请出房间，其他玩家也可通过投票的方式将房主请出房间'
	},
	[105002] = {
		id = 105002,
		fmt = '2.以上需要满足3个条件：一，房间内至少有3个玩家完成挑战；二，被请出房间的玩家在房间内至少呆满3小时；三，Ta成功挑战次数为0或未挑战'
	},
	[105003] = {
		id = 105003,
		fmt = '3.房主请玩家出房间时，自身需要满足完成至少1次挑战'
	},
	[105004] = {
		id = 105004,
		fmt = '4.其他玩家投票请房主出房间时，自身需要完成3次挑战后有投票资格，并且投票结果满足请Ta走票数多于让Ta留下的票数才可请房主出房间'
	},
	[105005] = {
		id = 105005,
		fmt = '5.挑战重置前累计被请出房间达3次的玩家不可再次参与本次元素挑战，下次挑战开始时可正常进入'
	},
	[106001] = {
		id = 106001,
		fmt = '1.活动时间内，同品质碎片之间可进行转换；成功转换后背包内的碎片会被消耗掉、并获得所选择的碎片。'
	},
	[106002] = {
		id = 106002,
		fmt = '2.每期活动，不同品质碎片可转换的数量独立计算，且都有一定的转换次数上限'
	},
	[106003] = {
		id = 106003,
		fmt = '3.玩家贵族等级提升到一定阶段后，可提升额外的转换次数'
	},
	[106004] = {
		id = 106004,
		fmt = '4.每期活动可转换的碎片会有所区别；如果本期没有你想要转换的碎片，敬请期待下次活动！'
	},
	[107001] = {
		id = 107001,
		fmt = '1.对于单个节日首领而言，每人只能挑战一次'
	},
	[107002] = {
		id = 107002,
		fmt = '2.每个节日副本都有挑战次数上限，达到挑战次数上限后不可再挑战'
	},
	[107003] = {
		id = 107003,
		fmt = '3.自己可以挑战自己发现的节日首领一次，这次挑战次数不累计到他人挑战次数中'
	},
	[107004] = {
		id = 107004,
		fmt = '4.节日副本具有三个难度分级，最高难度为SSS级'
	},
	[107005] = {
		id = 107005,
		fmt = '5.每个节日首领副本有单独的倒计时，倒计时结束时挑战信息即刻消失'
	},
	[107006] = {
		id = 107006,
		fmt = '6.挑战胜利后给予玩家一定的奖励，挑战失败后无奖励且不消耗挑战次数'
	},
	[107007] = {
		id = 107007,
		fmt = '7.每人每天触发的万圣节首领有个数上限和激活冷却'
	},
	[108001] = {
		id = 108001,
		fmt = '1.每日定时开启天降红包小游戏专场，参与小游戏的玩家将获得一张兑奖券，有概率获得超级大奖'
	},
	[108002] = {
		id = 108002,
		fmt = '2.天降红包小游戏专场每天在固定时间开启，请留意活动主界面的显示内容哦，逾时即关闭，也不会获得本场的兑奖券'
	},
	[108003] = {
		id = 108003,
		fmt = '3.天降红包小游戏需要玩家在规定时间内点击屏幕上落下的红包道具，时间截止后，点击了多少将获得多少红包，红包道具可前往背包打开获得奖励'
	},
	[108004] = {
		id = 108004,
		fmt = '4.每场天降红包小游戏会掉落不太一样的红包类内容，请留意活动主界面的显示内容哦'
	},
	[108005] = {
		id = 108005,
		fmt = '5.兑奖券获得后可在奖券入口进行刮奖，兑奖奖励也在该入口里进行公示'
	},
	[108006] = {
		id = 108006,
		fmt = '6.兑奖后，中奖的内容将在本场天降红包小游戏结束时采用邮件陆续进行发放，中奖的玩家请留意邮件内容'
	},
	[108007] = {
		id = 108007,
		fmt = '7.若玩家获得兑奖券后，未来得及在本场天降红包小游戏结束时间前兑奖，则系统会自动进行刮奖与兑奖，并按时将获奖邮件发放至邮箱'
	},
	[109001] = {
		id = 109001,
		fmt = '1.活动是一个堆雪人的小游戏，雪人有等级，随着等级的提高会解锁装饰，以及雪人的部位装扮'
	},
	[109002] = {
		id = 109002,
		fmt = '2.收集活动限定的雪花道具，可用在堆砌皮卡丘雪人上，每消耗1个道具堆砌，即可获得1次随机奖励内容，同时皮卡丘会提升等级'
	},
	[109003] = {
		id = 109003,
		fmt = '3.皮卡丘的等级提升后，将解锁身上部位的一些圣诞节装饰，解锁的部位可以随意更换心仪颜色的装饰，同时会固定解锁一些圣诞节气氛的环境装饰'
	},
	[109004] = {
		id = 109004,
		fmt = '4.皮卡丘的等级设定有上限，当等级达到上限后，就代表所有的装饰物与装扮将全部展示与开放，但此时仍可以对其消耗雪花道具，每次消耗同样获得奖励'
	},
	[110001] = {
		id = 110001,
		fmt = '1.小游戏提供3个生命值、移动速度与体型都各不相同的精灵供选择，每次开始游戏前可以自由选择自己擅长的精灵进入游戏'
	},
	[110002] = {
		id = 110002,
		fmt = '2.游戏开始后，会从天而降雪球与礼盒，被雪球砸1次会掉1点生命，捡到礼盒可得分，游戏时间结束或被雪球砸至生命值为0时，游戏结束'
	},
	[110003] = {
		id = 110003,
		fmt = '3.#C0xF76B45#雪球下落极快，注意脚下阴影；礼盒落地后一会就会消失，需要尽快捡起，捡起可获得积分；精灵在场上存活时间越长，还可获得越多的积分加成哦'
	},
	[110004] = {
		id = 110004,
		fmt = '4.每日小游戏免费开放次数进入，也可以花费钻石购买游戏次数'
	},
	[110005] = {
		id = 110005,
		fmt = '5.小游戏设有排行榜，你的单局获得积分的最高记录将被进行排行展示'
	},
	[110006] = {
		id = 110006,
		fmt = '6.小游戏每局获得的积分将会被累加记录，达到一定的积分后可以领取相应奖励内容'
	},
	[111001] = {
		id = 111001,
		fmt = '1.培养徽章可提升所有精灵的属性，快去挑战道馆获取培养材料吧！'
	},
	[111002] = {
		id = 111002,
		fmt = '2.徽章的数量和道馆一致，默认开放4个；徽章精神点亮到一定等级后可解锁新的一种徽章'
	},
	[111003] = {
		id = 111003,
		fmt = '3.每块徽章都需要设置守护精灵，根据守护精灵的养成情况可提供额外的徽章属性加成'
	},
	[111004] = {
		id = 111004,
		fmt = '4.徽章觉醒至更高阶段后，可激活更多新的精灵守护位'
	},
	[112001] = {
		id = 112001,
		fmt = '#C0xF76B45##L10#【基本规则】'
	},
	[112002] = {
		id = 112002,
		fmt = '1.精灵问答开放时间：#C0xF76B45#周六5:00#C0x5B545B#到#C0xF76B45#周日24:00#C0x5B545B#；每两周开启一次。'
	},
	[112003] = {
		id = 112003,
		fmt = '2.精灵问答开放后，有1次免费进入答题的机会，进入答题即扣除次数#C0xF76B45#（中途退出也算作使用一次机会）#C0x5B545B#；次日05:00重置'
	},
	[112004] = {
		id = 112004,
		fmt = '3.每日消耗钻石额外获得1次答题机会，但两次积分只能取较高的一次计入排行榜。'
	},
	[112005] = {
		id = 112005,
		fmt = '4.周六日的成绩都会显示在排名中，公会成员可看到自己和所在公会的排名。'
	},
	[112006] = {
		id = 112006,
		fmt = '#C0xF76B45##L10#【答题规则】'
	},
	[112007] = {
		id = 112007,
		fmt = '1.整体问答共有15道题，回答错误或不回答为0积分；回答正确则可以获得一定的相应积分，回答的用时越少且正确、则获得的积分会更高'
	},
	[112008] = {
		id = 112008,
		fmt = '2.每道题有15秒的作答时间，倒计时结束或玩家提前确认答案后，则自动进入下一题'
	},
	[112009] = {
		id = 112009,
		fmt = '3.题目分为文字题，图片题，小游戏题；初次遇到小游戏时，会有相关的规则说明。'
	},
	[112010] = {
		id = 112010,
		fmt = '4.积分将作为排行榜排名的依据，公会排行是公会内所有玩家积分的总和进行排名(玩家退出公会后，已获得积分仍会暂时记录在旧公会内，#C0xF76B45#新成员加入后若超出公会人数上限，则按照退会的先后顺序清空退会玩家成绩#C0x5B545B#)。'
	},
	[112011] = {
		id = 112011,
		fmt = '#C0xF76B45##L10#【答题奖励规则】'
	},
	[112012] = {
		id = 112012,
		fmt = '答题者每回答正确一道题，都会获得一个奖励背包，最多可获得15个，等到答题结束后统一开启。'
	},
	[112013] = {
		id = 112013,
		fmt = '#C0xF76B45##L10#【公会排名奖励规则】'
	},
	[112101] = {
		id = 112101,
		fmt = '#C0xF76B45##L10#【个人排名奖励规则】'
	},
	[113001] = {
		id = 113001,
		fmt = '1.跨服商业街需要等待服务器间匹配，当匹配成功后，会在界面展示#C0xF76B45#匹配成功等待开赛状态#C0x5B545B#'
	},
	[113002] = {
		id = 113002,
		fmt = '2.赛季流程：#C0xF76B45#赛季预告（持续1日）——赛季开赛（隔日10:00，持续3天）—赛季结算展示（结束当日22：00至下次开赛前一天）'
	},
	[113003] = {
		id = 113003,
		fmt = '3.赛季中的#C0xF76B45#每日22:00以及赛季结束当日22:00#C0x5B545B#将根据排名将发放个人奖励，#C0xF76B45#赛季结束当日22:00#C0x5B545B#还将结算服务器奖励，#C0xF76B45#所有内容均通过邮件领取'
	},
	[113004] = {
		id = 113004,
		fmt = '4.赛季中，#C0xF76B45#竞标行为只可在每天10:00-22:00进行，其余时间为休战期，休战期间商铺打烊，不可进行竞标、复仇等战斗行为'
	},
	[113005] = {
		id = 113005,
		fmt = '5.玩家有免费的竞标次数，刷新竞标玩家次数，以及复仇次数，超过次数可以使用钻石或金币购买'
	},
	[113006] = {
		id = 113006,
		fmt = '6.商业街区根据排名划分为#C0xF76B45#高级商业区与普通商业区#C0x5B545B#，排名在1-10的将被划分在高级商业区内，其他则在普通街区内进行显示'
	},
	[113007] = {
		id = 113007,
		fmt = '8.在对战情报内，可提供查看最近一段时间内高段位玩家之间的对战视频'
	},
	[113008] = {
		id = 113008,
		fmt = '9.赛季中#C0xF76B45#每日以及季终的22:00结算时#C0x5B545B#将根据结算排名发放称号，称号分别将由#C0xF76B45#排行榜前三名的玩家#C0x5B545B#获得，赛季中#C0xF76B45#每日结算获得的称号有效期将截止至下次每日结算，季终结算获得的称号有效期将截止至下个赛季准备匹配的时候'
	},
	[113020] = {
		id = 113020,
		fmt = '1.排名有对应的资源币生产速度与加成积分，占用该排名后，#C0xF76B45#资源币将按照现有生产速度产出，且将拥有本排名的加成积分，更换排名后，将直接替换生产速度与加成积分，并非叠加计算'
	},
	[113021] = {
		id = 113021,
		fmt = '2.资源币按照配排名所在的速度全天产出，包括非休战时期，与玩家竞标可以获得其部分的资源币，#C0xF76B45#可用于商店道具购买与祝福中属性培养'
	},
	[113022] = {
		id = 113022,
		fmt = '3.积分靠排名内更迭，以及限时首领战中的战斗与击杀奖励产出，#C0xF76B45#积分用于赛季结算时，#C0x5B545B#取每个服务器前100名的玩家的总积分值高低进行排序'
	},
	[113040] = {
		id = 113040,
		fmt = '1.对战前，玩家可以#C0xF76B45#布阵3支队伍，每支队伍最多可上阵4个精灵'
	},
	[113041] = {
		id = 113041,
		fmt = '2.战斗实行每队对战计分模式，#C0xF76B45#3局2胜为最终胜利，最多3轮战斗，上一轮的战斗结束后将不影响下一轮'
	},
	[113042] = {
		id = 113042,
		fmt = '3.一方2队的精灵全战败则判失败，若小队战斗的回合结束未分胜负的，则#C0xF76B45#判防守方的小队本回合胜利'
	},
	[113043] = {
		id = 113043,
		fmt = '4.跨服商业街的战斗方式为#C0xF76B45#锁定自动战斗#C0x5B545B#'
	},
	[113044] = {
		id = 113044,
		fmt = '5.对方主动挑战玩家时，将派出玩家的防守阵容迎战'
	},
	[113080] = {
		id = 113080,
		fmt = '1.玩家可在搜寻出的10个对手中选择1个竞标，若#C0xF76B45#战斗胜利，则与高于自己排名的玩家交换位置，并继承新排名的生产速度与加成积分，以及部分对手的资源币；若与低排名对手对战，则不交换排名及相关内容，可获得部分对手的资源币'
	},
	[113081] = {
		id = 113081,
		fmt = '2.对方发起战斗且战斗成功时，可以进行复仇，#C0xF76B45#对同一个目标的复仇有次数上限，复仇也可获得部分目标的资源币，但是不互换排名，且可以触发目标对自己的复仇'
	},
	[113082] = {
		id = 113082,
		fmt = '3.当出现以下情况时，竞标或复仇目标即使成功也无法获取资源币：'
	},
	[113083] = {
		id = 113083,
		fmt = '#C0xF76B45#①达到1小时内被竞标次数上限时，最后1次被战斗离当前时间大于1小时解除该状态'
	},
	[113084] = {
		id = 113084,
		fmt = '#C0xF76B45#②双方的战力值达到一定比例的战力差时'
	},
	[113085] = {
		id = 113085,
		fmt = '#C0xF76B45#③双方是同一个服务器的玩家时'
	},
	[113086] = {
		id = 113086,
		fmt = '#C0xF76B45#④达到每日被竞标的次数上限时'
	},
	[113087] = {
		id = 113087,
		fmt = '4.被竞标（抢走资源币）或复仇成功后的目标将会获得#C0xF76B45#5分钟的竞标保护，5分钟内不会再受到战斗'
	},
	[113100] = {
		id = 113100,
		fmt = '9.商业街-#C0xF76B45#娱乐城闪亮开幕！#C0x5B545B#它有特殊的运营模式，因此#C0xF76B45#每天开放时间段不固定，#C0x5B545B#可以去#C0xF76B45#商业街里问问#C0x5B545B#其他的训练家'
	},
	[113101] = {
		id = 113101,
		fmt = '10.娱乐城#C0xF76B45#仅在赛季开启期间营业，#C0x5B545B#赛季截止后，娱乐城也将长期关闭等待下次赛季到来'
	},
	[113102] = {
		id = 113102,
		fmt = '11.在娱乐城里可以与魔墙人偶玩幸运数字21 的小游戏，#C0xF76B45#每天限定游戏次数，#C0x5B545B#次数每日重置不进行保留'
	},
	[113103] = {
		id = 113103,
		fmt = '12.小游戏只要获得胜利，即可获得胜利的游戏奖励，若失败则不获得道具奖励'
	},
	[114001] = {
		id = 114001,
		fmt = '1.玩法持续时间内，会在普通商业区刷新可挑战的火箭队首领'
	},
	[114002] = {
		id = 114002,
		fmt = '2.首领刷新时间分别在中午12点30和晚上18点30，每个时间段刷新的首领难度不同'
	},
	[114003] = {
		id = 114003,
		fmt = '3.每个玩家拥有一定挑战首领的免费次数，也可以额外购买次数'
	},
	[114004] = {
		id = 114004,
		fmt = '4.玩家每次挑战完成后扣除首领对应的血量同时获得随机奖励，最后的击杀者可获得额外的击杀奖励，首领被击杀后按照造成伤害的高低发放排名奖励'
	},
	[114005] = {
		id = 114005,
		fmt = '5.击杀首领的玩家所在得服务器会获得额外加成，分别有属性增强，产出增加，抢夺增加三种效果中的一种'
	},
	[114006] = {
		id = 114006,
		fmt = '6.晚上的首领会格外强大，首领被击杀后击杀者所在服务器玩家获得的加成也会格外给力'
	},
	[115001] = {
		id = 115001,
		fmt = '1.新年限定集福活动上线！活动时间内，完成任务可得海量好礼！'
	},
	[115002] = {
		id = 115002,
		fmt = '2.活动期间，共有16个任务累计进度，每个任务都有号码，号码对应右边的拼图号码'
	},
	[115003] = {
		id = 115003,
		fmt = '3.每完成对应号码的任务，可以获得任务奖励，同时对应牌面将被翻开'
	},
	[115004] = {
		id = 115004,
		fmt = '4.拼图的右边、下方对应展示8个福袋礼物，完成对应直线号牌的任务，翻开牌面的可以获得福袋奖励'
	},
	[115005] = {
		id = 115005,
		fmt = '5.16张拼图号码全部翻开后，可获得超大福袋奖励哦！'
	},
	[116001] = {
		id = 116001,
		fmt = '1.活动时间内，每天限定次数可进入摩天高楼搭建小游戏进行游玩'
	},
	[116002] = {
		id = 116002,
		fmt = '2.小游戏要求在一定的操作时间内，#C0xF76B45#尽量使搭建的楼层完美搭建，以完成高楼的建设，每局游戏有3次搭建机会，要好好使用'
	},
	[116003] = {
		id = 116003,
		fmt = '3.搭建过程中，会#C0xF76B45#随机出现搭建奖励，只要能成功搭建本楼层，即可获得该奖励，#C0x5B545B#奖励会在最后的游戏结算里进行统计展示'
	},
	[116004] = {
		id = 116004,
		fmt = '4.搭建还有搭建评分考量，#C0xF76B45#楼层越高，搭建越完美，评分则会越高哦'
	},
	[116005] = {
		id = 116005,
		fmt = '5.每局摩天高楼小游戏的评分、搭建层数、完美搭建出现次数将被累计记录在勋章任务内，#C0xF76B45#完成对应任务可获得任务奖励与勋章积分，升级勋章还将获得升级奖励哦'
	},
	[116006] = {
		id = 116006,
		fmt = '6.排行榜将展示多个服务器内玩家们的成绩，根据搭建评分与搭建层数进行排名展示'
	},
	[117001] = {
		id = 117001,
		fmt = '1.完成日常任务可获取活跃度，累计的活跃度越高，解锁的战令奖励越丰厚'
	},
	[117002] = {
		id = 117002,
		fmt = '2.购买豪华版战令，可以解锁更多额外的超值奖励'
	},
	[117003] = {
		id = 117003,
		fmt = '3.每期购买的豪华版战令仅在本期活动内生效，下次活动需要重新购买；累计的活跃度也会在活动结束时清零'
	},
	[117004] = {
		id = 117004,
		fmt = '4.战令活动结束时，所有未领取的奖励将通过邮件发送'
	},
	[118001] = {
		id = 118001,
		fmt = '1.每天通过以太乐园，累计通过层数(每层最终首领挑战结束才可累计层数)，可解锁丰厚的通行证奖励'
	},
	[118002] = {
		id = 118002,
		fmt = '2.购买豪华版通行证，可以解锁更多额外的超值奖励'
	},
	[118003] = {
		id = 118003,
		fmt = '3.每期购买的豪华版通行证仅在本期活动内生效，下次活动需要重新购买；累计的通过层数也会在活动结束时清零'
	},
	[118004] = {
		id = 118004,
		fmt = '4.通行证活动结束时，所有未领取的奖励将通过邮件发送'
	},
	[119001] = {
		id = 119001,
		fmt = '#C0xFF5B545B#1.每周成功挑战道馆副本，可累计挑战次数(#C0xF76B45#挑战道馆玩家不计次数#C0xFF5B545B#)；累计的挑战次数越多，解锁的通行证奖励越丰厚'
	},
	[119002] = {
		id = 119002,
		fmt = '2.购买豪华版通行证，可以解锁更多额外的超值奖励'
	},
	[119003] = {
		id = 119003,
		fmt = '3.每期购买的豪华版通行证仅在本期活动内生效，下次活动需要重新购买；累计的副本挑战次数也会在活动结束时清零'
	},
	[119004] = {
		id = 119004,
		fmt = '4.通行证活动结束时，所有未领取的奖励将通过邮件发送'
	},
	[120001] = {
		id = 120001,
		fmt = '1.投掷骰子进行移动，地图上有宝箱，#C0xF76B45#它奖励丰富且在获得之后会随机在地图上再次显示，把追逐宝箱作为你的目标吧！'
	},
	[120002] = {
		id = 120002,
		fmt = '2.在地图上行进时，还会遇到其他的事件格子，在地图界面上#C0xF76B45#点击事件格子可以查看具体说明'
	},
	[120003] = {
		id = 120003,
		fmt = '3.事件格子中，#C0xF76B45#小店和宝箱只要途径便会触发事件，#C0x5B545B#事件结束之后，小智若还可移动，则再接着向前移动；#C0xF76B45#其他的事件格子则需要停驻才会触发'
	},
	[120004] = {
		id = 120004,
		fmt = '4.在大冒险中，你可以获得#C0xF76B45#探险者勋章，#C0x5B545B#它可以让你在#C0xF76B45#途径小店时进行道具购买，注意，它只可以用来购买大冒险中可以使用的道具'
	},
	[120005] = {
		id = 120005,
		fmt = '5.冒险途中，会获得一些各有特色的道具卡和骰子，如果不知道他们的用处，#C0xF76B45#可以查看下方的道具说明'
	},
	[121001] = {
		id = 121001,
		fmt = '#L10##C0xF76B45#"总是当时携手处，今年花胜去年红"。#C0xFF5B545B#——来自世界各地的训练家们带着他们的精灵，开始了一年一度的精灵赛跑季。'
	},
	[121002] = {
		id = 121002,
		fmt = '整个精灵赛跑季包括：有奖竞猜、赛前准备、比赛进行中、结果公布等四个阶段。'
	},
	[121003] = {
		id = 121003,
		fmt = '#L10##C0xF76B45#【有奖竞猜】:'
	},
	[121004] = {
		id = 121004,
		fmt = '1.活动开启期间，精灵赛跑季每天两轮比赛(12:00和20:00点)，每场比赛会随机选取4名精灵进行赛跑比试。'
	},
	[121005] = {
		id = 121005,
		fmt = '2.训练家们虽然不能和精灵一同参与训练，但是可以在比赛开始前进行有奖竞猜；竞猜结果会在比赛结束时发布。'
	},
	[121006] = {
		id = 121006,
		fmt = '3.有奖竞猜的时间分别为: 每日05:00~11:57和13:00~19:57;且其他时间段内是无法进行竞猜的。'
	},
	[121007] = {
		id = 121007,
		fmt = '4.竞猜下注需要消耗一定的钻石，且每次竞猜最多只能选择一名精灵进行下注。'
	},
	[121008] = {
		id = 121008,
		fmt = '#L10##C0xF76B45#【赛前准备】'
	},
	[121009] = {
		id = 121009,
		fmt = '1.比赛准备阶段，需要耗时3分钟，期间有奖竞猜将会被关闭。'
	},
	[121010] = {
		id = 121010,
		fmt = '#L10##C0xF76B45#【比赛进行中】:'
	},
	[121011] = {
		id = 121011,
		fmt = '1.每日12:00和20:00准时开始比赛，整个过程将持续3分种。'
	},
	[121012] = {
		id = 121012,
		fmt = '2.不同精灵选手的身体指标会有所不同，速度和冲刺概率将是两项比较重要的指标。'
	},
	[121013] = {
		id = 121013,
		fmt = '3.各项指标说明：'
	},
	[121014] = {
		id = 121014,
		fmt = 'a.速度，精灵的初始赛跑速度'
	},
	[121015] = {
		id = 121015,
		fmt = 'b.体力，精灵在比赛过程中会持续消耗体力，体力不足时，会进入虚弱状态（虚弱状态下速度将会受影响有所下降);体力恢复至充足时，虚弱状态将会消失。'
	},
	[121016] = {
		id = 121016,
		fmt = 'c.冲刺概率，精灵在比赛过程中每隔一段时间将有一定概率进行冲刺，实时速度会提高相应的倍数'
	},
	[121017] = {
		id = 121017,
		fmt = 'd.冲刺持续时间，精灵触发冲刺时所持续的时间'
	},
	[121018] = {
		id = 121018,
		fmt = '#L10##C0xF76B45#【结果公布】:'
	},
	[121019] = {
		id = 121019,
		fmt = '1.比赛将会在所有精灵在到达终点时结束。'
	},
	[121020] = {
		id = 121020,
		fmt = '2.比赛结束时，训练家们可以在【历史比赛】中领取竞猜奖励(没有竞猜过的训练师将没有任何奖励)，也可以回放比赛过程。'
	},
	[121021] = {
		id = 121021,
		fmt = '3.竞猜奖励包括两部分：竞猜积分、道具奖励；累计一定的竞猜积分，可以在【积分奖励】中领取相应的阶段性奖励。'
	},
	[121022] = {
		id = 121022,
		fmt = '#L10#4.竞猜奖励预览：'
	},
	[122001] = {
		id = 122001,
		fmt = '#C0xF76B45#【基础规则】'
	},
	[122002] = {
		id = 122002,
		fmt = '1.活动期间内，每天恢复3次挑战次数，次数恢复时间为凌晨5点，次数累计上限为10次'
	},
	[122003] = {
		id = 122003,
		fmt = '2.宝可梦挑战开始，可任选三只精灵作为首发精灵'
	},
	[122004] = {
		id = 122004,
		fmt = '3.特殊首发精灵有特殊解锁条件，需要解锁后才能使用'
	},
	[122005] = {
		id = 122005,
		fmt = '4.挑战关卡前可根据敌方信息进行调整上阵精灵'
	},
	[122006] = {
		id = 122006,
		fmt = '5.每场战斗胜利后可以从三个可选勋章中任选一个'
	},
	[122007] = {
		id = 122007,
		fmt = '6.连续使用3次相同的首发精灵阵容进行挑战可开局获得勋章奖励；每日首次挑战也会有额外勋章奖励，不要错过'
	},
	[122008] = {
		id = 122008,
		fmt = '7.勋章对战斗起到决定性的作用，所以要谨慎选择'
	},
	[122009] = {
		id = 122009,
		fmt = '8.打败最终的首领即完成本轮次的通关，记录通关次数和回合'
	},
	[122010] = {
		id = 122010,
		fmt = '9.活动期间，挑战进度会保存，完成通关或挑战失败会重置流程'
	},
	[122011] = {
		id = 122011,
		fmt = '10.活动期间，消耗次数，可重复挑战，完成成就，实现新的突破'
	},
	[122012] = {
		id = 122012,
		fmt = '#C0xF76B45#【战斗规则】'
	},
	[122013] = {
		id = 122013,
		fmt = '1.战斗结束会保留己方全部精灵血量和首发精灵的怒气，中途招募的精灵每次参战都为固定怒气'
	},
	[122014] = {
		id = 122014,
		fmt = '2.战斗过程中精灵阵亡，则不可再上阵'
	},
	[122015] = {
		id = 122015,
		fmt = '3.战斗胜利后的关卡不可重复挑战'
	},
	[122016] = {
		id = 122016,
		fmt = '#C0xF76B45#【奖励规则】'
	},
	[122017] = {
		id = 122017,
		fmt = '1.#C0xF76B45#活动结束，所有成就奖励不补发，请务必在活动结束前领取#C0x5B545B#'
	},
	[122018] = {
		id = 122018,
		fmt = '2.首次通关时，可获得首次通关奖励，通关后，重复挑战可获得挑战奖励'
	},
	[122019] = {
		id = 122019,
		fmt = '3.活动持续期间，副本挑战获得的金币上限为#Icommon/icon/icon_gold.png-56-56#8000000'
	},
	[123001] = {
		id = 123001,
		fmt = '#L10##C0xF76B45#【礼包规则】'
	},
	[123002] = {
		id = 123002,
		fmt = '1.根据礼包出现前训练家的自身情况，来定制专属礼包'
	},
	[123003] = {
		id = 123003,
		fmt = '2.礼包限时出售，训练家们不要错失良机'
	},
	[123004] = {
		id = 123004,
		fmt = '3.礼包是一次性投放，不会再有新的礼包加入到尊享限定'
	},
	[123005] = {
		id = 123005,
		fmt = '4.训练家在后续提升的自身实力，会在下次尊享开启时再为您定制更优质的礼包，敬请期待'
	},
	[124001] = {
		id = 124001,
		fmt = '#C0xF76B45#【基础规则】'
	},
	[124002] = {
		id = 124002,
		fmt = '1.Z觉醒培养可提升精灵的属性'
	},
	[124003] = {
		id = 124003,
		fmt = '2.Z觉醒一定阶段将会对精灵的技能进行二次觉醒强化'
	},
	[124004] = {
		id = 124004,
		fmt = '3.同进化系列（不包括超进化）精灵的Z觉醒培养共享'
	},
	[124005] = {
		id = 124005,
		fmt = '4.精灵进行z觉醒培养后，可提升觉醒之力的等级，获得更多额外全队属性加成'
	},
	[124006] = {
		id = 124006,
		fmt = '5.超进化后，旧的精灵Z觉醒培养会被自动重置，超进化后的精灵需要重新升级Z觉醒'
	},
	[124007] = {
		id = 124007,
		fmt = '6.Z觉醒碎片为一种新的碎片类型，不能合成完整精灵'
	},
	[124008] = {
		id = 124008,
		fmt = '7.不同进化系列的精灵，Z觉醒碎片不同'
	},
	[124009] = {
		id = 124009,
		fmt = '8.Z觉醒碎片可用于精灵的Z觉醒培养，极限属性培养，超进化的材料使用'
	},
	[124010] = {
		id = 124010,
		fmt = '9.Z觉醒重置说明：'
	},
	[124011] = {
		id = 124011,
		fmt = '①重置将返还100%养成资源，返还资源中兑换的Z觉醒碎片仍旧为Z觉醒碎片，不会变为精灵或精灵碎片'
	},
	[124012] = {
		id = 124012,
		fmt = '②已消耗的精灵或精灵碎片则将统一换算返还为Z觉醒碎片'
	},
	[124101] = {
		id = 124101,
		fmt = '#C0xF76B45#【觉醒之力说明】'
	},
	[124102] = {
		id = 124102,
		fmt = '1.觉醒之力等级的经验值来自于所有精灵系列的Z觉醒培养'
	},
	[124103] = {
		id = 124103,
		fmt = '2.每激活一条Z觉醒培养都可获得一定的经验值'
	},
	[124104] = {
		id = 124104,
		fmt = '3.经验值满足时，觉醒之力等级会自动提升'
	},
	[124105] = {
		id = 124105,
		fmt = '4.若精灵的Z觉醒被重置，觉醒之力会降低对应的经验值'
	},
	[124106] = {
		id = 124106,
		fmt = '5.觉醒之力失去经验值之后，等级和对应的加成效果也会失效'
	},
	[124201] = {
		id = 124201,
		fmt = '1.活动期间，根据委托指派精灵执行，执行完成后可获得丰富奖励！'
	},
	[124202] = {
		id = 124202,
		fmt = '2.执行委托需要派遣符合委托要求的精灵，扣除行动点，并耗费一定时长，若#C0xF76B45#满足委托的加分要求，则可收获额外惊喜！'
	},
	[124203] = {
		id = 124203,
		fmt = '3.委托分为主线与支线，在地图中有序排列，需要#C0xF76B45#先完成前置委托后，才可进行下一个委托'
	},
	[124204] = {
		id = 124204,
		fmt = '4.支线上的委托有#C0xF76B45#可进行多次的，#C0x5B545B#也有#C0xF76B45#宝箱奖励，#C0x5B545B#前者#C0xF76B45#可获得不菲奖励，#C0x5B545B#后者则#C0xF76B45#无需耗时即获得奖励，千万不要错过它们！'
	},
	[124205] = {
		id = 124205,
		fmt = '5.地图上展示的所有委托（包括宝箱），在没有完成的状态下，均可以点击进行查看'
	},
	[124206] = {
		id = 124206,
		fmt = '6.委托需要手动委派精灵，委托完成后记得要#C0xF76B45#亲自收取奖励。#C0x5B545B#同时#C0xF76B45#可执行（包括已完成未领取奖励的委托）3个#C0x5B545B#委托，请妥善安排'
	},
	[124207] = {
		id = 124207,
		fmt = '7.在委托进行中时，支持中途放弃任务，放弃任务后，任务计时归零，归还行动点，且不获得委托奖励。'
	},
	[124301] = {
		id = 124301,
		fmt = '1.欢迎来到狩猎地带，据说狩猎最好的方式就是将自己成为猎物'
	},
	[124302] = {
		id = 124302,
		fmt = '2.在狩猎地带中，战斗胜利获得的增益效果、适当选择治疗补给都有助于通关'
	},
	[124303] = {
		id = 124303,
		fmt = '3.狩猎地带分为普通和进阶两个线路等待探索，两条路线的内容、进度、增益效果等互相独立，互不影响'
	},
	[124304] = {
		id = 124304,
		fmt = '4.普通路线每48小时恢复1次挑战次数，进阶路线每96小时恢复1次挑战次数；次数恢复时间为凌晨5点，次数累计上限为5次'
	},
	[124305] = {
		id = 124305,
		fmt = '5.每条路线开启后直到对应线路的次数恢复节点都可保存该线路的挑战状态，系统将在对应线路的次数恢复节点重置该路线内容'
	},
	[124306] = {
		id = 124306,
		fmt = '6.挑战过程中或通关后，可选择手动结束挑战或等待系统自动重置路线内容'
	},
	[124307] = {
		id = 124307,
		fmt = '7.当玩家达到一定等级后开启碾压，根据历史最高战绩和上次最高表现，可以碾压一定层数以下的战斗，碾压后可以无伤过关并获得全部奖励'
	},
	[124401] = {
		id = 124401,
		fmt = '#F40##L10#洗练说明：'
	},
	[124402] = {
		id = 124402,
		fmt = '#F36#1.每个芯片最多只能选择2条属性进行洗练'
	},
	[124403] = {
		id = 124403,
		fmt = '#F36#2.选定洗练的属性条目洗练后，选定的洗练条目将被锁定，将无法再取消或者更换洗练目标，此操作不可逆，请谨慎选择洗练条目后再洗练'
	},
	[124404] = {
		id = 124404,
		fmt = '#F36#3.洗练时，会同时重置随机所选择洗练的属性类型以及所有随机属性的属性值与强化次数'
	},
	[124501] = {
		id = 124501,
		fmt = '1.在学习芯片重生内，可将自己培养过的学习芯片重置至初始1级状态'
	},
	[124502] = {
		id = 124502,
		fmt = '2.学习芯片重生后，返还100%的等级养成资源，可以利用这些资源重新培养其他学习芯片'
	},
	[124503] = {
		id = 124503,
		fmt = '3.学习芯片重生后，再强化到原始等级时，其属性条目和强化次数不会变化，即重生只能返还资源，不会重新随机属性'
	},
	[124504] = {
		id = 124504,
		fmt = '4.学习芯片重生需要消耗钻石，重生的学习芯片培养程度越高需要的钻石会更多；单个学习芯片重生钻石消耗上限为100#Icommon/icon/icon_diamond.png-56-56#'
	},
	[124505] = {
		id = 124505,
		fmt = '5.未培养过的学习芯片无法进行重生，也不会出现在重生可选学习芯片的界面内'
	},
	[124601] = {
		id = 124601,
		fmt = '1.穿着芯片可以增加精灵的战斗能力'
	},
	[124602] = {
		id = 124602,
		fmt = '2.每个芯片拥有1~2条固定属性和若干条随机属性'
	},
	[124603] = {
		id = 124603,
		fmt = '3.芯片有对应的套装属性，穿2/4件同一套装属性的芯片能够激活其对应的套装属性，芯片品质越高，套装属性越好'
	},
	[124604] = {
		id = 124604,
		fmt = '4.每个芯片只能装配到其指定的位置中'
	},
	[124605] = {
