	},
	[124802] = {
		id = 124802,
		fmt = '#L10##C0xF76B45#【活动规则】:'
	},
	[124803] = {
		id = 124803,
		fmt = '1.活动开启后，训练家们会为宝可梦们制作刨冰，消除炎热'
	},
	[124804] = {
		id = 124804,
		fmt = '2.宝可梦们在上场后会提出自己喜欢的刨冰口味，训练家们需要在进度条结束前记忆需求'
	},
	[124805] = {
		id = 124805,
		fmt = '3.进度条结束后，精灵会隐藏起自己提出的需求，需要玩家凭记忆选出精灵提出的需求'
	},
	[124806] = {
		id = 124806,
		fmt = '4.第一只精灵提出需求后，需要点击【开始制作】来开启冰箱，为精灵制作刨冰'
	},
	[124807] = {
		id = 124807,
		fmt = '5.选择完毕后，精灵会对训练家的选择做出服务评价，判定分三个等级'
	},
	[124808] = {
		id = 124808,
		fmt = '#C0xF76B45#完美服务：#C0x5B545B#没有错误且顺序无误'
	},
	[124809] = {
		id = 124809,
		fmt = '#C0xF76B45#良好服务：#C0x5B545B#没有错误但顺序有误'
	},
	[124810] = {
		id = 124810,
		fmt = '#C0xF76B45#瑕疵服务：#C0x5B545B#有错选的需求'
	},
	[124811] = {
		id = 124811,
		fmt = '6.服务后会有服务评价展示，#C0xF76B45#但注意下一位顾客很快会上场提需求，不要错过记忆时间哦#C0x5B545B#'
	},
	[124812] = {
		id = 124812,
		fmt = '7.随着服务轮数的提高，精灵提出的需求可能也会变多'
	},
	[124813] = {
		id = 124813,
		fmt = '8.总倒计时结束后停止营业，会根据训练家的服务状态结算最后的奖励物品'
	},
	[124901] = {
		id = 124901,
		fmt = '#L10##C0xF76B45#"沙滩上灵动的影子，精灵们的沙滩排球开始啦！"'
	},
	[124902] = {
		id = 124902,
		fmt = '#L10##C0xF76B45#【活动规则】:'
	},
	[124903] = {
		id = 124903,
		fmt = '1.活动开启后，玩家可以在沙滩上畅玩排球，每日没有次数限制'
	},
	[124904] = {
		id = 124904,
		fmt = '2.进入游戏后，玩家需要选择三种属性的其中一种作为使用精灵的优势属性'
	},
	[124905] = {
		id = 124905,
		fmt = '3.选择后会为您派遣对应的精灵出战！'
	},
	[124906] = {
		id = 124906,
		fmt = '4.场地默认左边是己方场地，右边是对手场地'
	},
	[124907] = {
		id = 124907,
		fmt = '5.玩家可以左右移动精灵，精灵们会用头回击对方打来的球，玩家还可以用下面三种方式秀操作\n'
	},
	[124908] = {
		id = 124908,
		fmt = '6.球打回到对方界内，但对方没接到时，就可以获得1分'
	},
	[124909] = {
		id = 124909,
		fmt = '7.如果打到对方界外，或者因为失误自己打出界外，会让对手获得1分'
	},
	[124910] = {
		id = 124910,
		fmt = '8.优先获得3分的一方为胜利方'
	},
	[124911] = {
		id = 124911,
		fmt = '9.完成对应任务可以获得丰厚的奖励'
	},
	[125001] = {
		id = 125001,
		fmt = '#L10##C0xF76B45#"欢迎来到夏日探险"'
	},
	[125002] = {
		id = 125002,
		fmt = '#C0xF76B45#传说在湖中神殿里，居住着世界上最美的宝可梦……#C0x5B545B#'
	},
	[125003] = {
		id = 125003,
		fmt = '#C0xF76B45#基础说明：#C0x5B545B#'
	},
	[125004] = {
		id = 125004,
		fmt = '1.每日开启固定数量的副本，副本未通关前可重复尝试挑战'
	},
	[125005] = {
		id = 125005,
		fmt = '2.副本首次通关后不可重复挑战，通关上一关才能开启下一关的挑战'
	},
	[125006] = {
		id = 125006,
		fmt = '3.副本内的对话隐藏着通关技巧，通关后信息界面可查看剧情回顾'
	},
	[125007] = {
		id = 125007,
		fmt = '#C0xF76B45#通关技巧：#C0x5B545B#留意剧情对话内容'
	},
	[125008] = {
		id = 125008,
		fmt = '#C0xF76B45#副本奖励：#C0x5B545B#通关获得首通奖励'
	},
	[125101] = {
		id = 125101,
		fmt = '#C0x5E565D#*全属性加成需要精灵背包内同系列精灵培养至一定的星级后自动生效'
	},
	[125102] = {
		id = 125102,
		fmt = '#C0x5E565D#*全属性加成只在该玩法中生效'
	},
	[125201] = {
		id = 125201,
		fmt = '1.欢迎来到属于你的小屋，在如画一般的家园里拥有属于自己的小屋子和一大片庭院，感觉还挺不错的吧？'
	},
	[125202] = {
		id = 125202,
		fmt = '2.小屋简直是太大了，所以需要一步步进行#C0xF76B45#区域#C0x5B545B#的解锁哦，点击#C0xF76B45#锁住的对应楼层和院落#C0x5B545B#，就可以看到解锁条件'
	},
	[125203] = {
		id = 125203,
		fmt = '3.小屋里可以摆放各种各样的家具，一些家具附有脚印的踩踏区域，在该区域上不可再叠放其他家具，但踩踏区域可以进行重叠，家具大部分都会放在商城里提供售卖，点击商城就可以前往'
	},
	[125204] = {
		id = 125204,
		fmt = '4.有的家具设计做工复杂，属于#C0xF76B45#稀有性的家具#C0x5B545B#，虽然售卖价格可能稍高，但是摆放之后肯定很好看，#C0xF76B45#另外家具也有属于的套装#C0x5B545B#，若收集成套还可激活额外属性哦'
	},
	[125205] = {
		id = 125205,
		fmt = '5.每次初次获得了一个家具之后，都会获得收藏经验，可以#C0xF76B45#提高你的收藏家等级#C0x5B545B#，也可获得额外属性'
	},
	[125206] = {
		id = 125206,
		fmt = '6.买到了心仪的家具之后，可点击布置功能用家具装扮你的小屋，注意墙面装饰只可在墙上使用，室内、院落标记的家具也仅可以在屋内（每个楼层）或院落对应区域中进行摆放'
	},
	[125207] = {
		id = 125207,
		fmt = '7.小屋内还提供布置方案的保存，你可以设计很多优秀的装修方案并在方案里保存和预览，需要注意，院落的布置方案和屋内（每个楼层）是分别保存和应用的'
	},
	[125208] = {
		id = 125208,
		fmt = '8.小屋家具均设定有装饰度，布置模式下，可以查看到当前楼层的装饰度总值，重复放置相同家具后装饰度会进行衰减，另外同层摆齐一套家具后还可获得额外系列加成，每个系列同层可获得一次哦，同层小屋的装饰度总值会在拜访内展示并有排行'
	},
	[125301] = {
		id = 125301,
		fmt = '1.活动期间，完成任务即可在活动界面上进行祈福'
	},
	[125302] = {
		id = 125302,
		fmt = '2.祈福时可以获得随机普通祝福，也可以获得幸运祝福'
	},
	[125303] = {
		id = 125303,
		fmt = '3.每次祈福，若没有获得幸运祝福，将可点亮一张幸运签，幸运签点亮个数越多的，获得幸运祝福的概率就越大，当点亮界面中所有的幸运签后，下一次必定可获得幸运祝福'
	},
	[125304] = {
		id = 125304,
		fmt = '4.任务每日定时重置，请注意及时完成以及领取，已获得的祈福次数不重置，将一直保留至活动结束'
	},
	[125305] = {
		id = 125305,
		fmt = '5.祈福任务界面中的祈福记录，可以查看本次活动获得的奖励内容'
	},
	[125401] = {
		id = 125401,
		fmt = '1.邮件上限为#C0xF76B45#60#C0x5B545B#封'
	},
	[125402] = {
		id = 125402,
		fmt = '2.超出邮件上限时，部分老邮件会丢失，请及时处理'
	},
	[125501] = {
		id = 125501,
		fmt = '#L10##C0xF76B45#强者们，欢迎来到部屋大作战'
	},
	[125502] = {
		id = 125502,
		fmt = '#L10##C0xF76B45#【选拔规则】'
	},
	[125503] = {
		id = 125503,
		fmt = '1.部屋工程需要在多个服中，共选拔 #C0xF76B45#16#C0x5B545B#个强者公会竞争'
	},
	[125504] = {
		id = 125504,
		fmt = '2.工程会根据三周的公会战累计积分选拔（可在部屋大作战界面中查看）， #C0xF76B45#第一和第二#C0x5B545B#排名的公会会被直接选拔'
	},
	[125505] = {
		id = 125505,
		fmt = '3.若匹配的跨服组内，无法凑齐所需工程数量的公会，则会根据同跨服组中公会战积分排名3~5名的公会中选取（优先选取公会总战力较高的）'
	},
	[125506] = {
		id = 125506,
		fmt = '4.在锁定本周入选公会后，入选公会内的所有玩家都会自动报名本周部屋的战斗'
	},
	[125507] = {
		id = 125507,
		fmt = '#L10##C0xF76B45#【基础规则】'
	},
	[125508] = {
		id = 125508,
		fmt = '1.部屋大作战以 #C0xF76B45#四周#C0x5B545B#为一个赛季，收集三周的公会战积分排名信息后，第四周周三开启，并展示入选公会详情'
	},
	[125509] = {
		id = 125509,
		fmt = '2.部屋大作战分为初赛和决赛两个阶段， 初赛为开启周的#C0xF76B45#周五#C0x5B545B#，决赛为开启周的#C0xF76B45#周日#C0x5B545B#'
	},
	[125510] = {
		id = 125510,
		fmt = '3.被选拔的公会，系统会为公会成员自动报名，会内成员需要在#C0xF76B45#9:00~20:50#C0x5B545B#选择自己的工程组和对应上阵阵容'
	},
	[125511] = {
		id = 125511,
		fmt = '4.比赛前10分钟未选择战场的玩家，系统会随机分配战场和选择较高战力的精灵布阵'
	},
	[125512] = {
		id = 125512,
		fmt = '5.正式开赛时间：#C0xF76B45#21:00#C0x5B545B#'
	},
	[125513] = {
		id = 125513,
		fmt = '#L10##C0xF76B45#【初赛规则】'
	},
	[125514] = {
		id = 125514,
		fmt = '1.初赛阶段：选拔的16个公会，根据战力排名分成四个竞标团，公会内的成员需要在规定的时间内报名自己想要参加的工程组'
	},
	[125515] = {
		id = 125515,
		fmt = '2.工程组共有三种'
	},
	[125516] = {
		id = 125516,
		fmt = '6人施工组：可派遣两队，每队6只精灵'
	},
	[125517] = {
		id = 125517,
		fmt = '4人勘测组：可派遣三队，每队4只精灵'
	},
	[125518] = {
		id = 125518,
		fmt = '1人设计组：可派遣三队，每队3只精灵'
	},
	[125519] = {
		id = 125519,
		fmt = '参赛玩家只能选择其中一个赛场参战，在报名工程时间结束后，锁定工程组和上阵精灵，战斗开始后无法修改'
	},
	[125520] = {
		id = 125520,
		fmt = '3.在战斗中，第一队被击倒后，第二队可在下一轮中继续战斗'
	},
	[125521] = {
		id = 125521,
		fmt = '4.比赛形式为混战模式，您会优先匹配到非本公会的玩家对战（当剩余玩家都是本公会的玩家时，战斗结束）'
	},
	[125522] = {
		id = 125522,
		fmt = '5.胜利的玩家，可继续进行下一轮的战斗，与其余非本公会对手继续对战'
	},
	[125523] = {
		id = 125523,
		fmt = '6.没有可上阵精灵的玩家会被暂时淘汰，若被淘汰的玩家所属公会成功晋级决赛，则一同晋级；若所属公会晋级失败，则无缘此次冠军争夺'
	},
	[125524] = {
		id = 125524,
		fmt = '6.每次战斗结束后保留生命值和怒气值'
	},
	[125525] = {
		id = 125525,
		fmt = '7.部屋大作战存在积分机制，不同的工程组胜利和失败会获得不同的积分'
	},
	[125526] = {
		id = 125526,
		fmt = '6人施工组：胜利可获得#C0xF76B45#12#C0x5B545B#积分，失败可获得#C0xF76B45#4#C0x5B545B#积分'
	},
	[125527] = {
		id = 125527,
		fmt = '4人勘测组：胜利可获得#C0xF76B45#8#C0x5B545B#积分，失败可获得#C0xF76B45#3#C0x5B545B#积分'
	},
	[125528] = {
		id = 125528,
		fmt = '1人设计组：胜利可获得#C0xF76B45#8#C0x5B545B#积分，失败可获得#C0xF76B45#3#C0x5B545B#积分'
	},
	[125529] = {
		id = 125529,
		fmt = '8.当公会所在战场仅剩余本公会玩家时，该战场战斗结束，每位存活的公会成员都可以获得#C0xF76B45#10#C0x5B545B#积分的额外存活积分（无工程组区分，全部战斗结束后汇入总积分中）'
	},
	[125530] = {
		id = 125530,
		fmt = '9.公会是否晋级由当日公会成员在不同工程组的汇总积分决定'
	},
	[125531] = {
		id = 125531,
		fmt = '10.双方最多战斗10回合，到时间若未分出胜负，剩余血量百分比多的一方获胜'
	},
	[125532] = {
		id = 125532,
		fmt = '11.初赛结束后，四个战斗组会选出各自的第一参与决赛，其余公会淘汰'
	},
	[125533] = {
		id = 125533,
		fmt = '#L10##C0xF76B45#【决赛规则】'
	},
	[125534] = {
		id = 125534,
		fmt = '1.根据初赛的成绩，选取四个强者公会进入到最后的冠军之争'
	},
	[125535] = {
		id = 125535,
		fmt = '2.决赛赛制与初赛统一'
	},
	[125536] = {
		id = 125536,
		fmt = '3.最后根据同初赛的积分机制做出决赛排名，决出1~4名'
	},
	[125537] = {
		id = 125537,
		fmt = '4.冠军公会将获得跨服组内每个公会都可见的无上荣誉'
	},
	[125538] = {
		id = 125538,
		fmt = '#L10##C0xF76B45#【精灵能力变化】'
	},
	[125539] = {
		id = 125539,
		fmt = '1.整个部屋大作战对战期间，每轮的对战中，首次进入战斗队伍中的所有精灵可以获得一定的攻击，防御，速度等属性加成'
	},
	[125540] = {
		id = 125540,
		fmt = '2.随着对战持续，该属性加成会得到衰减，且精灵会变得疲惫，战斗能力越来越弱'
	},
	[125541] = {
		id = 125541,
		fmt = '3.之后每次参与对战，队伍中的精灵攻击，防御，速度，受治疗量等属性会持续降低'
	},
	[125542] = {
		id = 125542,
		fmt = '#L10##C0xF76B45#【竞猜规则】'
	},
	[125543] = {
		id = 125543,
		fmt = '1.同一跨服组的所有玩家都可参与竞猜（包括参与战斗的玩家）'
	},
	[125544] = {
		id = 125544,
		fmt = '2.初赛和决赛都可竞猜'
	},
	[125545] = {
		id = 125545,
		fmt = '初赛阶段玩家可竞猜四次（每个战斗组各一次），竞猜目标为晋级决赛公会'
	},
	[125546] = {
		id = 125546,
		fmt = '决赛阶段玩家可竞猜一次，竞猜目标为冠军'
	},
	[125547] = {
		id = 125547,
		fmt = '3.竞猜需要消耗公会币，初赛每次竞猜需要300个，决赛竞猜需消耗1500个公会币'
	},
	[125548] = {
		id = 125548,
		fmt = '4.参与竞猜的玩家都会奖励，奖励通过邮件的方式发放'
	},
	[125549] = {
		id = 125549,
		fmt = '#L10##C0xF76B45#【奖励规则】'
	},
	[125550] = {
		id = 125550,
		fmt = '1.比赛结束后，所有奖励均通过邮件发送；'
	},
	[125551] = {
		id = 125551,
		fmt = '2.部屋大作战是以公会为单位的荣耀战，公会排名奖励为该公会所有参赛人员获得'
	},
	[125552] = {
		id = 125552,
		fmt = '3.参与初赛和决赛的公会均可获得一份奖励'
	},
	[125553] = {
		id = 125553,
		fmt = '4.获得决赛冠军的公会可获得跨服组内最高荣誉展示'
	},
	[125554] = {
		id = 125554,
		fmt = '5.积分排名奖励详见以下奖励展示'
	},
	[125601] = {
		id = 125601,
		fmt = '#L10##C0xF76B45#【初赛与决赛竞猜】'
	},
	[125602] = {
		id = 125602,
		fmt = '1.玩家可在大作战当天进行竞猜'
	},
	[125603] = {
		id = 125603,
		fmt = '2.竞猜时间为周五和周日的9:00~20:50'
	},
	[125604] = {
		id = 125604,
		fmt = '3.统一跨服组内的所有玩家都可参与竞猜'
	},
	[125605] = {
		id = 125605,
		fmt = '4.初赛阶段，可在每个区域都竞猜一个公会，共四组，竞猜目标为组内第一名'
	},
	[125606] = {
		id = 125606,
		fmt = '5.决赛阶段，可在四个公会内选择其中一个，竞猜目标为冠军公会'
	},
	[125607] = {
		id = 125607,
		fmt = '6.每次竞猜都会消耗一定数量的公会币'
	},
	[125608] = {
		id = 125608,
		fmt = '7.竞猜成功的玩家可获得物品奖励，竞猜失败的玩家也会获得安慰奖'
	},
	[125609] = {
		id = 125609,
		fmt = '8.若玩家5次竞猜全部成功则会获得额外奖励'
	},
	[125701] = {
		id = 125701,
		fmt = '#C0xF76B45#【基础规则】'
	},
	[125702] = {
		id = 125702,
		fmt = '1.世界锦标赛初次登场，仍需继续优化完善，后续可能进行规则上的微调'
	},
	[125703] = {
		id = 125703,
		fmt = '2.世界锦标赛分赛季进行，赛季开启、持续时间可在世界锦标赛玩法主界面查看'
	},
	[125704] = {
		id = 125704,
		fmt = '3.比赛期间，#C0xF76B45#每周五、六、日#C0x5B545B#开启对战，每周五#C0xF76B45#10点#C0x5B545B#后可进行对战'
	},
	[125705] = {
		id = 125705,
		fmt = '4.天梯对战存在次数限制，对战期间每天凌晨#C0xF76B45#5点#C0x5B545B#重置'
	},
	[125706] = {
		id = 125706,
		fmt = '5.世界锦标赛设置胜点机制，对战胜利可获取胜点，胜点对应相应段位，提升胜点可提高段位'
	},
	[125707] = {
		id = 125707,
		fmt = '6.世界锦标赛中，每10分钟可以获取一定锦标赛币奖励，奖励随段位提高而增加'
	},
	[125708] = {
		id = 125708,
		fmt = '7.世界锦标赛分为战区赛和全服赛，初始段位只能进行战区内的比赛，达到钻石级后，可进行全服比赛，与全区全服的高手一较高下吧'
	},
	[125709] = {
		id = 125709,
		fmt = '8.每个赛季结算时间为结束日期的#C0xF76B45#22点#C0x5B545B#'
	},
	[125710] = {
		id = 125710,
		fmt = '#C0xF76B45#【战斗规则】'
	},
	[125711] = {
		id = 125711,
		fmt = '1.世界锦标赛的战斗为三队宝可梦的随机一对一对战，每队最多#C0xF76B45#6个宝可梦#C0x5B545B#，为自动战斗形式，三局两胜制'
	},
	[125712] = {
		id = 125712,
		fmt = '2.每队最多战斗20回合，战斗过程中一方精灵全部战败则判为失败，若回合结束未分出胜负，则判定为剩余精灵的血量百分比之和高的一方胜出'
	},
	[125713] = {
		id = 125713,
		fmt = '3.世界锦标赛的布阵设【精英宝可梦】，同一时间，可指定若干个宝可梦为【精英宝可梦】'
	},
	[125714] = {
		id = 125714,
		fmt = '4.【精英宝可梦】可在不同的布阵队伍中使用两次（即可额外使用一次）'
	},
	[125715] = {
		id = 125715,
		fmt = '5.每个队伍中，【精英宝可梦】上阵数量有一定限制'
	},
	[125716] = {
		id = 125716,
		fmt = '6.部分特殊宝可梦系列无法被同时选择为【精英宝可梦】'
	},
	[125717] = {
		id = 125717,
		fmt = '7.战斗时，敌我双方的队伍会随机配对进行战斗'
	},
	[125718] = {
		id = 125718,
		fmt = '#C0xF76B45#【资源产出】'
	},
	[125719] = {
		id = 125719,
		fmt = '根据玩家段位，每10分钟可产生一定段位奖励，段位奖励存在上限(上限为相应段位对应24小时的产量)，请及时领取哟；#C0xF76B45#荧光棒#C0x5B545B#可领取为等量的金币；休战期也是可以领取的哟！'
	},
	[125720] = {
		id = 125720,
		fmt = '#C0xF76B45#【赛季奖励】'
	},
	[125721] = {
		id = 125721,
		fmt = '1.世界锦标赛赛季奖励包含赛季结束全服排名奖励、赛季结束段位奖励，可点击奖励按钮查看,奖励在结算时通过邮件领取'
	},
	[125722] = {
		id = 125722,
		fmt = '2.世界锦标赛还设置每周挑战奖励，挑战达到指定次数即可领取相应奖励'
	},
	[125723] = {
		id = 125723,
		fmt = '3.称号奖励，在赛季结束当日#C0xF76B45#22:00#C0x5B545B#将根据全服排名发放个人称号奖励，#C0xF76B45#称号奖励通过邮件领取'
	},
	[125724] = {
		id = 125724,
		fmt = '4.赛季专属头像框框奖励，若玩家达到一定排名，在赛季结束当日#C0xF76B45#22:00#C0x5B545B#将根据当前段位发放对应段位的专属头像框奖励，#C0xF76B45#头像框奖励通过邮件领取'
	},
	[125801] = {
		id = 125801,
		fmt = '1.将获得的图腾置入秘符，激活秘符来获得超强属性吧！'
	},
	[125802] = {
		id = 125802,
		fmt = '2.秘境中拥有许多石像，每个石像都附着了不少的秘符，这些秘符带有神秘的属性，需要使用收集到的图腾道具，当一块秘符上的所有图腾均被置入后，即可获得其属性加成'
	},
	[125803] = {
		id = 125803,
		fmt = '3.每块秘符仅可被激活一次，激活后立即获得属性，其中还有些秘符附带的是针对某些元素的精灵独有的属性加成，可以点击秘符进行查看'
	},
	[125804] = {
		id = 125804,
		fmt = '4.每个石像均记录着激活秘符获得的属性值可提供给探险家记录查看，同时，还可领取激活奖励，在收集总览内可以查看到'
	},
	[125805] = {
		id = 125805,
		fmt = '5.激活秘符除了获得属性加成外，还可积攒秘符能量，积攒的秘符能量不仅能为你带来额外的属性加成，还可以解锁其他神秘的新石像！'
	},
	[125901] = {
		id = 125901,
		fmt = '1.欢迎进入市中心，这里是家园的“主心骨”，负责处理居民和精灵们的各种行政问题'
	},
	[125902] = {
		id = 125902,
		fmt = '2.市中心可以进行#C0xF76B45#升级#C0x5B545B#，只要备齐一些材料道具即可，好的建筑需要精雕细琢，所以可能需要等上一段时间，如果不想等待的，也可以花费一点钻石快速完成'
	},
	[125903] = {
		id = 125903,
		fmt = '3.家园内的#C0xF76B45#其他建筑升级或解锁会和市中心的等级有关联#C0x5B545B#，需要市中心等级达成解锁建筑的，在市中心界面内具体升级界面进行提示；需要市中心等级达成拓展其他建筑上限的，在各个建筑水升级界面上将展示条件'
	},
	[126001] = {
		id = 126001,
		fmt = '1.欢迎来到各个加工厂，这些建筑负责为家园的居民和精灵提供各种建造、生活的便利'
	},
	[126002] = {
		id = 126002,
		fmt = '#C0xF76B45#【关于各个加工厂】'
	},
	[126003] = {
		id = 126003,
		fmt = '1.在#C0xF76B45#炼金场、甜品站、伐木场#C0x5B545B#中，会#C0xF76B45#一直持续产出道具#C0x5B545B#，道具主要使用在建设、精灵探险中；而#C0xF76B45#金融银行#C0x5B545B#则需要#C0xF76B45#手动设定订单#C0x5B545B#后才开始生产，主要产出货币'
	},
	[126004] = {
		id = 126004,
		fmt = '2.持续产出道具的工厂#C0xF76B45#每隔一段时间可领取产出道具#C0x5B545B#，未领取时道具将占用工厂库存，#C0xF76B45#当库存已满时，工厂会停止工作；#C0x5B545B#而金融银行则有#C0xF76B45#订单数量的限制#C0x5B545B#，每次生产#C0xF76B45#不可设定超出上限#C0x5B545B#，当生产完成时，一次性领取产出货币'
	},
	[126005] = {
		id = 126005,
		fmt = '3.所有建筑同样可以#C0xF76B45#升级，#C0x5B545B#升级条件设定不尽相同，升级后，各工厂的#C0xF76B45#库存上限、生产效率以及精灵精力消耗#C0x5B545B#均会有变化'
	},
	[126006] = {
		id = 126006,
		fmt = '4.加工厂内可以#C0xF76B45#预设值班小队#C0x5B545B#啦，这样训练家就可以方便的从#C0xF76B45#预设小队里直接调拨精灵#C0x5B545B#进入加工厂值班！需要注意功能需要训练家#C0xF76B45#一定等级#C0x5B545B#后开启，开启后，#C0xF76B45#需要本加工厂内3个值班位置全部解锁#C0x5B545B#后方能使用~'
	},
	[126007] = {
		id = 126007,
		fmt = '#C0xF76B45#【精灵值班】'
	},
	[126008] = {
		id = 126008,
		fmt = '1.所有建筑内均可派出精灵常驻在内值班，#C0xF76B45#每个建筑最多可容纳3只精灵#C0x5B545B#，值班需要消耗精灵精力，无精力的精灵则会停止值班工作，且需要#C0xF76B45#手动撤下；#C0x5B545B#精灵精力消耗按照当前所处的加工厂内标准进行扣除'
	},
	[126009] = {
		id = 126009,
		fmt = '2.所有加工厂内，每指派1个精灵值班且在#C0xF76B45#工作状态#C0x5B545B#时，将会获得#C0xF76B45#对于库存上限、生产效率、订单市场缩减等的加成效果#C0x5B545B#，普通加成效果会在对应工厂的界面中进行展示，可进行查看'
	},
	[126010] = {
		id = 126010,
		fmt = '3.当加工厂停止工作时（持续产出道具的工厂库存爆满、金融银行当前未接到订单时），精灵也会停止工作，此时#C0xF76B45#不会再扣除精灵精力#C0x5B545B#，直至他们再次开始值班工作'
	},
	[126011] = {
		id = 126011,
		fmt = '4.一旦将精灵安排值班工作，精灵将处于#C0xF76B45#工作中状态#C0x5B545B#，不可在家园的其他地方再行使用，也可随时撤下精灵，撤下时会根据当前消耗的精力进行扣除'
	},
	[126012] = {
		id = 126012,
		fmt = '5.精灵有携带家园技能，达成设定条件后技能可升级，技能可能会#C0xF76B45#针对不同的建筑生效#C0x5B545B#，未在该建筑内的，技能效果将不作数，请仔细查看技能描述'
	},
	[126013] = {
		id = 126013,
		fmt = '6.一些精灵带有可以减少所有值班小伙伴们精力消耗的技能效果的，同时值班2个该类精灵时，效果只取一个最优的计算'
	},
	[126014] = {
		id = 126014,
		fmt = '7.#C0xF76B45#精灵在被撤下之后，会自然恢复精力，悄悄告诉探险家们：把精灵放置到小憩花园中，精灵精力恢复会更快速哦'
	},
	[126101] = {
		id = 126101,
		fmt = '1.欢迎来到未知探险，这里是通向外面世界的渠道之一，在这里可以获得一些家园里并不常见的东西哦'
	},
	[126102] = {
		id = 126102,
		fmt = '2.探险中有许多不同的区域，每个区域都有#C0xF76B45#探索度#C0x5B545B#，每次探索都会获得探索度加成，#C0xF76B45#升级探索度经验条可以使探索获得的道具更加优质'
	},
	[126103] = {
		id = 126103,
		fmt = '3.每个区域#C0xF76B45#同时可分派1支探索小队前往#C0x5B545B#，探索小队由#C0xF76B45#5只精灵+1个探险器组成#C0x5B545B#，其中探险器可以设置，也可以不设置'
	},
	[126104] = {
		id = 126104,
		fmt = '4.探险除了需要消耗精灵精力，还需要消耗甜点，每个区域探险都将提供#C0xF76B45#3个探险方案可供选择#C0x5B545B#，每个方案的探险持续时长不一样，所需的消耗和所得的奖励也会有所差别'
	},
	[126105] = {
		id = 126105,
		fmt = '5.一旦派出探险，精灵将处于#C0xF76B45#工作中状态#C0x5B545B#，不可在家园的其他地方再行使用，探险中若想撤换精灵，撤销精灵或探险器，则需要中断探险，中断后将不可获得探险奖励'
	},
	[126106] = {
		id = 126106,
		fmt = '6.精灵有携带家园探险技能，达成设定条件后技能可升级，技能可能会#C0xF76B45#针对不同区域生效#C0x5B545B#，使用时请仔细查看技能描述'
	},
	[126107] = {
		id = 126107,
		fmt = '7.一些精灵带有可以减少本次探险时长技能效果的，同时值班2个该类精灵时，效果只取一个最优的计算'
	},
	[126108] = {
		id = 126108,
		fmt = '8.探险器同样也拥有探险技能，可对探险大有作用，在探险器达到要求等级后解锁技能，之后需要消耗对应道具即可升级技能，使用时请仔细查看技能描述'
	},
	[126109] = {
		id = 126109,
		fmt = '9.#C0xF76B45#精灵未在探险时，会自然恢复精力，悄悄告诉探险家们：把精灵放置到小憩花园中，精灵精力恢复会更快速哦'
	},
	[126201] = {
		id = 126201,
		fmt = '#L10##C0xF76B45#辞旧迎新，点亮新春'
	},
	[126202] = {
		id = 126202,
		fmt = '1，在活动期间内，每日都可以点亮1盏灯笼或1种物品'
	},
	[126203] = {
		id = 126203,
		fmt = '2，点亮灯笼前需要回答灯谜，灯谜结束点亮物品可获得奖励'
	},
	[126301] = {
		id = 126301,
		fmt = '1.精灵训练师们可以将剩余无处镶嵌的图腾在图腾分解内无消耗分解'
	},
	[126302] = {
		id = 126302,
		fmt = '2.已经镶嵌进秘符的图腾不能分解，也无法在图腾分解内查看'
	},
	[126303] = {
		id = 126303,
		fmt = '3.每次分解可按照品质分类一键多选；或者长按多选进行分解'
	},
	[126304] = {
		id = 126304,
		fmt = '4.任何品质的图腾分解后都可获得一种图腾分解材料，用于图腾商店或其他途径中消耗使用'
	},
	[127001] = {
		id = 127001,
		fmt = '#C0xF76B45#【基本规则】'
	},
	[127002] = {
		id = 127002,
		fmt = '1.对战竞猜为限时活动玩法，玩法中红蓝两方阵容对战，玩家通过竞猜其中一方能获得最终胜利的方式赢得奖励'
	},
	[127003] = {
		id = 127003,
		fmt = '2.玩法内使用竞猜代币进行竞猜，竞猜代币通过每日系统赠送，也可通过兑换购买代币，竞猜成功后获得竞猜积分，竞猜积分可在商店兑换道具'
	},
	[127004] = {
		id = 127004,
		fmt = '3.请注意查看玩法界面的活动时间，每场战斗结算前停止该场战斗的竞猜，当天所有比赛结束后开启下一天的赛事竞猜'
	},
	[127005] = {
		id = 127005,
		fmt = '4.每场比赛竞猜分多个档位，对应竞猜所需消耗的竞猜代币，档位越高竞猜成功后获得奖励越多'
	},
	[127006] = {
		id = 127006,
		fmt = '5.确认竞猜之后无法更改竞猜方，竞猜成功或失败都会获得对应的竞猜积分'
	},
	[127007] = {
		id = 127007,
		fmt = '6.竞猜成功后根据竞猜赔率和玩家下注的竞猜代币，可在玩法界面领取竞猜积分；竞猜失败后，系统也会给少量的竞猜积分作为安慰奖励'
	},
	[127008] = {
		id = 127008,
		fmt = '7.玩法设置弹幕聊天功能，玩家可发表对这场比赛的胜负分析'
	},
	[127009] = {
		id = 127009,
		fmt = '8.翻盘局：玩家选择竞猜的队伍总竞猜人数和总竞猜代币数额均低于敌对方30%时，若选择竞猜该方并该队伍取得胜利，则该局为翻盘局，竞猜赔率会替换成更高的翻盘赔率'
	},
	[127010] = {
		id = 127010,
		fmt = '#C0xF76B45#【战斗规则】'
	},
	[127011] = {
		id = 127011,
		fmt = '1.战斗类型为全自动，玩家仅可以查看战报形式观战，战斗前可查看对阵双方的具体信息'
	},
	[127012] = {
		id = 127012,
		fmt = '2.每场比赛中参战精灵等级和星级基本保持一致，有固定的属性和固定的携带道具，注意查看有助于提升竞猜成功率哦~'
	},
	[127013] = {
		id = 127013,
		fmt = '3.战斗中有一定程度的随机天气效果，天气效果也许会对比赛结果有所影响'
	},
	[127014] = {
		id = 127014,
		fmt = '4.战斗胜负判定：全部被消灭的一方判负，若战斗满20回合按人数多的一方获胜，若双方数量相同则按所有精灵生命值总和较多的一方获胜'
	},
	[127015] = {
		id = 127015,
		fmt = '5.每场战斗结算后开放战报供玩家回放观战'
	},
	[127051] = {
		id = 127051,
		fmt = '由16只精灵率领的16支队伍，经过激烈的6V6小组赛和淘汰赛洗礼，最终决出一支优胜队伍！每个队伍有固定的精灵以及携带道具，你可以通过观察选择一个你觉得可以夺冠的队伍进行支持'
	},
	[127052] = {
		id = 127052
	},
	[127053] = {
		id = 127053,
		fmt = '#C0xF76B45#【基本规则】'
	},
	[127054] = {
		id = 127054,
		fmt = '1.对战庆典为限时活动玩法，由对战竞猜原有固定的队伍对战转变为多支队伍决出冠军的方式'
	},
	[127055] = {
		id = 127055,
		fmt = '2.每一场赛事分红蓝两方阵容对战，玩家可通过竞猜其中一方能获得最终胜利的方式赢得奖励'
	},
	[127056] = {
		id = 127056,
		fmt = '3.玩法内使用竞猜代币进行竞猜，竞猜代币通过每日系统赠送，也可通过兑换购买代币，竞猜成功后获得庆典积分，庆典积分可在商店兑换道具'
	},
	[127057] = {
		id = 127057,
		fmt = '4.请注意查看每场赛事的竞猜时间，每场战斗结算前停止该场战斗的竞猜，当天所有比赛结束后开启下一天的赛事竞猜'
	},
	[127058] = {
		id = 127058,
		fmt = '5.每场比赛竞猜分多个档位，对应竞猜所需消耗的竞猜代币，档位越高竞猜成功后获得奖励越多'
	},
	[127059] = {
		id = 127059,
		fmt = '6.确认竞猜之后无法更改竞猜方，竞猜成功或失败都会获得对应的庆典积分'
	},
	[127060] = {
		id = 127060,
		fmt = '7.竞猜成功后根据竞猜赔率和玩家下注的竞猜代币，可在玩法界面领取庆典积分；竞猜失败后，系统也会给少量的庆典积分作为安慰奖励'
	},
	[127061] = {
		id = 127061,
		fmt = '8.翻盘局：玩家选择竞猜的队伍总竞猜人数和总竞猜代币数额均低于敌对方30%时，若选择竞猜该方并该队伍取得胜利，则该局为翻盘局，竞猜赔率会替换成更高的翻盘赔率'
	},
	[127070] = {
		id = 127070,
		fmt = '#C0xF76B45#【战斗规则】'
	},
	[127071] = {
		id = 127071,
		fmt = '1.战斗类型为全自动，玩家仅可以查看战报形式观战，战斗前可查看对阵双方的具体信息'
	},
	[127072] = {
		id = 127072,
		fmt = '2.每场比赛中参战精灵等级和星级基本保持一致，有固定的属性和固定的携带道具，注意查看有助于提升竞猜成功率哦~'
	},
	[127073] = {
		id = 127073,
		fmt = '3.战斗中有一定程度的随机天气效果，天气效果也许会对比赛结果有所影响'
	},
	[127074] = {
		id = 127074,
		fmt = '4.战斗胜负判定：全部被消灭的一方判负，若战斗满20回合按人数多的一方获胜，若双方数量相同则按所有精灵生命值总和较多的一方获胜'
	},
	[127075] = {
		id = 127075,
		fmt = '5.战斗中双方会持续累加造成伤害增加和治疗量降低的效果'
	},
	[127076] = {
		id = 127076,
		fmt = '6.战斗中的属性克制伤害会额外加深'
	},
	[127081] = {
		id = 127081,
		fmt = '#C0xF76B45#【冠军竞猜】'
	},
	[127082] = {
		id = 127082,
		fmt = '1.进入竞猜冠军页面，查看各个队伍的阵容、站位、属性、携带道具等详细信息'
	},
	[127083] = {
		id = 127083,
		fmt = '2.选择自己认为最有希望夺冠队伍进行竞猜支持，竞猜时间截止于第一场小组赛开赛前'
	},
	[127084] = {
		id = 127084,
		fmt = '3.冠军竞猜无需消耗竞猜代币，且仅能竞猜1次，确认竞猜之后无法更改'
	},
	[127085] = {
		id = 127085,
		fmt = '4.支持的队伍，将根据最终的排名（冠军、亚军、季军、殿军、八强、未进八强）决定奖励'
	},
	[127086] = {
		id = 127086,
		fmt = '#C0xF76B45#【小组赛】'
	},
	[127087] = {
		id = 127087,
		fmt = '1.16支队伍分为ABCD4个小组，每个小组的队伍两两之间相互对决，每天进行6场战斗，共24场战斗'
	},
	[127088] = {
		id = 127088,
		fmt = '2.获胜队伍获得1分，败北队伍不得分'
	},
	[127089] = {
		id = 127089,
		fmt = '3.小组赛结束时，每组积分最高的两队出线，作为八强晋级淘汰赛'
	},
	[127090] = {
		id = 127090,
		fmt = '4.若积分相同，则看每个队伍所有赛事结束时累计存活的精灵数量，数量多的队伍排名靠前；若数量仍相同，则按队伍造成的总伤害量较高的排名靠前'
	},
	[127091] = {
		id = 127091,
		fmt = '#C0xF76B45#【淘汰赛】'
	},
	[127092] = {
		id = 127092,
		fmt = '1.淘汰赛分为四强赛的4场战斗，半决赛的2场战斗，以及季军赛和冠军赛，一共8场战斗'
	},
	[127093] = {
		id = 127093,
		fmt = '2.四强赛由4个小组第1名与其他小组的第2名分别对阵，获胜的4支队伍进入半决赛'
	},
	[127094] = {
		id = 127094,
		fmt = '3.半决赛失败的2支队伍进入季军赛，获胜的一方为季军，失败的一方为殿军'
	},
	[127095] = {
		id = 127095,
		fmt = '4.季军赛后，半决赛获胜的2支队伍将进行冠军赛决赛，最终优胜方将成为本届对战庆典的冠军，失败方成为亚军'
	},
	[127096] = {
		id = 127096,
		fmt = '5.赛事全部结束后，将通过邮件发放冠军竞猜奖励'
	},
	[127097] = {
		id = 127097,
		fmt = '6.半决赛、季军赛、冠军赛在同一天进行，请注意合理分配使用竞猜代币！！'
	},
	[127110] = {
		id = 127110,
		fmt = '#C0xF76B45#【活动规则】'
	},
	[127111] = {
		id = 127111,
		fmt = '1.活动期间，可通过完成任务获取翻牌次数'
	},
	[127112] = {
		id = 127112,
		fmt = '2.每消耗1点翻牌次数即可翻开一张牌，卡牌背面会隐藏本轮需要寻找的精灵和干扰精灵'
	},
	[127113] = {
		id = 127113,
		fmt = '3.当翻出任意行、列或对角线4个牌子都为同一需要寻找的精灵时，完成当次关卡，进入下一关'
	},
	[127114] = {
		id = 127114,
		fmt = '4.每轮过关后都可获得寻找奖励，并且会获得额外步数奖励，翻牌次数在8次以内（包括第8次）奖励会更优'
	},
	[127200] = {
		id = 127200,
		fmt = '1.#C0xF76B45##L10#甲贺忍蛙#C0x5B545B#拥有羁绊进化的资格，可通过羁绊进化进化成小智版甲贺忍蛙'
	},
	[127201] = {
		id = 127201,
		fmt = '2.羁绊进化有一定的前提条件：星级、个体总值、好感度、战斗力，以上全部满足方可羁绊进化'
	},
	[127203] = {
		id = 127203,
		fmt = '3.羁绊进化所需的钥石和专属的超级进化石，每天都可以在超进化屋内通过转化获得。'
	},
	[127204] = {
		id = 127204,
		fmt = '4.羁绊进化之后不消耗#C0xF76B45##L10#甲贺忍蛙#C0x5B545B#，且获得一只全新的#C0xF76B45##L10#小智版甲贺忍蛙#C0x5B545B#'
	},
	[127205] = {
		id = 127205,
		fmt = '1.#C0xF76B45##L10#超级火焰鸡#C0x5B545B#可通过特殊超进化进化成假面超级火焰鸡，基本规则与羁绊进化类似'
	},
	[127206] = {
		id = 127206,
		fmt = '2.假面超级火焰鸡进化有一定的前提条件：星级、个体总值、好感度、战斗力，以上全部满足方可特殊进化'
	},
	[127207] = {
		id = 127207,
		fmt = '3.假面超级火焰鸡所需的钥石和专属的超级进化石，每天都可以在超进化屋内通过转化获得。'
	},
	[127208] = {
		id = 127208,
		fmt = '4.假面超级火焰鸡进化之后不消耗#C0xF76B45##L10#超级火焰鸡#C0x5B545B#，且获得一只全新的#C0xF76B45##L10#假面超级火焰鸡#C0x5B545B#'
	},
	[127310] = {
		id = 127310,
		fmt = '#C0xF76B45#【活动规则】'
	},
	[127311] = {
		id = 127311,
		fmt = '1.活动期间，玩家可随时进入游戏，消除精灵'
	},
	[127312] = {
		id = 127312,
		fmt = '2.玩家可#C0xF76B45#任意拖动界面上的两个精灵头像#C0x5B545B#互换位置'
	},
	[127313] = {
		id = 127313,
		fmt = '3.每次移动将#C0xF76B45#3个或3个以上的精灵头像#C0x5B545B#连接到一起后会成功消除，每次成功消除后都可获得积分，#C0xF76B45#单次移动最高可获得10积分！'
	},
	[127314] = {
		id = 127314,
		fmt = '4.听说不同属性的精灵在5个或5个以上同时消除后会产生更强大的效果！（可在游戏界面内查看特殊消除）'
	},
	[127315] = {
		id = 127315,
		fmt = '5.玩家的体力上限为100点，在每次成功消除后，都会扣减2点体力，体力用尽后需要一定时间慢慢恢复'
	},
	[127316] = {
		id = 127316,
		fmt = '6.每一轮都会有新的需求消除数量和剩余步数'
	},
	[127317] = {
		id = 127317,
		fmt = '需求消除：本轮需要完成的某一或某几个精灵需要消除的数量，完成后可获得额外的积分并切换至下一轮'
	},
	[127318] = {
		id = 127318,
		fmt = '剩余步数：指本轮的规定移动次数，不论需求完成与否，剩余步数为0后，就会自动切换到下一轮哦'
	},
	[127319] = {
		id = 127319,
		fmt = '7.通过获取的积分值发放排行奖励，奖励如下'
	},
	[127410] = {
		id = 127410,
		fmt = '#C0xF76B45#【特殊消除说明】'
	},
	[127411] = {
		id = 127411,
		fmt = '当5个或5个以上精灵头像连接消除后，会生成对应的特殊精灵头像，消除特殊精灵头像后会出现如下效果：'
	},
	[127412] = {
		id = 127412,
		fmt = '特殊水：特殊水被消除后可清除特殊水所在行的其余精灵头像'
	},
	[127413] = {
		id = 127413,
		fmt = '特殊雷：特殊雷与某种属性头像交换位置并成功消除后，场上被交换的属性头像全部消除'
	},
	[127414] = {
		id = 127414,
		fmt = '特殊火：特殊火被消除后可消除特殊火所在列的其余精灵头像'
	},
	[127415] = {
		id = 127415,
		fmt = '特殊草：特殊草消除后，场上随机四个头像变为本轮需求的属性头像'
	},
	[127416] = {
		id = 127416,
		fmt = '特殊飞：特殊飞消除后，场上固定菱形路径的方块消除'
	},
	[127500] = {
		id = 127500,
		fmt = '#C0xF76B45#基础说明：#C0x5B545B#'
	},
	[127501] = {
		id = 127501,
		fmt = '1.每日开启固定数量的副本，副本未通关前可重复尝试挑战'
	},
	[127502] = {
		id = 127502,
		fmt = '2.副本首次通关后不可重复挑战，通关上一关才能开启下一关的挑战'
	},
	[127503] = {
		id = 127503,
		fmt = '3.副本内的对话隐藏着通关技巧，通关后信息界面可查看剧情回顾'
	},
	[127504] = {
		id = 127504,
		fmt = '4.副本内的精灵属性均为副本专属特殊修正，与玩家自身养成无关'
	},
	[127505] = {
		id = 127505,
		fmt = '#C0xF76B45#通关技巧：#C0x5B545B#留意关卡效果提示和剧情对话内容'
	},
	[127506] = {
		id = 127506,
		fmt = '#C0xF76B45#副本奖励：#C0x5B545B#通关获得首通奖励'
	},
	[128001] = {
		id = 128001,
		fmt = '1.欢迎来到拜访，现在你可以#C0xF76B45#去到其他训练家的小屋里串门啦！'
	},
	[128002] = {
		id = 128002,
		fmt = '2.这里为你提供了几种串门的方式：#C0xF76B45#拜访我的好友，随机或查找玩家拜访，以及查看最强搭配训练家们的小屋~'
	},
	[128003] = {
		id = 128003,
		fmt = '3.分别点击界面中#C0xF76B45#我的好友、随机访问或在下方查找框内输入玩家昵称或UID（仅可查找本区服）#C0x5B545B#即可查看到对应的玩家，需要查看最强搭配训练家们的小屋时，点击界面下方#C0xF76B45#排行榜#C0x5B545B#即可'
	},
	[128004] = {
		id = 128004,
		fmt = '4.#C0xF76B45#有配置跨服区服的玩家，可以通过随机推送或者在排行榜内#C0x5B545B#前往参观其他服务器内的训练家们的小屋'
	},
	[128005] = {
		id = 128005,
		fmt = '5.除了拜访小屋，还可以对钟意的小屋玩家#C0xF76B45#送花#C0x5B545B#，以表喜爱赞赏之情~#C0xF76B45#每周将会给固定数量的礼赞之花，礼赞之花仅用于在拜访其他玩家小屋时，对对方进行赠送，礼赞之花数量每周重置'
	},
	[128006] = {
		id = 128006,
		fmt = '6.累计收到一定数量礼赞之花可以获得奖励，奖励会在小屋中出现；同样，完成送花数量任务的玩家也可获得奖励，在拜访界面内即可领取。#C0xF76B45#注意，收到的礼赞之花以计数形式累积，并不可再次转送他人奥'
	},
	[128007] = {
		id = 128007,
		fmt = '7.所有排行榜均#C0xF76B45#先按小屋布置的装饰度总值再按收到的礼赞之花数量进行排序#C0x5B545B#，因跨服排行榜展示跨越幅度较大 ，因此#C0xF76B45#需要达到240装饰度才可上榜#C0x5B545B#，快去布置你的小屋吧！'
	},
	[128051] = {
		id = 128051,
		fmt = '1.欢迎来到拜访，现在你可以#C0xF76B45#去到其他训练家的小屋里串门啦！'
	},
	[128052] = {
		id = 128052,
		fmt = '2.这里为你提供了几种串门的方式：#C0xF76B45#拜访我的好友，随机或查找玩家拜访，以及查看最强搭配训练家们的小屋~'
	},
	[128053] = {
		id = 128053,
		fmt = '3.分别点击界面中#C0xF76B45#我的好友、随机访问或在下方查找框内输入玩家昵称或UID（仅可查找本区服）#C0x5B545B#即可查看到对应的玩家，需要查看最强搭配训练家们的小屋时，点击界面下方#C0xF76B45#排行榜#C0x5B545B#即可'
	},
	[128054] = {
		id = 128054,
		fmt = '4.#C0xF76B45#有配置跨服区服的玩家，可以通过随机推送或者在排行榜内#C0x5B545B#前往参观其他服务器内的训练家们的小屋'
	},
	[128055] = {
		id = 128055,
		fmt = '5.除了拜访小屋，还可以对钟意的小屋玩家#C0xF76B45#送花#C0x5B545B#，以表喜爱赞赏之情~#C0xF76B45#每周将会给固定数量的礼赞之花，礼赞之花仅用于在拜访其他玩家小屋时，对对方进行赠送，礼赞之花数量每周重置'
	},
	[128056] = {
		id = 128056,
		fmt = '6.累计收到一定数量礼赞之花可以获得奖励，奖励会在小屋中出现；同样，完成送花数量任务的玩家也可获得奖励，在拜访界面内即可领取。#C0xF76B45#注意，收到的礼赞之花以计数形式累积，并不可再次转送他人奥'
	},
	[128057] = {
		id = 128057,
		fmt = '7.另外，还可以在拜访其他小屋的时候，#C0xF76B45#献上自己对于其他玩家的小屋布置的评价！如果觉得Ta的小屋布置的不错，请奉上超赞的表情；如果觉得Ta的水平还需提升的，那就留下不开心的表情吧'
	},
	[128058] = {
		id = 128058,
		fmt = '8.#C0xF76B45#一周内仅可对相同的玩家做出1次评价，#C0x5B545B#不可重复评价哦，#C0xF76B45#你的评价对于Ta来说非常重要，#C0x5B545B#请真诚，仔细的附上你的评价吧'
	},
	[128059] = {
		id = 128059,
		fmt = '9.所有排行榜中，将根据#C0xF76B45#装饰最终分、评审分进行玩家排名，优先根据装饰最终分排名，分值相同时根据评审分大小排序，均相同的玩家并列排名'
	},
	[128060] = {
		id = 128060,
		fmt = '—装饰最终分是将装饰度值与玩家评价综合计算出的得分，#C0xF76B45#不等于家具布置的装饰度值；评审分则主要与其他玩家对于小屋的评价有关，#C0x5B545B#同样也是根据计算所得的分数'
	},
	[128101] = {
		id = 128101,
		fmt = '1.传说中的许愿池，据说许愿很灵喔！'
	},
	[128102] = {
		id = 128102,
		fmt = '2.点击愿望盒，或者界面中的气泡+按钮可以打开愿望奖励盒，从中选择一个愿望吧！#C0xF76B45#注意，有一些愿望需要达成一些小小的要求才会开放，不同的愿望需要许愿的次数也不同'
	},
	[128103] = {
		id = 128103,
		fmt = '3.每日在许愿池进行许愿，#C0xF76B45#许愿需要耗费一些道具，不同的愿望耗费的道具不同，#C0x5B545B#请准备的充分些吧'
	},
	[128104] = {
		id = 128104,
		fmt = '4.一旦#C0xF76B45#进行过许愿的愿望奖励就不能更换了，直到愿望奖励被领取后才可重新选择，#C0x5B545B#部分愿望在领取之后会有短暂的准备时间，待准备时间结束后可再次选择，请耐心等待一些时日~'
	},
	[128105] = {
		id = 128105,
		fmt = '5.每日许愿之后，#C0xF76B45#有概率立即获得一次惊喜小事件，#C0x5B545B#同时成功领取愿望奖励之后，#C0xF76B45#也有概率获得一张愿望奖券，#C0x5B545B#惊喜小事件和愿望奖券内都将#C0xF76B45#随机奖励一些内容，#C0x5B545B#愿幸运之神常降临与你~'
	},
	[128106] = {
		id = 128106,
		fmt = '6.许愿池#C0xF76B45#需要升级，#C0x5B545B#道具材料准备充足后可来此升级建筑'
	},
	[128201] = {
		id = 128201,
		fmt = '1.家园派对激情上线！快喊你的小伙伴来一块轰趴鸭！'
	},
	[128202] = {
		id = 128202,
		fmt = '2.派对#C0xF76B45#每周周末开启，#C0x5B545B#开启后可自行筹备派对，也可以邀请其他的小伙伴参与自己的派对，#C0xF76B45#参与和筹备均限定次数，#C0x5B545B#请在派对筹办部中仔细查看'
	},
	[128203] = {
		id = 128203,
		fmt = '3.派对有不同的品级可供训练家选择筹办，不同品级的派对的奖励内容、花费以及装饰场面均不相同，选择对应品级的派对后消耗道具即可立即筹办派对！'
	},
	[128204] = {
		id = 128204,
		fmt = '4.筹办派对成功后，#C0xF76B45#筹办派对的玩家将获得筹办道具奖励，进入派对的玩家也可获得参与道具奖励，所有在派对内的玩家均可以享受派对中快速恢复精灵精力的派对福利'
	},
	[128205] = {
		id = 128205,
		fmt = '5.在派对中，点击#C0xF76B45#正中显示的精力气泡框#C0x5B545B#可以打开选择快速恢复精灵精力的功能，#C0xF76B45#注意每一只精灵只可享受一次，#C0x5B545B#选择完毕后精灵瞬时恢复精力，恢复的精力值超出上限的部分不予保留'
	},
	[128206] = {
		id = 128206,
		fmt = '6.一场派对将持续一段时间，想串门？没问题，你可同时在多个派对中出现，同时可在这些派对中进行切换，#C0xF76B45#注意！在切换或参与新派对前使用完快速恢复精灵精力福利，否则去往另一个派对后，本派对的福利不予保留！'
	},
	[128207] = {
		id = 128207,
		fmt = '7.可以邀请其他训练家，或自行接受其他人的邀请进入派对，#C0xF76B45#每场派对均有房间id，#C0x5B545B#若寻找派对时，输入id可以更快速的找到它'
	},
	[128208] = {
		id = 128208,
		fmt = '8.若派对临近结束或派对中的参与奖励已全部被发放，则该派对将不再允许新的训练家加入，可千万别错过心仪的派对噢'
	},
	[128209] = {
		id = 128209,
		fmt = '9.派对中人山人海，气氛爆棚，对于这些派对，还将奉上#C0xF76B45#人气奖励，当派对人数达到一定数量后，将会给所有派对中的训练家们通过邮件发送神秘的人气奖励~'
	},
	[128210] = {
		id = 128210,
		fmt = '10.在每场派对中，均设定了气氛特效、穿戴以及交流弹幕，表情包等功能与小玩法，一定要用用看！'
	},
	[128301] = {
		id = 128301,
		fmt = '#L10##C0xF76B45#拟态形成的机械首领，快摧毁他们的阴谋！'
	},
	[128302] = {
		id = 128302,
		fmt = '#L10##C0xF76B45#温馨提示：专攻一个首领对积分排名更有利！'
	},
	[128303] = {
		id = 128303,
		fmt = '#L10##C0xF76B45#【基础规则】'
	},
	[128304] = {
		id = 128304,
		fmt = '1.拟态对战开启后，每天恢复2次挑战机会，达到上限后停止次数恢复'
	},
	[128305] = {
		id = 128305,
		fmt = '2.拟态挑战每期会有1~3个机械首领，各自拥有不同的特点，可根据特点选择更适合自己的首领进行挑战'
	},
	[128306] = {
		id = 128306,
		fmt = '3.选择首领后，可为首领选择属性增益，不同品质的增益可为本次挑战增加大量积分'
	},
	[128307] = {
		id = 128307,
		fmt = '4.挑战结束后，根据对首领造成的伤害决定积分值的获取，也会根据每次挑战后的积分值发放奖励！'
	},
	[128308] = {
		id = 128308,
		fmt = '5.在多个首领同时开启的情况下，若挑战首领获得的积分一致，则取首个挑战的首领名称和积分上榜'
	},
	[128309] = {
		id = 128309,
		fmt = '#L10##C0xF76B45#【首领属性增益】'
	},
	[128310] = {
		id = 128310,
		fmt = '1.首领的属性增益共有四种品质'
	},
	[128311] = {
		id = 128311,
		fmt = '绿，蓝，部分紫色品质的首领增益可通过挑战任意首领概率获得，且本期首领通用'
	},
	[128312] = {
		id = 128312,
		fmt = '部分紫色，橙色品质的首领增益仅可在对应首领挑战后概率获得，且为该首领专属属性增益'
	},
	[128313] = {
		id = 128313,
		fmt = '2.在增益装备界面可点击增益图标查看增益效果，点击增益图标右下角的复选框上阵或卸下增益'
	},
	[128314] = {
		id = 128314,
		fmt = '3.各品质可装备的首领增益栏位会根据累计积分值的提升逐渐开启'
	},
	[128315] = {
		id = 128315,
		fmt = '4.每个品质的首领增益都有最大的装备上限，可以自行调整挑战难度'
	},
	[128316] = {
		id = 128316,
		fmt = '#L10##C0xF76B45#【战斗规则】'
	},
	[128317] = {
		id = 128317,
		fmt = '1.可选用图鉴内已解锁的精灵'
	},
	[128318] = {
		id = 128318,
		fmt = '2.精灵的#C0xF76B45#等级、突破等级#C0x5B545B#等修正到统一水平线，#C0xF76B45#星级保底修正至8星#C0x5B545B#带入该玩法内，#C0xF76B45#Z觉醒等级会读取同系列中战力最高的精灵#C0x5B545B#带入本玩法中'
	},
	[128319] = {
		id = 128319,
		fmt = '3.#C0xF76B45#精灵的携带道具、符石和芯片系统#C0x5B545B#不继承到本玩法挑战中'
	},
	[128320] = {
		id = 128320,
		fmt = '4.公会技能，天赋技能，探险器属性等修正到统一水平线'
	},
	[128321] = {
		id = 128321,
		fmt = '#L10##C0xF76B45#【额外奖励规则】'
	},
	[128322] = {
		id = 128322,
		fmt = '1.#C0xF76B45#本期结束后，所有成就奖励不补发，请务必在活动结束前领取#C0x5B545B#'
	},
	[128323] = {
		id = 128323,
		fmt = '2.#C0xF76B45#开服时间达到%d天后可进入到跨服组排名#C0x5B545B#'
	},
	[128324] = {
		id = 128324,
		fmt = '3.根据排行榜的名次派发额外奖励'
	},
	[128401] = {
		id = 128401,
		fmt = '#C0xF76B45#【基础规则】'
	},
	[128402] = {
		id = 128402,
		fmt = '1.陨石的培养可提升所有精灵的属性'
	},
	[128403] = {
		id = 128403,
		fmt = '2.每一个陨石都有各自的解锁条件，需完成条件后可解锁培养'
	},
	[128404] = {
		id = 128404,
		fmt = '3.每个陨石都有一定数量的守护精灵和守护携带槽位，玩家可放置精灵和携带，根据培养程度提供基于陨石基础属性额外的百分比加成'
	},
	[128405] = {
		id = 128405,
		fmt = '#C0xF76B45#本养成模式中，z觉醒加成仅对同系列里战力最高的生效#C0x5B545B#'
	},
	[128406] = {
		id = 128406,
		fmt = '#C0xF76B45#同一系列精灵只能守护一个陨石#C0x5B545B#'
	},
	[128407] = {
		id = 128407,
		fmt = '#C0xF76B45#被上阵守护的精灵和携带不能参与到战斗#C0x5B545B#'
	},
	[128408] = {
		id = 128408,
		fmt = '4.上阵的精灵或携带在上阵冷却时间内可卸下，重新上阵需等待冷却结束后可再次上阵守护'
	},
	[128501] = {
		id = 128501,
		fmt = '1.开通订阅会签约您的支付账户，确认订阅后将从您的账户扣费，订阅价格为￥%s/月，订阅周期为1个月'
	},
	[128502] = {
		id = 128502,
		fmt = '2.订阅后会在每个月订阅到期前一天自动从您的账户扣除￥%s/月的费用并自动延长一个月的月卡有效期限，如您未在有效期结束1天前取消订阅，则订阅将会自动续订'
	},
	[128503] = {
		id = 128503,
		fmt = '3.启用自动续订后您可在手机订购项目中取消自动订阅功能，取消订阅后您的账户将不再扣除费用'
	},
	[128504] = {
		id = 128504,
		fmt = '#C0xF76B45#4.自动续订月卡可获得如下奖励，续订成功后通过邮件发放：'
	},
	[128505] = {
		id = 128505,
		fmt = '5.取消自动订阅方法:'
	},
	[128506] = {
		id = 128506,
		fmt = '	您可通过以下方式取消连续包月服务:'
	},
	[128507] = {
		id = 128507,
		fmt = '	-如果是支付宝，可以在支付宝的我的>设置>支付设置>免密支付/自动扣款页面进行解约；'
	},
	[128508] = {
		id = 128508,
		fmt = '	-如果是微信支付，点击头像进入帐号中心>付款与账单>自动扣费/免密支付的功能中可以进行解约。'
	},
	[128509] = {
		id = 128509,
		fmt = '	-可以在App>我的>会员中心>右上角三点>会员购买记录>右上角三点>管理连续包月，即可查看是否取消连续包月产品包。'
	},
	[128601] = {
		id = 128601,
		fmt = '#C0xF76B45#【小游戏规则】'
	},
	[128602] = {
		id = 128602,
		fmt = '1.和魔墙人偶各自摸牌计算牌面点数，#C0xF76B45#谁的点数在不大于21的情况下最接近21，谁将获得本次的胜利！'
	},
	[128603] = {
		id = 128603,
		fmt = '2.每局游戏可用到：#C0xF76B45#2-9点的各4张牌，10点的16张牌，以及4张1或11点数灵活变换的百变牌。抽到2-9牌面时，将按照显示的数字进行点数计算，而抽到百变怪后，可以灵活代入1或者11点进行计算'
	},
	[128604] = {
		id = 128604,
		fmt = '3.游戏开始后，由魔墙人偶进行发牌表演，每人获得2张初始牌，其中魔墙人偶最后获得的一张初始牌翻面，无法看见点数'
	},
	[128605] = {
		id = 128605,
		fmt = '4.接下来#C0xF76B45#先由你进行操作，#C0x5B545B#当你确认操作结束后，魔墙人偶再进行操作'
	},
	[128606] = {
		id = 128606,
		fmt = '5.你可以对牌进行2个基础操作：#C0xF76B45#要牌、停牌。#C0x5B545B#可以#C0xF76B45#连续进行要牌，#C0x5B545B#但是#C0xF76B45#当点击停牌#C0x5B545B#后，#C0xF76B45#本局游戏你的操作将全部结束，#C0x5B545B#接下来等待魔墙人偶操作后进行点数比对结算'
	},
	[128607] = {
		id = 128607,
		fmt = '6.每次要牌之后，将根据#C0xF76B45#当前牌面自动计算点数值，#C0x5B545B#注意#C0xF76B45#若任何一方#C0x5B545B#的牌面点数计算#C0xF76B45#所有结果均超过21点时，#C0x5B545B#则#C0xF76B45#自动停止要牌，并会被判输；#C0x5B545B#若你先手时被判输，则本局结束'
	},
	[128608] = {
		id = 128608,
		fmt = '7.若两方均已停牌，且#C0xF76B45#双方均有任一牌面点数计算结果不超过21的，#C0x5B545B#则双方进行#C0xF76B45#比较大小，较大点数值者胜利；#C0x5B545B#若#C0xF76B45#双方点数一致时，#C0x5B545B#则仍判#C0xF76B45#魔墙人偶获得胜利'
	},
	[128609] = {
		id = 128609,
		fmt = '8.若初始2张牌发完后，即#C0xF76B45#刚好凑成21点的（一张10点+一张百变牌）#C0x5B545B#，则#C0xF76B45#该方直接获得传说中的大胜利！#C0x5B545B#若#C0xF76B45#双方均达成21点的，#C0x5B545B#则仍判#C0xF76B45#魔墙人偶获得胜利'
	},
	[128610] = {
		id = 128610,
		fmt = '9.以上是小游戏的基础规则，接下来将介绍两个玩法：#C0xF76B45#分牌、双倍。#C0x5B545B#这2个玩法#C0xF76B45#只对你开放，且需要在固定的回合#C0x5B545B#进行选择和使用哦'
	},
	[128611] = {
		id = 128611,
		fmt = '#C0xF76B45#分牌：'
	},
	[128612] = {
		id = 128612,
		fmt = '1.当你#C0xF76B45#初始拿到两张点数完全一样的牌后，在第一次要牌之前，可以选择分牌操作'
	},
	[128613] = {
		id = 128613,
		fmt = '2.将两张牌分开之后，会为这2张牌再各补齐一张凑齐2堆，接下来你可以#C0xF76B45#1人操作2堆牌与魔墙人偶进行游戏'
	},
	[128614] = {
		id = 128614,
		fmt = '3.同样先由你分别操作2堆牌，接着魔墙人偶再进行操作，之后3堆牌进行比较'
	},
	[128615] = {
		id = 128615,
		fmt = '4.奖励将按照单堆牌各自进行结算哦，#C0xF76B45#若你两对牌均获得胜利或大胜利，则总计可以领取2次奖励（在结算界面统一合并发放）'
	},
	[128616] = {
		id = 128616,
		fmt = '5.注意，可#C0xF76B45#不是每次拿到相同点数的牌都进行分牌才是有利的哦，#C0x5B545B#需要思考之后再下手呢！'
	},
	[128617] = {
		id = 128617,
		fmt = '#C0xF76B45#双倍：'
	},
	[128618] = {
		id = 128618,
		fmt = '1.当你初始拿到两张点数牌，且#C0xF76B45#两张牌点数结果大于10点时（此时百变牌只能按1点进行计算），可以使用双倍操作'
	},
	[128619] = {
		id = 128619,
		fmt = '2.#C0xF76B45#点击双倍操作#C0x5B545B#之后，你将#C0xF76B45#不可再进行停牌或要牌操作，#C0x5B545B#魔墙人偶#C0xF76B45#将为你仅再发一张牌，#C0x5B545B#之后进行点数值计算与比较大小'
	},
	[128620] = {
		id = 128620,
		fmt = '3.若双倍操作并#C0xF76B45#获得胜利的，则该堆牌将为你赢得2倍的胜利奖励（在结算界面统一合并发放）'
	},
	[128621] = {
		id = 128621,
		fmt = '3.将会优先判断大胜利的情况，因此#C0xF76B45#大胜利时不出现双倍操作'
	},
	[128622] = {
		id = 128622,
		fmt = '4.分牌操作后，会对于每堆牌#C0xF76B45#分别判断是否满足双倍玩法的条件，满足则可以分别选双倍；但确认双倍操作后，将不可以再进行分牌操作'
	},
	[128701] = {
		id = 128701,
		fmt = '#C0xF76B45#【赛事竞猜规则】'
	},
	[128702] = {
		id = 128702,
		fmt = '1.万众瞩目的世界杯开踢啦！欢迎参加狂热世界杯的预测竞猜活动！'
	},
	[128703] = {
		id = 128703,
		fmt = '2.世界杯所有赛事均可进行投票竞猜，其中#C0xF76B45#非热门赛事的仅竞猜比赛结果胜平负；而热门赛事额外提供自定义的净胜球竞猜玩法'
	},
	[128704] = {
		id = 128704,
		fmt = '3.赛事#C0xF76B45#会提前开放竞猜，点击按钮可查看到具体的时间提示#C0x5B545B#竞猜截止至赛事开始前，届时可进入竞猜界面进行选择投票'
	},
	[128705] = {
		id = 128705,
		fmt = '4.竞猜胜平负玩法#C0xF76B45#使用金币进行投票，#C0x5B545B#最终投中或者未投中均#C0xF76B45#按固定的比例返还#C0x5B545B#金币，猜中还可#C0xF76B45#额外获得其他的道具奖励；#C0x5B545B#竞猜#C0xF76B45#净胜球则免费进行投票，猜中可获得奖励，#C0x5B545B#未猜中则没有奖励可领取哦'
	},
	[128706] = {
		id = 128706,
		fmt = '5.竞猜#C0xF76B45#奖励发放时间一般为隔日或当日，以本场赛事结束时间为准，比赛开始后可在赛事的竞猜奖券界面内查看到'
	},
	[128707] = {
		id = 128707,
		fmt = '6.赛事竞猜#C0xF76B45#奖励将统一存放至竞猜奖箱（活动主界面左下角）中，#C0x5B545B#请不要忘记领取哦'
	},
	[128708] = {
		id = 128708,
		fmt = '7.参与竞猜就可获得#C0xF76B45#活动限定代币——足球纪念币，#C0x5B545B#可以使用它在活动界面内的#C0xF76B45#纪念商城中兑换#C0x5B545B#其他丰厚的游戏资源'
	},
	[128709] = {
		id = 128709,
		fmt = '8.对于球队不太了解？没关系，#C0xF76B45#点击球队图标可以查看球队近期的赛事表现和荣誉成就，竞猜界面内也提供参考赔率让你可以比较全面的了解这些队伍的信息，#C0x5B545B#帮助你提高猜中几率'
	},
	[128710] = {
		id = 128710,
		fmt = '#C0xF76B45#【夺冠预测规则】'
	},
	[128711] = {
		id = 128711,
		fmt = '1.活动期间，除了可以参与赛事竞猜，还可以来参与夺冠预测哦'
	},
	[128712] = {
		id = 128712,
		fmt = '2.夺冠预测在#C0xF76B45#小组赛阶段限时开放，预测倒计时请具体查看预测入口显示，#C0x5B545B#需要在开放时间内参与预测竞猜，时间截止后将无法参与该活动'
	},
	[128713] = {
		id = 128713,
		fmt = '3.在本次世界杯32支球队中，选择1支夺冠的“种子”队伍支持Ta！#C0xF76B45#选择后，可在夺冠预测界面全程跟踪该队伍的赛程信息'
	},
	[128714] = {
		id = 128714,
		fmt = '4.待世界杯所有比赛结束后，将更新32支球队的排名信息，#C0xF76B45#你选择的球队的最终排名达到一定名次时，将可以获得预测奖励，奖励由邮件进行发放，#C0x5B545B#请注意查收'
	},
	[128715] = {
		id = 128715,
		fmt = '5.请多多参与赛事与夺冠的竞猜哦，参与或猜中的越多，即可#C0xF76B45#达成越多的狂热成就，#C0x5B545B#可以领很多奖励耶！'
	},
	[128801] = {
		id = 128801,
		fmt = '遗迹是远离城镇中心的古老建筑，包围并守护着家园与市民们'
	},
	[128802] = {
		id = 128802,
		fmt = '#C0xF76B45#【遗迹介绍】'
	},
	[128803] = {
		id = 128803,
		fmt = '1.遗迹一共有4座，#C0xF76B45#大漠遗迹、山城遗迹、苍雪遗迹与熔岩遗迹，#C0x5B545B#分别在地图的东南西北四周的位置，#C0xF76B45#点击任一遗迹即可打开玩法界面'
	},
	[128804] = {
		id = 128804,
		fmt = '2.遗迹可以升级，需要#C0xF76B45#达到升级条件以及消耗要求的建筑材料等道具后进行升级'
	},
	[128805] = {
		id = 128805,
		fmt = '3.升级遗迹会带来#C0xF76B45#属性加成奖励，升级到固定的等级还可能获得额外建设奖励，#C0x5B545B#这部分内容在玩法界面中可以直接查看'
	},
	[128806] = {
		id = 128806,
		fmt = '#C0xF76B45#【遗迹群的祝福】'
	},
	[128807] = {
		id = 128807,
		fmt = '1.当4座遗迹等级#C0xF76B45#均达到5级时，可开启遗迹群的祝福'
	},
	[128808] = {
		id = 128808,
		fmt = '2.#C0xF76B45#每日首次进入家园#C0x5B545B#时，将有概率获得1份遗迹群的祝福，祝福会自动弹出在界面上显示，若无获得，则不显示任何祝福界面内容'
	},
	[128809] = {
		id = 128809,
		fmt = '3.遗迹群的祝福涉及日常副本、冒险之路、派遣、购买体力、家园建筑加成等等其他各个玩法，或者直接获得奖励道具，当#C0xF76B45#获得玩法相关祝福后，会在对应的购买、副本、资源产出等界面显示祝福图标，#C0x5B545B#可点击进行查看'
	},
	[128810] = {
		id = 128810,
		fmt = '4.祝福有#C0xF76B45#时间或次数的限制，#C0x5B545B#请注意需要在有效时间内或按次进行使用，#C0xF76B45#时效期过后祝福将过期'
	},
	[128811] = {
		id = 128811,
		fmt = '5.同一个玩法下，若有多个祝福时，#C0xF76B45#同时仅会生效1个祝福，#C0x5B545B#按获得祝福顺序逐条生效'
	},
	[128812] = {
		id = 128812,
		fmt = '6.请注意查看各个祝福的描述要求，有一些祝福的说明文本中会#C0xF76B45#写明在相关玩法中做出提前截止，回退等操作后将不予返还'
	},
	[128901] = {
		id = 128901,
		fmt = '#L10##C0xF76B45#“阴暗迷失的丛林，感受一场芬芳飞跃的邂逅”'
	},
	[128902] = {
		id = 128902,
		fmt = '#L10##C0xF76B45#【活动规则】:'
	},
	[128903] = {
		id = 128903,
		fmt = '1.活动开启后，训练家可以控制在密林里迷失的谢米，不断飞跃，每日最多可挑战#C0xF76B45#%s#C0x5B545B#次'
	},
	[128904] = {
		id = 128904,
		fmt = '2.通过点击左半或右半屏幕，调整谢米的跳跃方向，踩中踏板不断提升高度'
	},
	[128905] = {
		id = 128905,
		fmt = '3.提升高度的同时，可以增长积分，飞跃的#C0xF76B45#高度#C0x5B545B#越高，#C0xF76B45#积分值#C0x5B545B#也就会越高'
	},
	[128906] = {
		id = 128906,
		fmt = '4.跳跃是很消耗体力的事情，所以每次挑战会有#C0xF76B45#倒计时限制#C0x5B545B#'
	},
	[128907] = {
		id = 128907,
		fmt = '5.在中途会遇到各种道具，每个道具都有自己的效果，训练家们需要合理的运用'
	},
	[128908] = {
		id = 128908,
		fmt = '6.在冒险的过程中，难免会遇到干扰者，有一些宝可梦会阻挡谢米飞跃的道路，训练家们可以把他们当做踏板，继续向上飞跃！当然，被踩落的精灵会给玩家提供#C0xF76B45#额外积分#C0x5B545B#哦'
	},
	[128909] = {
		id = 128909,
		fmt = '7.如果在冒险过程中 #C0xF76B45#倒计时结束，被阻碍的宝可梦攻击，或者被道具攻击到#C0x5B545B#，都会结束本次的冒险'
	},
	[128910] = {
		id = 128910,
		fmt = '8.每局都会根据训练家的 #C0xF76B45#本局积分成绩#C0x5B545B#来派发奖励，除此之外，通过  #C0xF76B45#累计飞跃#C0x5B545B#的积分，还可以额外领取到任务奖励'
	},
	[128911] = {
		id = 128911,
		fmt = '9.接下来详细的介绍一下游戏内会出现的物品'
	},
	[128912] = {
		id = 128912,
		fmt = '#L10##C0xF76B45#【踏板介绍】:'
	},
