	},
	[128928] = {
		id = 128928,
		fmt = '#L10##C0xF76B45#【活动规则】'
	},
	[129001] = {
		id = 129001,
		fmt = '#L10##C0xF76B45#【参与规则】'
	},
	[129002] = {
		id = 129002,
		fmt = '1.每场派对均开启百发百中射飞镖小游戏，每个派对玩家游玩次数限定，不可购买或增加'
	},
	[129003] = {
		id = 129003,
		fmt = '2.游戏结束后，#C0xF76B45#会根据计分结果发放游戏奖励，并将排名展示在派对排行榜内，可随时查看排行榜，注意排行榜仅提供展示'
	},
	[129004] = {
		id = 129004,
		fmt = '#L10##C0xF76B45#【游戏玩法】'
	},
	[129005] = {
		id = 129005,
		fmt = '1.游戏开始后，一共有#C0xF76B45#5次射镖#C0x5B545B#机会，玩家需要#C0xF76B45#用5只飞镖清零起始目标分数204分#C0x5B545B#，游戏界面中右侧计分板内会详细记录玩家每次射飞镖的分数以及当前的分差值，要注意查看哦'
	},
	[129006] = {
		id = 129006,
		fmt = '2.#C0xF76B45#按住拿着飞镖的手#C0x5B545B#后，可以进行移动，此处准心也会开始晃动，找准时机后#C0xF76B45#直接松手，飞镖即会射出#C0x5B545B#，并且自动计分'
	},
	[129007] = {
		id = 129007,
		fmt = '3.游戏中若射飞镖计分#C0xF76B45#高于204分#C0x5B545B#时，则视为#C0xF76B45#爆镖#C0x5B545B#，会#C0xF76B45#取消当前这次投掷的分数#C0x5B545B#，若#C0xF76B45#仍有射镖机会#C0x5B545B#，则会#C0xF76B45#继续游戏，射完5次飞镖后游戏进行结算#C0x5B545B#，根据当前的分差给出评价并获得奖励'
	},
	[129008] = {
		id = 129008,
		fmt = '4.游戏的诀窍在于#C0xF76B45#耐心等待，抓住准心移动比较集中的时刻，果断进行松手射出！'
	},
	[129009] = {
		id = 129009,
		fmt = '5.镖盘计分：参照下图，参照较正视镖盘的积分方式进行设定'
	},
	[129101] = {
		id = 129101,
		fmt = '#L10##C0xF76B45#【基础规则】'
	},
	[129102] = {
		id = 129102,
		fmt = '1.玩法分为#C0xF76B45#休闲模式#C0x5B545B#和#C0xF76B45#常规模式#C0x5B545B#，常规模式每天恢复1次挑战次数，次数累计上限为5次。休闲模式每天恢复5次挑战次数，次数累计上限为10次。休闲模式无法解锁成就，不会获得任何奖励'
	},
	[129103] = {
		id = 129103,
		fmt = '2.每场冒险分为#C0xF76B45#野外冒险#C0x5B545B#和#C0xF76B45#巅峰对决#C0x5B545B#两部分，完成#C0xF76B45#野外冒险#C0x5B545B#部分即视为通关，#C0xF76B45#巅峰对决#C0x5B545B#部分的对决情况会转化为积分并计入排行榜'
	},
	[129104] = {
		id = 129104,
		fmt = '3.训练家风格对应属性的卡牌会在冒险中更容易遇到'
	},
	[129105] = {
		id = 129105,
		fmt = '4.训练家会随成就等级解锁，#C0xF76B45#解锁后需要主动购买#C0x5B545B#方可使用'
	},
	[129106] = {
		id = 129106,
		fmt = '5.每个训练家有各自独立的精通等级，使用该训练家参与冒险即可获得精通值，随着精通等级的提高会提升训练家初始生命，并解锁更多的训练家技能和初始伙伴'
	},
	[129107] = {
		id = 129107,
		fmt = '6.#C0xF76B45#暂时退出#C0x5B545B#时会保留游戏进度回到主城界面。#C0xF76B45#放弃游戏#C0x5B545B#时会根据当前游戏进度立刻结算奖励'
	},
	[129108] = {
		id = 129108,
		fmt = '7.赛季结算时，还在游戏中的玩家可以继续进行游戏，但是本次游戏数据#C0xF76B45#不会计入排行榜#C0x5B545B#；新赛季开始后，旧赛季未完成的游戏进度将被废弃，#C0xF76B45#不返还挑战次数#C0x5B545B#'
	},
	[129109] = {
		id = 129109,
		fmt = '8.游戏版本更新后可能导致玩法版本不一致，会#C0xF76B45#直接放弃旧版本的游戏进度，并将挑战次数返还#C0x5B545B#'
	},
	[129110] = {
		id = 129110,
		fmt = '#L10##C0xF76B45#【玩法规则】'
	},
	[129111] = {
		id = 129111,
		fmt = '1.在除战斗阶段外的任意时刻均可打出和操作卡牌，#C0xF76B45#战斗阶段内玩家无法进行任何操作#C0x5B545B#，卡牌会自动进行战斗'
	},
	[129112] = {
		id = 129112,
		fmt = '2.精灵卡牌和装备卡牌向上拖动至出售区域松手即可出售卡牌，#C0xF76B45#任意卡牌出售时均获得1金币#C0x5B545B#'
	},
	[129113] = {
		id = 129113,
		fmt = '3.右下角事件卡区域会展示事件卡牌的信息，#C0xF76B45#持续型事件卡可以通过点击右上角叉号来出售#C0x5B545B#，即时型事件卡不可出售'
	},
	[129114] = {
		id = 129114,
		fmt = '4.每个精灵卡默认可以携带一件装备，向已经携带装备的精灵打出装备卡时，#C0xF76B45#会直接出售旧装备#C0x5B545B#获得1金币，并穿上新装备'
	},
	[129115] = {
		id = 129115,
		fmt = '5.已穿戴装备的精灵卡返回手牌时，会自动脱下身上的装备卡至手牌'
	},
	[129116] = {
		id = 129116,
		fmt = '6.给精灵穿戴两个相同的装备时，#C0xF76B45#特殊效果无法叠加生效'
	},
	[129117] = {
		id = 129117,
		fmt = '7.玩家手牌达到10张后，无法进行任何主动获得卡牌的操作（比如商店购买卡牌），此时仍可通过被动方式获得卡牌（比如部分卡牌效果）；玩家手牌达到20张后，新获得的卡牌将直接烧毁，并禁用部分可能获得新卡牌的操作'
	},
	[129118] = {
		id = 129118,
		fmt = '#L10##C0xF76B45#【战斗规则】'
	},
	[129119] = {
		id = 129119,
		fmt = '1.战斗阶段开始后，精灵会按照从左到右的顺序依次行动。如果最左侧有两只精灵，则比较这两只精灵的攻击、生命、护甲三维，总值较高者优先行动。攻击力为0的精灵无法行动'
	},
	[129120] = {
		id = 129120,
		fmt = '2.精灵攻击时，默认会选取随机敌方单位作为目标，默认索敌优先度为0。多条索敌规则冲突时，按照优先度最高的索敌规则执行'
	},
	[129121] = {
		id = 129121,
		fmt = '3.任一方场上没有精灵存在时，游戏结束。战斗失败方的训练家会受到伤害，如果玩家方训练家生命降至0，则立即结束冒险'
	},
	[129122] = {
		id = 129122,
		fmt = '4.当战斗难以分出胜负时，会判定为平局，对玩家来说，平局也视为失败'
	},
	[129123] = {
		id = 129123,
		fmt = '5.大部分非首领战斗在失败后也可以通过，但是每个章节的首领战必须获胜后才可通过'
	},
	[129124] = {
		id = 129124,
		fmt = '6.巅峰对决中每一场都会使用玩家在#C0xF76B45#野外冒险#C0x5B545B#中的通关阵容，期间获得的永久属性也无法继承到下一场巅峰对决中'
	},
	[129125] = {
		id = 129125,
		fmt = '#L10##C0xF76B45#【奖励规则】'
	},
	[129126] = {
		id = 129126,
		fmt = '1.奖励分为#C0xF76B45#常规奖励#C0x5B545B#和#C0xF76B45#排行奖励#C0x5B545B#两部分'
	},
	[129127] = {
		id = 129127,
		fmt = '2.#C0xF76B45#常规奖励#C0x5B545B#在结束任意一场#C0xF76B45#非休闲模式#C0x5B545B#游戏后立刻获得'
	},
	[129128] = {
		id = 129128,
		fmt = '3.#C0xF76B45#排行奖励#C0x5B545B#将于赛季结算时根据排行榜名次定期以邮件形式发放奖励，具体奖励规则详见排行榜界面奖励预览'
	},
	[129201] = {
		id = 129201,
		fmt = '1.星级功能可以让精灵之间的星级进行交换'
	},
	[129202] = {
		id = 129202,
		fmt = '#L10##C0xF76B45#【临时交换】'
	},
	[129203] = {
		id = 129203,
		fmt = '1.训练家挑选2个精灵放入栏位#C0xF76B45#自行开始或终止#C0x5B545B#星级交换'
	},
	[129204] = {
		id = 129204,
		fmt = '2.每个交换栏位仅能提供1对精灵的星级交换，#C0xF76B45#交换栏位对精灵的稀有度也有限制，需要注意查看哦'
	},
	[129205] = {
		id = 129205,
		fmt = '3.当交换被#C0xF76B45#终止#C0x5B545B#后，栏位会#C0xF76B45#进入冷却时间，#C0x5B545B#在冷却时间内不得再次使用'
	},
	[129206] = {
		id = 129206,
		fmt = '4.临时交换需要消耗道具，不同稀有度以及不同星级数量转换的消耗道具均可能不同，以实际交换中的显示为准'
	},
	[129207] = {
		id = 129207,
		fmt = '5.#C0xF76B45#交换期间，对精灵升星之后开放的一系列养成进行消耗道具的（升级技能、Z觉醒培养等）在交换结束后不退道具不重置，封锁以待星级再次达成'
	},
	[129208] = {
		id = 129208,
		fmt = '6.#C0xF76B45#正在交换期间的精灵不可升星，不可作为材料投入其他养成（如超进化）以及分解，也不作为完成相关任务条件的内容（如要求精灵达成一定星级的成就或勋章任务等）'
	},
	[129209] = {
		id = 129209,
		fmt = '#C0xF76B45#星级临时交换目前仅针对部分稀有度的精灵，另进行过超进化的精灵不可使用该功能，正式进行交换前，预留了一段时间供预览星级效果，请仔细进行查看'
	},
	[129231] = {
		id = 129231,
		fmt = '#L10##C0xF76B45#【永久交换】'
	},
	[129232] = {
		id = 129232,
		fmt = '1.训练家挑选2个精灵进行星级永久交换，其中至少有1个精灵需要达到8星（包括8星）以上，交换成功后不可原路退回星级'
	},
	[129233] = {
		id = 129233,
		fmt = '2.交换需要消耗道具与交换次数，不同稀有度的消耗道具可能不同，以实际交换中的显示为准'
	},
	[129234] = {
		id = 129234,
		fmt = '3.#C0xF76B45#交换次数会定期回复1次，也会不定时统一发放，发放的次数可点击进入界面右下角的领取入口进行领取'
	},
	[129235] = {
		id = 129235,
		fmt = '#C0xF76B45#星级永久交换目前仅针对部分稀有度的精灵，另进行过超进化的精灵不可使用该功能，正式进行交换前，预留了一段时间供预览星级效果，请仔细进行查看'
	},
	[129301] = {
		id = 129301,
		fmt = '#L10##C0xF76B45#【基础规则】'
	},
	[129302] = {
		id = 129302,
		fmt = '1.玩法分为#C0xF76B45#休闲模式#C0x5B545B#和#C0xF76B45#常规模式#C0x5B545B#，常规模式每天恢复1次挑战次数，次数累计上限为5次。休闲模式每天恢复5次挑战次数，次数累计上限为10次。休闲模式无法解锁成就，不会获得任何奖励'
	},
	[129303] = {
		id = 129303,
		fmt = '2.每场冒险分为#C0xF76B45#野外冒险#C0x5B545B#和#C0xF76B45#巅峰对决#C0x5B545B#两部分，完成#C0xF76B45#野外冒险#C0x5B545B#部分即视为通关，#C0xF76B45#巅峰对决#C0x5B545B#部分的对决情况会转化为积分并计入排行榜'
	},
	[129304] = {
		id = 129304,
		fmt = '3.训练家风格对应属性的卡牌会在冒险中更容易遇到'
	},
	[129305] = {
		id = 129305,
		fmt = '4.训练家会随成就等级解锁，#C0xF76B45#解锁后需要主动购买#C0x5B545B#方可使用'
	},
	[129306] = {
		id = 129306,
		fmt = '5.每个训练家有各自独立的精通等级，使用该训练家参与冒险即可获得精通值，随着精通等级的提高会提升训练家初始生命，并解锁更多的训练家技能和初始伙伴'
	},
	[129307] = {
		id = 129307,
		fmt = '6.#C0xF76B45#暂时退出#C0x5B545B#时会保留游戏进度回到主城界面。#C0xF76B45#放弃游戏#C0x5B545B#时会根据当前游戏进度立刻结算奖励'
	},
	[129308] = {
		id = 129308,
		fmt = '7.赛季结算时，还在游戏中的玩家可以继续进行游戏，但是本次游戏数据#C0xF76B45#不会计入排行榜#C0x5B545B#；新赛季开始后，旧赛季未完成的游戏进度将被废弃，#C0xF76B45#不返还挑战次数#C0x5B545B#'
	},
	[129309] = {
		id = 129309,
		fmt = '8.游戏版本更新后可能导致玩法版本不一致，会#C0xF76B45#直接放弃旧版本的游戏进度，并将挑战次数返还#C0x5B545B#'
	},
	[129310] = {
		id = 129310,
		fmt = '#L10##C0xF76B45#【玩法规则】'
	},
	[129311] = {
		id = 129311,
		fmt = '1.在除战斗阶段外的任意时刻均可打出和操作卡牌，#C0xF76B45#战斗阶段内玩家无法进行任何操作#C0x5B545B#，卡牌会自动进行战斗'
	},
	[129312] = {
		id = 129312,
		fmt = '2.精灵卡牌和装备卡牌向上拖动至出售区域松手即可出售卡牌，#C0xF76B45#任意卡牌出售时均获得1金币#C0x5B545B#'
	},
	[129313] = {
		id = 129313,
		fmt = '3.右下角事件卡区域会展示事件卡牌的信息，#C0xF76B45#持续型事件卡可以通过点击右上角叉号来出售#C0x5B545B#，即时型事件卡不可出售'
	},
	[129314] = {
		id = 129314,
		fmt = '4.每个精灵卡默认可以携带一件装备，向已经携带装备的精灵打出装备卡时，#C0xF76B45#会直接出售旧装备#C0x5B545B#获得1金币，并穿上新装备'
	},
	[129315] = {
		id = 129315,
		fmt = '5.已穿戴装备的精灵卡返回手牌时，会自动脱下身上的装备卡至手牌'
	},
	[129316] = {
		id = 129316,
		fmt = '6.给精灵穿戴两个相同的装备时，#C0xF76B45#特殊效果无法叠加生效'
	},
	[129317] = {
		id = 129317,
		fmt = '7.玩家手牌达到10张后，无法进行任何主动获得卡牌的操作（比如商店购买卡牌），此时仍可通过被动方式获得卡牌（比如部分卡牌效果）；玩家手牌达到20张后，新获得的卡牌将直接烧毁，并禁用部分可能获得新卡牌的操作'
	},
	[129318] = {
		id = 129318,
		fmt = '#L10##C0xF76B45#【战斗规则】'
	},
	[129319] = {
		id = 129319,
		fmt = '1.战斗阶段开始后，精灵会按照从左到右的顺序依次行动。如果最左侧有两只精灵，则比较这两只精灵的攻击、生命、护甲三维，总值较高者优先行动。攻击力为0的精灵无法行动'
	},
	[129320] = {
		id = 129320,
		fmt = '2.精灵攻击时，默认会选取随机敌方单位作为目标，默认索敌优先度为0。多条索敌规则冲突时，按照优先度最高的索敌规则执行'
	},
	[129321] = {
		id = 129321,
		fmt = '3.任一方场上没有精灵存在时，游戏结束。战斗失败方的训练家会受到伤害，如果玩家方训练家生命降至0，则立即结束冒险'
	},
	[129322] = {
		id = 129322,
		fmt = '4.当战斗难以分出胜负时，会判定为平局，对玩家来说，平局也视为失败'
	},
	[129323] = {
		id = 129323,
		fmt = '5.大部分非首领战斗在失败后也可以通过，但是每个章节的首领战必须获胜后才可通过'
	},
	[129324] = {
		id = 129324,
		fmt = '6.巅峰对决中每一场都会使用玩家在#C0xF76B45#野外冒险#C0x5B545B#中的通关阵容，期间获得的永久属性也无法继承到下一场巅峰对决中'
	},
	[129325] = {
		id = 129325,
		fmt = '#L10##C0xF76B45#【奖励规则】'
	},
	[129326] = {
		id = 129326,
		fmt = '1.奖励分为#C0xF76B45#常规奖励#C0x5B545B#和#C0xF76B45#排行奖励#C0x5B545B#两部分'
	},
	[129327] = {
		id = 129327,
		fmt = '2.#C0xF76B45#常规奖励#C0x5B545B#在结束任意一场#C0xF76B45#非休闲模式#C0x5B545B#游戏后立刻获得'
	},
	[129328] = {
		id = 129328,
		fmt = '3.#C0xF76B45#排行奖励#C0x5B545B#将于赛季结算时根据排行榜名次定期以邮件形式发放奖励，具体奖励规则详见排行榜界面奖励预览'
	},
	[130001] = {
		id = 130001,
		fmt = '#L10##C0xF76B45#疾行飞驰，疾斗与征战之影'
	},
	[130002] = {
		id = 130002,
		fmt = '#L10##C0xF76B45#【玩法时间】'
	},
	[130003] = {
		id = 130003,
		fmt = '1.本玩法#C0xF76B45#8#C0x5B545B#轮为一个赛季，每轮的比赛日为#C0xF76B45#每周的周五,周日,次周周三#C0x5B545B#，休赛时间为#C0xF76B45#2#C0x5B545B#周'
	},
	[130004] = {
		id = 130004,
		fmt = '2.比赛日#C0xF76B45#%s#C0x5B545B#锁定报名公会，并匹配对战公会，匹配将于#C0xF76B45#%s#C0x5B545B#结束并统一展示，两个公会为一个对战组'
	},
	[130005] = {
		id = 130005,
		fmt = '3.若在#C0xF76B45#%s#C0x5B545B#前公会全员少于#C0xF76B45#%s#C0x5B545B#人，则本场视为放弃参与比赛'
	},
	[130006] = {
		id = 130006,
		fmt = '4.#C0xF76B45#%s#C0x5B545B#为选择上阵阵容和会长/副会长调整参赛人员时间'
	},
	[130007] = {
		id = 130007,
		fmt = '5.#C0xF76B45#%s#C0x5B545B#锁定参赛公会成员，参赛成员可进入战场查看，#C0xF76B45#%s#C0x5B545B#正式开赛'
	},
	[130008] = {
		id = 130008,
		fmt = '6.据点模式比赛时长为#C0xF76B45#20#C0x5B545B#分钟，资源模式比赛时长为#C0xF76B45#30#C0x5B545B#分钟'
	},
	[130009] = {
		id = 130009,
		fmt = '7.两种结算模式提前结束的公会需统一等待%s结算积分和发放奖励，在统一结束前不可调整精灵阵容与人员分配'
	},
	[130010] = {
		id = 130010,
		fmt = '8.赛季末最后一次比赛结束后将统计本赛季积分排名派发最终奖励'
	},
	[130011] = {
		id = 130011,
		fmt = '#L10##C0xF76B45#【报名规则】'
	},
	[130012] = {
		id = 130012,
		fmt = '1.分配到同一跨服组内的公会在满足相关参与前提后可以参与报名，贵族3的会长/副会长将自动报名参赛'
	},
	[130013] = {
		id = 130013,
		fmt = '2.会长/副会长拥有定夺是否参与本赛季战斗的权利'
	},
	[130014] = {
		id = 130014,
		fmt = '3.若会长/副会长在未选择公会报名，则会内成员无法参与本场战斗。会长/副会长选择报名后，会内满足参赛条件的玩家全员参赛'
	},
	[130015] = {
		id = 130015,
		fmt = '4.公会报名首次报名后，本赛季都会处于参赛状态。若本公会活跃玩家人数小于#C0xF76B45#3#C0x5B545B#人，则报名无效'
	},
	[130016] = {
		id = 130016,
		fmt = '5.本玩法限定参与人数，会长/副会长可做战术调整，决定报名成员的上阵'
	},
	[130017] = {
		id = 130017,
		fmt = '6.若开赛前参赛区人数未满，系统将会从禁赛区内按照战力顺序自动补充人员到参赛区'
	},
	[130018] = {
		id = 130018,
		fmt = '#L10##C0xF76B45#【基础玩法】'
	},
	[130019] = {
		id = 130019,
		fmt = '1.公会人员报名后，可在#C0xF76B45#%s#C0x5B545B#前布阵自己两队参战精灵，每队#C0xF76B45#6#C0x5B545B#只'
	},
	[130020] = {
		id = 130020,
		fmt = '2.#C0xF76B45#%s#C0x5B545B#后不可更改上阵精灵，仅能调整先手上阵阵容和后手上阵'
	},
	[130021] = {
		id = 130021,
		fmt = '3.战场布局为双方大本营和多个据点（据点数量与不同主题相关），据点初始状态为未占领领地'
	},
	[130022] = {
		id = 130022,
		fmt = '4.玩家可选择要前往的据点，并按照两点之间的固定线路行走，行走过程和据点过程都会消耗相应的自然时间'
	},
	[130023] = {
		id = 130023,
		fmt = '5.每个据点都拥有不同的增益，驻守在内的玩家可获得增益效果'
	},
	[130024] = {
		id = 130024,
		fmt = '6.据点会产出资源，不同的据点产出的资源数量不同'
	},
	[130025] = {
		id = 130025,
		fmt = '7.双方玩家可攻打对方占领的的据点，当占领方无人驻守据点，则攻打方可消耗自然时间占领'
	},
	[130026] = {
		id = 130026,
		fmt = '8.当双方玩家在路径相交或相遇后，开始战斗，胜利的一方可按照所选路线继续行走，失败的一方会更换下一组队伍从营地出发'
	},
	[130027] = {
		id = 130027,
		fmt = '9.当玩家两只队伍全部阵亡后，将重返主营地复活，需消耗一定的自然时间，复活次数不限制，复活时长会根据自身死亡次数有所延长'
	},
	[130028] = {
		id = 130028,
		fmt = '10.每#C0xF76B45#6#C0x5B545B#分钟将在随机道路上出现地鼠，地鼠会携带增益在出现路径上反复移动，当触碰到地鼠后将会获得携带的增益效果'
	},
	[130029] = {
		id = 130029,
		fmt = '11.在地鼠出现后的#C0xF76B45#2#C0x5B545B#分钟后，若没有一方玩家前往获取，地鼠将携带着增益消失'
	},
	[130030] = {
		id = 130030,
		fmt = '12.本次未参与战斗或在备赛区的玩家可进入战场观战，查看战局'
	},
	[130031] = {
		id = 130031,
		fmt = '#L10##C0xF76B45#【胜利条件】'
	},
	[130032] = {
		id = 130032,
		fmt = '1.胜利条件分为两种形式，#C0xF76B45#据点形式#C0x5B545B#和#C0xF76B45#资源形式#C0x5B545B#，不同主题对应的胜利条件不同'
	},
	[130033] = {
		id = 130033,
		fmt = '2.资源形式胜利条件：'
	},
	[130034] = {
		id = 130034,
		fmt = '当某方产出的总资源量达到#C0xF76B45#%s#C0x5B545B#后，可不计算倒计时，直接获得胜利'
	},
	[130035] = {
		id = 130035,
		fmt = '提前胜利条件：当某方占领据点数量达到总据点数量的#C0xF76B45#%s#C0x5B545B#，且持续#C0xF76B45#%s#C0x5B545B#秒未被对方占领时，可不计算倒计时和资源量，直接获取胜利'
	},
	[130036] = {
		id = 130036,
		fmt = '当以上两个条件未满足时，则倒计时结束后根据双方资源量判断胜负'
	},
	[130037] = {
		id = 130037,
		fmt = '3.据点形式胜利条件：'
	},
	[130038] = {
		id = 130038,
