	[133103] = {
		id = 133103,
		fmt = '2.天气类型分为普通天气、高级天气、特殊天气（如乱流），特殊天气不可在布阵界面中选择'
	},
	[133104] = {
		id = 133104,
		fmt = '3.若玩家未手动选择天气，系统将自动优先选择高级天气，若级别相同，则优先选择上阵精灵与天气类型相同属性的单位数量较多一方，上述条件均一样时，随机选择'
	},
	[133105] = {
		id = 133105,
		fmt = '4.单方阵营同时只能生效一种天气效果，且部分天气存在升级效果'
	},
	[133106] = {
		id = 133106,
		fmt = '5.双方阵营的天气存在压制，共存两种模式'
	},
	[133107] = {
		id = 133107,
		fmt = '6.天气携带者死亡后，对应天气消失，此时若之前被克制的天气的天气携带者仍存活，则将继续生效该天气'
	},
