	},
	[133139] = {
		id = 133139,
		fmt = '#Ibattle/weather_icon/icon_luanliu.png-80-80# 【乱流】：特殊天气，双方所有天气效果会暂时失效；己方飞行系精灵提升6%速度和15%闪避（电系精灵无视乱流闪避），受到属性克制效果降低50%'
	},
	[133140] = {
		id = 133140,
		fmt = '相关精灵：#Iconfig/portrait/speedranktouxiang/img_384_cjlkz@.png-60-60#'
