		id = 133142
	},
	[134001] = {
		id = 134001,
		fmt = '1.又一店铺上新！#C0xF76B45#返利商店火爆来袭！'
	},
	[134002] = {
		id = 134002,
		fmt = '2.返利商店中使用#C0xF76B45#精灵纪念币#C0x5B545B#进行道具兑换，精灵纪念币可以通过#C0xF76B45#充值#C0x5B545B#行为获得'
	},
	[134003] = {
		id = 134003,
		fmt = '3.#C0xF76B45#充值被计入贵族至尊特权经验的项目，将可获得精灵纪念币，特权经验与纪念币的比例为10:1，该内容与充值获得的额外钻石（比如充值双倍，月卡持续每日可获得钻石奖励等）无关'
	},
	[134004] = {
		id = 134004,
		fmt = '4.充值成功后，会#C0xF76B45#立即获得精灵纪念币，#C0x5B545B#将#C0xF76B45#显示在恭喜获得界面上，#C0x5B545B#请训练家们仔细查看哦'
	},
	[134005] = {
		id = 134005,
		fmt = '5.商店中的商品有需要达到一定的贵族或至尊等级才可购买的，各商品设定不同，请仔细查看商品列表上的文本内容'
	},
	[134006] = {
		id = 134006,
		fmt = '6.商品还可能在一定时间内或者永久限制购买数量，各商品设定不同，请支持查看商品列表上的文本内容'
	},
	[135001] = {
		id = 135001,
		fmt = '#L10##C0xF76B45#【团队纹章】'
	},
	[135002] = {
		id = 135002,
		fmt = '1.根据精灵的元素属性，共存在#C0xF76B45#18#C0x5B545B#种不同的纹章'
	},
	[135003] = {
		id = 135003,
		fmt = '2.每个纹章都拥有多个阶段，放置本系精灵后，会按照放置的精灵自动解锁满足的阶段，并获得阶段增益'
	},
	[135004] = {
		id = 135004,
		fmt = '3.阶段解锁条件主参考#C0xF76B45#本系#C0x5B545B#放置精灵的#C0xF76B45#星级，稀有度和数量#C0x5B545B#'
	},
	[135005] = {
		id = 135005,
		fmt = '4.当放置的精灵在上述三个条件发生变动后，可能会导致阶段同步变动（新解锁阶段效果或已解锁阶段失效）'
	},
	[135006] = {
		id = 135006,
		fmt = '5.当有条件更优的本系精灵时，可手动调整或使用一键放置调整'
	},
	[135007] = {
		id = 135007,
		fmt = '6.#C0xF76B45#阶段要求内的稀有度非向下兼容#C0x5B545B#'
	},
	[135008] = {
		id = 135008,
		fmt = '7.#C0xF76B45#放置的精灵可正常入队参战#C0x5B545B#'
	},
	[135009] = {
		id = 135009,
		fmt = '#L10##C0xF76B45#【放置筛选】'
	},
	[135010] = {
		id = 135010,
		fmt = '1.可放置的精灵会筛选玩家自身背包内#C0xF76B45#同一进化链星级最高的一只#C0x5B545B#'
	},
	[135011] = {
		id = 135011,
		fmt = '2.双属性精灵仅能生效在一种元素纹章内'
	},
	[135012] = {
		id = 135012,
		fmt = '#L10##C0xF76B45#【纹章基础属性增益】'
	},
	[135013] = {
		id = 135013,
		fmt = '基础属性增益生效于背包内本系全部精灵'
	},
	[135014] = {
		id = 135014,
		fmt = '#L10##C0xF76B45#【纹章上阵效果增益】'
	},
	[135015] = {
		id = 135015,
		fmt = '1.纹章解锁上阵效果增益后，即可在部分玩法内上阵该纹章'
	},
	[135016] = {
		id = 135016,
		fmt = '2.纹章上阵效果仅生效于本系的上阵精灵，且队伍#C0xF76B45#仅可上阵2个纹章光环#C0x5B545B#'
	},
	[135017] = {
		id = 135017,
		fmt = '3.若上阵双属性精灵的属性与上阵的纹章属性一致，则精灵可获得两种纹章光环的加成'
	},
	[135018] = {
		id = 135018,
		fmt = '4.纹章上阵效果增益非叠加，仅生效已解锁更高阶段的上阵效果增益'
	},
	[135101] = {
		id = 135101,
		fmt = '1、30-67元订阅产品购买或续订送价值99元满减券:'
	},
	[135102] = {
		id = 135102,
		fmt = '“12-6”、“30-8”满减券各一张，有效期一周'
	},
	[135103] = {
		id = 135103,
		fmt = '“60-15”、“88-25”、“168-45”满减券各一张，有效期两周'
	},
	[135104] = {
		id = 135104,
		fmt = '2、68元以上订阅产品购买或续订送价值200元满减券:'
	},
	[135105] = {
		id = 135105,
		fmt = '“88-25”满减券一张，有效期一周'
	},
	[135106] = {
		id = 135106,
		fmt = '“30-15”、“128-30”“188-50”“328-80”满减券各一张，有效期两周'
	},
	[135107] = {
		id = 135107,
		fmt = '3、购买多个档位订阅商品，每个档位奖励可获得一次。'
	},
	[135108] = {
		id = 135108,
		fmt = '4、支付金额必须大于0.01元才能获得奖励。'
	},
	[135201] = {
		id = 135201,
		fmt = '1.在鹊桥相会活动界面中完成任务、参与小游戏来获得飞鸢，获得的飞鸢达到一定数量时，可以领取超棒的活动奖励！'
	},
	[135202] = {
		id = 135202,
		fmt = '2.所有活动界面中获得的飞鸢将自动进行计数，无需训练家手动整理'
	},
	[135203] = {
		id = 135203,
		fmt = '3.收集飞鸢每次达到要求的数量时，可以进行乞巧哦，乞巧将获得不同的随机奖励'
	},
	[135204] = {
		id = 135204,
		fmt = '4.活动结束后，补发最后一天任务以及收集飞鸢进度未领取奖励，其他奖励不计，且时间截止后的寻找比翼鸟游戏不获得奖励，请训练家注意活动时间，及时游玩活动内容'
	},
	[135251] = {
		id = 135251,
		fmt = '1.用你明亮的眼眸找寻花色各异的比翼鸟吧！'
	},
	[135252] = {
		id = 135252,
		fmt = '2.游戏开始后，在屏幕中间区域会出现许多对比翼鸟，每一对比翼鸟的颜色和样式都不同，上方也会出现几对比翼鸟，需要你尽快在中间区域中找到与上方完全对应的比翼鸟'
	},
	[135253] = {
		id = 135253,
		fmt = '3.游戏以关卡的形式出现，每个关卡中找到所有比翼鸟后自动进入下一关，在游戏总时长归零之前，请尽量多闯关卡吧，闯关数越多，奖励会越好哦'
	},
	[135254] = {
		id = 135254,
		fmt = '4.每局游戏将有3次点错机会，多于3次点错将会立即结束游戏，请你仔细观察比翼鸟~'
	},
	[135301] = {
		id = 135301,
		fmt = '与精灵缔结契约，让Ta变得更强力吧'
	},
	[135302] = {
		id = 135302,
		fmt = '#L10##C0xF76B45#【契约介绍】'
	},
	[135303] = {
		id = 135303,
		fmt = '1.契约有不同品质与类型的设定，可以带来属性以及战斗中各方面的加成内容'
	},
	[135304] = {
		id = 135304,
		fmt = '2.契约可以进行升级，每升级到固定的等级时，需要进行突破拓展下一阶段的等级之后再行升级'
	},
	[135305] = {
		id = 135305,
		fmt = '3.契约可被重生，#C0xF76B45#在界面-获取入口中获得的契约无法被分解或用作其他契约的升级、突破的材料被消耗'
	},
	[135306] = {
		id = 135306,
		fmt = '4.#C0xF76B45#部分契约与契约之间可触发羁绊，即装配在同一个精灵身上之后，羁绊效果生效，可为精灵带来额外的效果加持'
	},
	[135307] = {
		id = 135307,
		fmt = '#L10##C0xF76B45#【精灵装配】'
	},
	[135308] = {
		id = 135308,
		fmt = '1.稀有及以上的精灵可装配契约，具体可在获得精灵后，来到契约界面中进行选择查看'
	},
	[135309] = {
		id = 135309,
		fmt = '2.#C0xF76B45#每个精灵设定有契约装配栏位，栏位同样也有类型的设定，需要装配同类型的契约，且相同契约重复装配在一个精灵上，装配对品质不做设定'
	},
	[135310] = {
		id = 135310,
		fmt = '3.根据精灵稀有度的不同，装备契约的栏位数量也不相同'
	},
	[135311] = {
		id = 135311,
		fmt = '4.#C0xF76B45#精灵的栏位需要达成解锁条件之后方可解锁后使用，若已解锁栏位后，因为精灵其他养成内容发生变化的，栏位将再次封锁，已装配的契约会卸下，等待再次满足条件后开启，若消耗资源解锁的栏位，不会再次要求消耗资源'
	},
	[135312] = {
		id = 135312,
		fmt = '5.#C0xF76B45#当精灵因超进化而变化稀有度时，精灵栏位的数量与设定可能会发生变化，变化后，会保留与之前相同的栏位的装配信息，不同的栏位会再次封锁，已装配的契约会卸下，此处在之前解锁时消耗资源解锁栏位，则资源会进行返还，请前往邮箱领取'
	},
	[135401] = {
		id = 135401,
		fmt = '1.口袋世界可以随你心意变化冒险”速度“了！'
	},
	[135402] = {
		id = 135402,
		fmt = '2.在时空加速中，点击加号（+）、减号（-）按钮可以调整加速倍率，点击开启或暂停来使用加速倍率'
	},
	[135403] = {
		id = 135403,
		fmt = '3.#C0xF76B45#一些依赖时间计算的玩法和界面中无法使用加速器哦，在该界面时，加速效果会自动停止，待退出该界面后会重新生效的'
	},
	[135404] = {
		id = 135404,
		fmt = '4.达成要求的条件后，可以扩展最高加速倍率哦：'
	},
	[135501] = {
		id = 135501,
		fmt = '1.精灵训练师可以通过重生系统，将自己拥有的契约之章还原至初始状态'
	},
	[135502] = {
		id = 135502,
		fmt = '2.契约之章的重生的内容，包括：契约之章的强化等级以及突破养成'
	},
	[135503] = {
		id = 135503,
		fmt = '3.契约之章重生后，将返还100%的强化以及突破中消耗的养成资源，注意若使用过已养成的契约之章进行升级的，重生后不会返还该契约之章，会对应返还经验道具'
	},
	[135504] = {
		id = 135504,
		fmt = '4.契约之章重生需要消耗钻石，钻石消耗上限为100#Icommon/icon/icon_diamond.png-56-56#'
	},
	[135601] = {
		id = 135601,
		fmt = '1.活动期间，可以消耗道具“捞”一把，有机会获得称心好礼~'
	},
	[135602] = {
		id = 135602,
		fmt = '2.可能抽到的超幸运奖励在穿着熊身后的泳池公告板上进行展示，点击下方更多奖励按钮可以查看具体的奖励内容哦'
	},
	[135603] = {
		id = 135603,
		fmt = '3.活动期间，将会记录所有捞奖的次数，达成任务还可以额外领取奖励哦，祝你好运'
	},
	[135701] = {
		id = 135701,
		fmt = '1.在卡牌图鉴中可以浏览查看卡牌效果，支持筛选和搜索功能'
	},
	[135702] = {
		id = 135702,
		fmt = '2.在一局#C0xF76B45#正式挑战模式#C0x5B545B#中#C0xF76B45#从手牌打出到场上#C0x5B545B#的卡牌会在本局结束后点亮图鉴并解锁点亮奖励'
	},
	[135703] = {
		id = 135703,
		fmt = '3.打出4星精灵卡也可以直接解锁1星和2星的点亮奖励哦'
	},
	[135801] = {
		id = 135801,
		fmt = '#L10##C0xF76B45#碰撞！击破！擦出全场最明艳的花火！'
	},
	[135802] = {
		id = 135802,
		fmt = '#L10##C0xF76B45#【活动规则】:'
	},
	[135803] = {
		id = 135803,
		fmt = '1.由宝可梦研发中心研制的拟态宝可梦方块，会出现在固定的正方形边框内'
	},
	[135804] = {
		id = 135804,
		fmt = '2.边框对应四种宝可梦方块的颜色，训练家需要在中间区域通过#C0xF76B45#上下左右#C0x5B545B#四个方向滑动，将#C0xF76B45#与边同色#C0x5B545B#的宝可梦方块销毁'
	},
	[135805] = {
		id = 135805,
		fmt = '3.当滑动路径上有阻碍前行的与边异色的宝可梦方块时，由于能量互斥，与边同色的宝可梦也不会移动'
	},
	[135806] = {
		id = 135806,
		fmt = '4.当遇到无法消除的情况，可以尝试使用#C0xF76B45#旋转#C0x5B545B#功能，内部的宝可梦方块会#C0xF76B45#顺时针旋转90°#C0x5B545B#'
	},
	[135807] = {
		id = 135807,
		fmt = '5.中间方块消除后会获得积分，当中间方块#C0xF76B45#全部消除#C0x5B545B#后会进入到下一轮，并#C0xF76B45#恢复一定的倒计时#C0x5B545B#，当倒计时为0时游戏结束并结算最后积分'
	},
	[135808] = {
		id = 135808,
		fmt = '6.每场累计的积分达到一些节点后，可领取累计积分奖励！'
	},
	[135809] = {
		id = 135809,
		fmt = '7.每日免费次数用尽后可额外购买挑战次数，继续挑战。免费次数将在次日刷新'
	},
	[135901] = {
		id = 135901,
		fmt = '#L10##C0xF76B45#【基础规则】'
	},
	[135902] = {
		id = 135902,
		fmt = '#L10##C0xF76B45#温馨提示：以太乐园（无尽模式）的积分区别于普通模式'
	},
	[135903] = {
		id = 135903,
		fmt = '1.以太乐园（无尽模式）每期可以挑战一定次数'
	},
	[135904] = {
		id = 135904,
		fmt = '2.每期玩法开启重置挑战进度和排名情况'
	},
	[135905] = {
		id = 135905,
		fmt = '3.排名奖励会在重置时以邮件发放'
	},
	[135906] = {
		id = 135906,
		fmt = '#L10##C0xF76B45#【玩法规则】'
	},
	[135907] = {
		id = 135907,
		fmt = '1.以太乐园（无尽模式）设有主题玩法，#C0xF76B45#主题玩法以期为单位，每期都会进行主题更换'
	},
	[135908] = {
		id = 135908,
		fmt = '2.以太乐园（无尽模式）会根据主题模式给怪物增加不同的额外技能效果，且额外技能效果会随着层数提升和怪物类型（简单、普通、困难、霸主）的增强而增强'
	},
	[135909] = {
		id = 135909,
		fmt = '3.以太乐园（无尽模式）新增了备选阶段，备选阵容分为主阵容和预备卡牌，确定备战进入玩法后，玩家只能使用这些精灵进行挑战，请谨慎选择备战精灵'
	},
	[135910] = {
		id = 135910,
		fmt = '4.预备卡牌分为基础槽位和战斗力解锁槽位，战斗力解锁槽位会根据主城战斗力自动解锁对应的槽位'
	},
	[135911] = {
		id = 135911,
		fmt = '5.以太乐园（无尽模式）战斗中#C0xF76B45#携带道具、符文、性格、芯片、契约、天气等#C0x5B545B#系统的属性及效果都不会带入，公会技能、天赋技能、探险器属性等会修正到一定水平线，系统会根据玩家上阵卡牌的最高星级和最高Z觉醒阶段增加额外属性'
	},
	[135912] = {
		id = 135912,
		fmt = '6.祝福类选项会给战斗和提供大量的帮助'
	},
	[135913] = {
		id = 135913,
		fmt = '7.祝福类效果分为：战斗流派祝福和属性祝福，当同一战斗流派祝福数量达到3，5，8时可解锁额外流派羁绊祝福'
	},
	[135914] = {
		id = 135914,
		fmt = '8.宝箱类的选项可以获得一些奖励'
	},
	[135915] = {
		id = 135915,
		fmt = '9.事件类的选项会随机或根据选择出现对应的结果，某些特定事件可以获取特定的流派祝福'
	},
	[135916] = {
		id = 135916,
		fmt = '10.补给品：进入玩法和达到特定层数系统会发放一定数量的补给品可在战斗外使用'
	},
	[135917] = {
		id = 135917,
		fmt = '#L10##C0xF76B45#【碾压规则】'
	},
	[135918] = {
		id = 135918,
		fmt = '1.每种主题单独保存玩家可碾压的层数'
	},
	[135919] = {
		id = 135919,
		fmt = '2.每种不同的主题，上次通关和历史通关层数达到一定层数后，可在后续挑战中碾压一定层数的关卡'
	},
	[136001] = {
		id = 136001,
		fmt = '1.可以使用#C0xF76B45#好运券进行抽奖，好运券可以#C0xF76B45#通过本活动页面中的其他活动内容中，领取任务奖励或购买礼包获得'
	},
	[136002] = {
		id = 136002,
		fmt = '2.活动中左侧卡片中的格子内是可以抽到的奖励展示，奖励中#C0xF76B45#最亮眼的要属高能奖励，它被固定显示在左上角第1个格子中，可一定不能错过它'
	},
	[136003] = {
		id = 136003,
		fmt = '3.抽奖可以抽到高能奖励，若一直未抽中也不要灰心，#C0xF76B45#一次次的抽奖会不断累积高能值，高能值越高抽中高能奖励的概率就越大，而当它积攒满时，下一次可直接抽中高能奖励哦'
	},
	[136004] = {
		id = 136004,
		fmt = '4.#C0xF76B45#每次抽中高能奖励之后，卡片中每个格子上的奖励都会进行随机刷新，而高能奖励也会进行变化，也可以选择手动进行刷新，#C0x5B545B#手动刷新除了每日重置给予免费次数以外，也可进行购买'
	},
	[136005] = {
		id = 136005,
		fmt = '5.抽奖卡片左侧将直接显示本次活动所有会出现的高能奖励道具情况，点击奖励预览则可以查看本次活动所有会出现的奖励道具情况'
	},
	[136006] = {
		id = 136006,
		fmt = '6.#C0xF76B45#抽奖次数（指在活动期间抽奖的总次数）达到任务要求后，#C0x5B545B#可以在好运簿中领取对应的任务奖励'
	},
	[136101] = {
		id = 136101,
		fmt = '在游戏中充值即可获得VIP经验。 购买钻石或超值包都是增加VIP经验的一种方式。 充值 ￥6 即可获得 60 VIP经验，与钻石数量相同。 另外，如果您购买价值 ￥6 的超值包，您还将获得 60 VIP经验。'
	},
	[136201] = {
		id = 136201,
		fmt = '1.通过挑战消耗体力，累计的消耗的体力越多，解锁的战令奖励越丰厚'
	},
	[136202] = {
		id = 136202,
		fmt = '2.购买豪华版战令，可以解锁更多额外的超值奖励'
	},
	[136203] = {
		id = 136203,
		fmt = '3.每期购买的豪华版战令仅在本期活动内生效，下次活动需要重新购买；累计的体力消耗值也会在活动结束时清零'
	},
	[136204] = {
		id = 136204,
		fmt = '4.战令活动结束时，所有未领取的奖励将通过邮件发送'
	},
	[136301] = {
		id = 136301,
		fmt = '1.跨服战令开启后，将在相关跨服玩法的奖励内额外增加跨服战令经验道具'
	},
	[136302] = {
		id = 136302,
		fmt = '2..跨服战令经验道具获取后直接填充到战令内，提升等级。获取的战令经验数量越多，等级解锁的战令奖励越丰厚'
	},
	[136303] = {
		id = 136303,
		fmt = '3.在当期#C0xF76B45#跨服战令结束#C0x5B545B#后，未领取的跨服战令经验道具也会一并#C0xF76B45#隐藏清空#C0x5B545B#。部分邮件奖励，玩法奖励内的跨服战令经验道具要及时领取'
	},
	[136304] = {
		id = 136304,
		fmt = '4.购买豪华版战令，可以解锁更多额外的超值奖励'
	},
	[136305] = {
		id = 136305,
		fmt = '5.每期购买的豪华版战令仅在本期活动内生效，下次活动需要重新购买；跨服战令等级也会在活动结束时清零'
	},
	[136306] = {
		id = 136306,
		fmt = '6.战令活动结束时，所有未领取的奖励将通过邮件发送'
	},
	[136307] = {
		id = 136307,
		fmt = '7.战令经验获取途径'
	},
	[136308] = {
		id = 136308,
		fmt = '（1）跨服石英大会-排名奖励'
	},
	[136309] = {
		id = 136309,
		fmt = '（2）跨服竞技场-每日奖励，7日奖励，最终奖励'
	},
	[136310] = {
		id = 136310,
		fmt = '（3）对战竞技场-每日前6场对战奖励'
	},
	[136401] = {
		id = 136401,
		fmt = '#C0xFF5B545B#1.每周成功挑战道馆副本，可累计挑战次数(#C0xF76B45#挑战道馆玩家不计次数#C0xFF5B545B#)；累计的挑战次数越多，解锁的战令奖励越丰厚'
	},
	[136402] = {
		id = 136402,
		fmt = '2.购买豪华版战令，可以解锁更多额外的超值奖励'
	},
	[136403] = {
		id = 136403,
		fmt = '3.每期购买的豪华版战令仅在本期活动内生效，下次活动需要重新购买；累计的副本挑战次数也会在活动结束时清零'
	},
	[136404] = {
		id = 136404,
		fmt = '4.战令活动结束时，所有未领取的奖励将通过邮件发送'
	},
	[136501] = {
		id = 136501,
		fmt = '1.启示之塔轮回不止，好礼不停！'
	},
	[136502] = {
		id = 136502,
		fmt = '2.启动启示之塔需要消耗活动道具，#C0xF76B45#在一轮之内，随着抽奖次数不同消耗数量会有变化，#C0x5B545B#请注意查看'
	},
	[136503] = {
		id = 136503,
		fmt = '3.启示之塔的奖励从最上层开始逐层分为一等奖、二等奖、三等奖、四等奖，#C0xF76B45#每层上每个格子的奖励每轮仅可被抽中1次'
	},
	[136504] = {
		id = 136504,
		fmt = '4#C0xF76B45#.一、二等奖需要自行选择#C0x5B545B#心仪的道具内容，未选择前不可启动启示之塔，但别担心，在#C0xF76B45#你没有抽到它们之前，是可以随意进行变更的'
	},
	[136505] = {
		id = 136505,
		fmt = '5.启示之塔会有多轮奖励，若训练家抽到一等奖，便可获得直接进入下一轮的机会，若选择直进下一轮，则不可再回到本轮抽奖；也可以留在本轮抽奖，当本轮所有奖励全数获得后，则会自动进入下一轮启示之塔'
	},
	[136601] = {
		id = 136601,
		fmt = '#F40##L10#助战规则：#L0#\n1.激活助战后可解锁后续的助战养成，并可以在队伍中上阵助战精灵，精灵们会使用他们独特的助战技在战场上帮助您'
	},
	[136602] = {
		id = 136602,
		fmt = '2.提升助战精灵等级可提升团队属性并提升助战技能基础效果数值，可升级的上限由精灵的助战突破阶段决定'
	},
	[136603] = {
		id = 136603,
		fmt = '3.提升助战精灵突破阶段可逐步解锁精灵专属助战技能的阶段效果，并提供全队属性'
	},
	[136604] = {
		id = 136604,
		fmt = '4.部分精灵存在觉醒功能，完成激活条件后可后续培养，会为精灵的助战技能提供额外的效果，并提供全队属性！'
	},
	[136605] = {
		id = 136605,
		fmt = '5.同进化系列精灵的助战培养共享'
	},
	[136606] = {
		id = 136606,
		fmt = '6.#C0xF76B45#上阵助战#C0x5B545B#精灵后，会为上阵队伍提供助战精灵专属的#C0xF76B45#助战战力#C0x5B545B#，#C0xF76B45#历史最高战力#C0x5B545B#会增加#C0xF76B45#主城上阵#C0x5B545B#助战位的精灵助战战力'
	},
	[136607] = {
		id = 136607,
		fmt = '7.助战额外说明：'
	},
	[136608] = {
		id = 136608,
		fmt = '（1）重置将返还100%养成资源'
	},
	[136609] = {
		id = 136609,
		fmt = '（2）在助战阵容中精灵不允许重置'
	},
	[136610] = {
		id = 136610,
		fmt = '（3）在助战阵容中的精灵不能被重生/分解，需手动下阵后才可操作'
	},
	[136611] = {
		id = 136611,
		fmt = '（4）若背包内已养成的助战精灵未重置且全系列被分解，则助战增益失效，重新获取且达到激活条件后自动激活原助战养成'
	},
	[136612] = {
		id = 136612,
		fmt = '（5）助战为协助队伍作战，所以助战上阵#C0xF76B45#不受限于#C0x5B545B#部分玩法中对于#C0xF76B45#精灵上阵数量限制#C0x5B545B#的要求'
	},
	[136701] = {
		id = 136701,
		fmt = '#L10##C0xF76B45#舞台亦真实亦荒诞，亦自由亦拘束，亦搭配亦离析。帷幕马戏团内的好戏，不容错过'
	},
	[136702] = {
		id = 136702,
		fmt = '#L10##C0xF76B45#【入团时间】'
	},
	[136703] = {
		id = 136703,
		fmt = '1.本玩法赛季持续时间为#C0xF76B45#1#C0x5B545B#周，休赛时间为#C0xF76B45#2#C0x5B545B#周'
	},
	[136704] = {
		id = 136704,
		fmt = '2.正式开团为赛季第一天#C0xF76B45#10:00#C0x5B545B#，闭团为赛季最后一天#C0xF76B45#22:00#C0x5B545B#，期间时间都可以参与对战'
	},
	[136705] = {
		id = 136705,
		fmt = '3.本团开启后有固定的场地清扫及维护时间，每晚#C0xF76B45#22:00~次日10:00#C0x5B545B#将无法挑战'
	},
	[136706] = {
		id = 136706,
		fmt = '#L10##C0xF76B45#【入场须知】'
	},
	[136707] = {
		id = 136707,
		fmt = '1.玩家等级需要达到#C0xF76B45#85#C0x5B545B#级，开服天数需#C0xF76B45#60#C0x5B545B#天'
	},
	[136708] = {
		id = 136708,
		fmt = '2.本团主要分为三大舞台：#C0xF76B45#元素杂糅，阵容乱奏，荒诞把戏#C0x5B545B#'
	},
	[136709] = {
		id = 136709,
		fmt = '3.每赛季舞台都会生成一种主题效果，您可以选择更适合自己的舞台，也可以多个舞台同时参演'
	},
	[136710] = {
		id = 136710,
		fmt = '4.在首次进入某个舞台时需布阵后才可入场，上阵时可以利用舞台的主题效果进行布阵，同时有的舞台也必须严格按照规定进行布阵'
	},
	[136711] = {
		id = 136711,
		fmt = '5.布阵进入战场后，会保存阵容作为您的初始进攻/防守阵容，当然在舞台的主界面也可以自由调试'
	},
	[136712] = {
		id = 136712,
		fmt = '6.非首次进入舞台则会跳过布阵界面，直接进入主舞台'
	},
	[136713] = {
		id = 136713,
		fmt = '7.每个舞台都有多个跨服而来的参演者，可以对他们发起挑战。每日有固定的挑战次数，次数每天#C0xF76B45#玩法开启时#C0x5B545B#重置'
	},
	[136714] = {
		id = 136714,
		fmt = '8.注意：三个舞台共用每日挑战次数，请合理分配'
	},
	[136715] = {
		id = 136715,
		fmt = '9.玩家可以手动刷新可挑战对手，手动刷新有免费次数，当免费次数使用完之后，需要花费钻石刷新对手，手动刷新免费次数每天#C0xF76B45#玩法开启时#C0x5B545B#进行重置'
	},
	[136716] = {
		id = 136716,
		fmt = '#L10##C0xF76B45#【舞台须知】'
	},
	[136717] = {
		id = 136717,
		fmt = '1.舞台主题千变万化，不到最后一刻都无法知晓胜利的天平会向谁偏转'
	},
	[136718] = {
		id = 136718,
		fmt = '2.玩家主动挑战对手，若战斗胜利，则与对方互换排名；若战斗失败，则排名不进行变化'
	},
	[136719] = {
		id = 136719,
		fmt = '3.对方主动挑战玩家时，将派出玩家的防守阵容迎战，排名更迭与战斗结束关系与上条一致'
	},
	[136720] = {
		id = 136720,
		fmt = '#L10##C0xF76B45#【积分须知】'
	},
	[136721] = {
		id = 136721,
		fmt = '1.每个舞台的积分与排名相互独立，不同的排名区间对应的积分不同，通过不断地挑战参演者，换位提升自己的名次'
	},
	[136722] = {
		id = 136722,
		fmt = '2.三个舞台的榜单积分会按照由高到低，按照#C0xF76B45#100%，75%，50%#C0x5B545B#的比率汇总入总榜'
	},
	[136723] = {
		id = 136723,
		fmt = '3.若出现2~3个舞台积分相同的情况，则按照对应舞台的排名高低，按上述比例转入总榜积分'
	},
	[136724] = {
		id = 136724,
		fmt = '#L10##C0xF76B45#【奖励须知】'
	},
	[136725] = {
		id = 136725,
		fmt = '1.喵喵存储奖励：根据总积分，每10分钟可产生一定存储奖励，存储奖励存在上限(上限为相应总积分值对应12小时的产量)，请及时领取哟'
	},
	[136726] = {
		id = 136726,
		fmt = '2.排名奖励：赛季末会根据总榜的排名通过邮件发放赛季排名奖励'
	},
	[136801] = {
		id = 136801,
		fmt = '1.训练家在满足本活动界面要求的充值额度之后，可以解锁每日有礼奖励，助你冲击世界最强训练家的宝座！'
	},
	[136802] = {
		id = 136802,
		fmt = '2.当满足充值额度后，当天请先领取充值额度的一次性奖励，等隔日5点后，可以开始领取每日有礼礼包'
	},
	[136803] = {
		id = 136803,
		fmt = '3.每日登录即可满足每日有礼的领取条件，奖励为你而来，千万记得领取哦！'
	},
	[136901] = {
		id = 136901,
		fmt = '1.选定精灵获得专属进化助力资源，助你快速超进化'
	},
	[136902] = {
		id = 136902,
		fmt = '2.在界面中，需要先在几个精灵中选定一个精灵进行助力，首先点击+号选择一个精灵预览，回到活动界面后可以看到针对该精灵设定的奖励内容，若确定选择，则点击锁定精灵，若需要更换查看，也可点击切换精灵预览'
	},
	[136903] = {
		id = 136903,
		fmt = '3.选定精灵后，可以在界面中领取或购买满足条件的奖励和礼包：升星精灵，满足星级可以免费领取资源奖励，还可以购买对应星级中专属的超值礼包；购买升星超值礼包达成条件，额外赠送精灵本体卡；精灵形象旁的专属特惠中，还有海量特惠礼包可供选择'
	},
	[136904] = {
		id = 136904,
		fmt = '#C0xF76B45#4.若活动中提供助力的精灵已经进行过超进化的，也可以再次选择精灵进行助力，但养成奖励内容不会因为该精灵已经超进化而进行变更哦'
	},
	[136905] = {
		id = 136905,
		fmt = '#C0xF76B45#5.锁定的精灵的星级任务达成判断，取训练家拥有的该精灵当前最高星级进行判断；若训练家锁定精灵后，精灵进行其他操作（星级交换、分解、重生等）而导致星级下降的，则已达成的星级奖励内容不变，后续需要该精灵再次升星之后再解锁后续的星级奖励；其中星级6.临时交换的，不会影响该活动中对于精灵星级条件的判断'
	},
	[136906] = {
		id = 136906,
		fmt = '#C0xF76B45#锁定助力精灵后，不可进行变更，请训练家慎重考虑后再行选择'
	},
	[137001] = {
		id = 137001,
		fmt = '1.活动共计#C0xF76B45#34#C0x5B545B#轮，每次可进行#C0xF76B45#3#C0x5B545B#次十连抽'
	},
	[137002] = {
		id = 137002,
		fmt = '2.满足等级要求后才可进行抽奖和领取'
	},
	[137003] = {
		id = 137003,
		fmt = '3.抽到的奖励结果保留，玩家可在3次抽奖结果中选择其中一个进行领取#C0xF76B45#（3次全部抽取后开放领取）#C0x5B545B#'
	},
	[137004] = {
		id = 137004,
		fmt = '4.当前轮次奖励领取后才可进行下一轮抽奖'
	},
	[137005] = {
		id = 137005,
		fmt = '5.每次十连抽最多可获得#C0xF76B45#1#C0x5B545B#个精英精灵，部分轮次可获得史诗精灵！'
